-- Poems batch 262
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('99319814-0f45-450f-ace9-348d94330549','除夜','楊公遠','宋','宋诗','song-poetry','','[]','簷溜聲中送舊年，團圞笑語不成眠。',64,'全唐诗/poet.song.234000.json','["簷溜聲中送舊年，團圞笑語不成眠。", "忽驚雷吼三更後，始悟春回半月前。", "桃板欲題詩未穩，燈花頻結兆開先。", "明朝賀客無祗待，汲水煎茶當酒傳。"]'),
('9e29cb7c-ec7c-4ec5-abca-2a4f7d24eb06','次黄山中首尾吟','楊公遠','宋','宋诗','song-poetry','','[]','雙井源流綽有聲，襟期一片玉壺清。',64,'全唐诗/poet.song.234000.json','["雙井源流綽有聲，襟期一片玉壺清。", "吟成物外風騷句，付與人間月旦評。", "隨柳問花知雅興，論心握手見交情。", "英雄標致真難敵，雙井源流綽有聲。"]'),
('8cd11d02-0308-4c39-9a57-82c126a9e1ea','初度寓郡','楊公遠','宋','宋诗','song-poetry','','[]','得失榮枯付分休，康强之外復何求。',64,'全唐诗/poet.song.234000.json','["得失榮枯付分休，康强之外復何求。", "靈臺洞徹天無夜，銀海精明月正秋。", "謾賦律章酬誕節，旋沽官醖破羈愁。", "生來結得梅花伴，長占春風第一籌。"]'),
('d20b72db-a7bc-42b5-95a1-31d49f082a8b','次余靜庵晚望欲雪','楊公遠','宋','宋诗','song-poetry','','[]','凝眸天欲莫，烏鵲認巢歸。',48,'全唐诗/poet.song.234000.json','["凝眸天欲莫，烏鵲認巢歸。", "萬竅號風急，千林脫葉稀。", "雲頑垂地暝，屋冷带煙霏。", "默想滕郎意，商量剪水飛。"]'),
('1d0c4c78-c804-4c53-840e-9a18ced5cf5f','再韻','楊公遠','宋','宋诗','song-poetry','','[]','牧豎橫清笛，騎牛引犢歸。',48,'全唐诗/poet.song.234000.json','["牧豎橫清笛，騎牛引犢歸。", "陰凝山髣髴，暝合樹依稀。", "風逼衣裘冷，天將雨雪霏。", "倚闌遥睇處，接翅有鴉飛。"]'),
('a55f7fca-0722-4312-b824-0e65975df190','自述','楊公遠','宋','宋诗','song-poetry','','[]','年踰半百頗酸心，眼底朋儔試選掄。',64,'全唐诗/poet.song.234000.json','["年踰半百頗酸心，眼底朋儔試選掄。", "松竹梅花三益友，詩書畫卷一閒人。", "北窗高卧那非樂，南阮甘貧只任真。", "却喜生無榮辱事，底須姓字動朝紳。"]'),
('93bb7f96-6b4b-458a-8578-30d8edcb5037','次宋省齋問月','楊公遠','宋','宋诗','song-poetry','','[]','開樽酹酒問嬋娟，來照人間是幾年。',64,'全唐诗/poet.song.234000.json','["開樽酹酒問嬋娟，來照人間是幾年。", "從古到今今復古，纔圓又缺缺還圓。", "隔千里共何同異，描萬象真無醜妍。", "最是婆娑仙桂樹，新枝不長出青天。"]'),
('0cf93a48-07c2-4d27-bc7d-c88240b74850','借張山長韻呈方虛谷  其一','楊公遠','宋','宋诗','song-poetry','','[]','幡然何事賦歸來，領略黄山酬玉杯。',64,'全唐诗/poet.song.234000.json','["幡然何事賦歸來，領略黄山酬玉杯。", "敲月幾編雖滿世，澤民一念未宜灰。", "笑呼臞鶴梅邊去，旋買寒花竹外栽。", "襟度汪汪千萬頃，眼青應爲野人開。"]'),
('a0652d93-3591-4d19-827f-6bc70480cf10','借張山長韻呈方虛谷  其二','楊公遠','宋','宋诗','song-poetry','','[]','歸來默坐似心齋，南北曾穿幾緉鞋。',64,'全唐诗/poet.song.234000.json','["歸來默坐似心齋，南北曾穿幾緉鞋。", "踏遍關河才思古，名知草木宦情佳。", "桐江勝景歸吟卷，練水寒雲入壯懷。", "試數時賢誰敢並，蘇黄端的是同儕。"]'),
('253da5ce-8c10-4af0-a0b3-9ab0b7e3bf53','借張山長韻呈方虛谷  其三','楊公遠','宋','宋诗','song-poetry','','[]','樓臺寂寂白雲堆，三徑縈迂鎖翠苔。',64,'全唐诗/poet.song.234000.json','["樓臺寂寂白雲堆，三徑縈迂鎖翠苔。", "怪得菊松多喜色，祇緣琴鶴已歸來。", "人瞻北斗光尤燦，門對南山掩復開。", "野客再持漫刺謁，不應袖手又空回。"]'),
('ffe097ee-05b8-409c-8189-f8d8f84c6918','次韻別黄山中','楊公遠','宋','宋诗','song-poetry','','[]','相逢祇在萬山阿，每愧才疎藉琢磨。',64,'全唐诗/poet.song.234000.json','["相逢祇在萬山阿，每愧才疎藉琢磨。", "昨日忽來明日去，會時常少別時多。", "茶聊當酒匆匆話，詩爲言懷細細哦。", "折得梅花須寄我，不然携杖早相過。"]'),
('6cfae907-3bdc-4572-9502-e18aca7ef9c5','九日','楊公遠','宋','宋诗','song-poetry','','[]','造化推移秋意深，安排景物逐時新。',64,'全唐诗/poet.song.234000.json','["造化推移秋意深，安排景物逐時新。", "又逢九日寒花節，不覺三年逆旅身。", "烏帽戀頭渾忤俗，白衣送酒竟無人。", "翻思杜牧牛山句，誰解清吟繼後塵。"]'),
('ea7b192a-9830-41a9-ac4e-fa936aedba3a','次宋省齋九月十日','楊公遠','宋','宋诗','song-poetry','','[]','恰說重陽又罷休，奈何烏兔去悠悠。',64,'全唐诗/poet.song.234000.json','["恰說重陽又罷休，奈何烏兔去悠悠。", "可憐節後人心別，未信花前蝶意愁。", "病裏不禁三盞酒，客中虛負一年秋。", "來年昨日登高興，强健還能痛飲不。"]'),
('35437ae5-a87b-4b00-9360-12260d0d1817','次省齋韻覓友梅索笑集不蒙見惠再借韻','楊公遠','宋','宋诗','song-poetry','','[]','巨編藏古錦，風雅續遺音。',120,'全唐诗/poet.song.234000.json','["巨編藏古錦，風雅續遺音。", "雷電欲下取，辟易不敢侵。", "真趣誰領會，一如陶潛琴。", "所言正而大，詎比鄭聲淫。", "疑有造化爐，煉鐵成黄金。", "箇是絕世寶，何必問西琛。", "有時吟竹外，竹影弄清陰。", "有時歌梅邊，梅香散水沈。", "所以形之句，毋乃得之心。", "俗子敢再請，幸爾勿沈吟。"]'),
('a5d0e4ab-621e-4371-817a-8a4d50f257e8','次宋省齋七夕雨  其一','楊公遠','宋','宋诗','song-poetry','','[]','自笑生來作麽爲，百無一解太癡愚。',32,'全唐诗/poet.song.234000.json','["自笑生來作麽爲，百無一解太癡愚。", "今宵欲覓天孫巧，未審天孫乞我無。"]'),
('8e39e1cf-0769-4d6f-9ab4-7bef349217d3','次宋省齋七夕雨  其二','楊公遠','宋','宋诗','song-poetry','','[]','織女河邊渡鵲橋，風吹仙袂舉飄飄。',32,'全唐诗/poet.song.234000.json','["織女河邊渡鵲橋，風吹仙袂舉飄飄。", "洗車一夜霶𩃱雨，圖得人間起旱苗。"]'),
('f2601f95-81bd-411d-95ad-4219f8045607','次宋省齋七夕雨  其三','楊公遠','宋','宋诗','song-poetry','','[]','人言此夕會雙星，騃女癡兒競乞靈。',32,'全唐诗/poet.song.234000.json','["人言此夕會雙星，騃女癡兒競乞靈。", "學織學耕非我事，何如牛角自橫經。"]'),
('208c2d0b-703b-4d63-9770-633c13b16714','次姚舍人  其一','楊公遠','宋','宋诗','song-poetry','','[]','披起綿衣換葛裘，不禁時序去悠悠。',64,'全唐诗/poet.song.234000.json','["披起綿衣換葛裘，不禁時序去悠悠。", "吳江楓老蕭蕭下，紫塞鴻歸點點秋。", "幾幅蠻牋詩狀景，一聲羌笛客凭樓。", "羈懷正此無聊奈，細雨簷花分外愁。"]'),
('0b083879-0a6f-4f96-a5ab-cbf061111736','次姚舍人  其二','楊公遠','宋','宋诗','song-poetry','','[]','斜岸烏紗落魄裘，得寬閒處且悠悠。',64,'全唐诗/poet.song.234000.json','["斜岸烏紗落魄裘，得寬閒處且悠悠。", "任渠名利濃於酒，顧我情懷淡似秋。", "黄菊蒼松陶令宅，清風明月庾公樓。", "翻思二老今何在，景物依然惱客愁。"]'),
('ed8c4586-e4f1-459f-bdfc-9907791007e0','次友梅編校獨卧牀','楊公遠','宋','宋诗','song-poetry','','[]','梅花紙帳伴書窗，氈褥平鋪小小牀。',64,'全唐诗/poet.song.234000.json','["梅花紙帳伴書窗，氈褥平鋪小小牀。", "趺膝橫琴情自適，曲肱當枕樂偏長。", "詩魂直透冰霜國，衾錦那沾粉膩香。", "丈五日高眠正熟，不知前古又三皇。"]'),
('a4b701f4-9e65-4ff8-bd4c-65390d18d68d','癸未元日','楊公遠','宋','宋诗','song-poetry','','[]','桃板休題只任真，也無艱苦與悲辛。',64,'全唐诗/poet.song.234000.json','["桃板休題只任真，也無艱苦與悲辛。", "屠蘇後飲身雖老，毛穎頻揮道不貧。", "昨夜燈花今歲兆，今朝元日昨宵春。", "邇來時俗全非古，烏帽長衫能幾人。"]'),
('dd72d370-674c-46ce-a46f-aaaae51b5d70','銅缾簪梅','楊公遠','宋','宋诗','song-poetry','','[]','梅花點點自清真，雪虐風饕苦且辛。',64,'全唐诗/poet.song.234000.json','["梅花點點自清真，雪虐風饕苦且辛。", "白玉堂開雖是貴，古銅缾浸亦非貧。", "愛渠夜寫燈前影，類我時揮筆底春。", "雅趣有誰能領會，華光已後更無人。"]'),
('e5081a9e-5bb5-4e3d-88bf-0d865db1728e','遊南山次劉曉窗韻二首  其一','楊公遠','宋','宋诗','song-poetry','','[]','神仙窟宅白雲扃，山逕迂迴峻復平。',64,'全唐诗/poet.song.234000.json','["神仙窟宅白雲扃，山逕迂迴峻復平。", "煙冷恐遺丹竈在，草深不向斗壇生。", "市廛塵隔二三里，巖谷禽啼一兩聲。", "莫訝此來仙不見，遥岑寸碧眼增明。"]'),
('27349043-b42f-42c1-93d5-12c2389b7dd8','遊南山次劉曉窗韻二首  其二','楊公遠','宋','宋诗','song-poetry','','[]','李白曾來問姓名，宣平疑是古初平。',64,'全唐诗/poet.song.234000.json','["李白曾來問姓名，宣平疑是古初平。", "負薪出處天將曙，沽酒歸時月又生。", "雞啄遺丹非有意，瓢懸老樹寂無聲。", "寒泉滿沼依然在，靜夜長涵星斗明。"]'),
('5ee53282-b3b9-4a1a-9c50-5fc5c02393d3','龍金庵次黄山中','楊公遠','宋','宋诗','song-poetry','','[]','清風明月逐時新，天付幽人直萬金。',32,'全唐诗/poet.song.234000.json','["清風明月逐時新，天付幽人直萬金。", "和得詩成無箇事，來時可惜不携琴。"]'),
('66715873-68fd-4bcb-b1b7-501984712dde','龍金庵借張山長韻','楊公遠','宋','宋诗','song-poetry','','[]','道人結屋萬山阿，趺坐焚香意味多。',64,'全唐诗/poet.song.234000.json','["道人結屋萬山阿，趺坐焚香意味多。", "塵事不干心已寂，年華易度髮難皤。", "薇烹石銚供常饌，茶煮山泉當太和。", "我亦非貪名利者，擬來入社許儂麽。"]'),
('e5d8a134-8c43-469a-8dcc-2c48604fb898','題徐氏聚秀樓','楊公遠','宋','宋诗','song-poetry','','[]','輪奐危危百尺樓，闌干徙倚豁雙眸。',64,'全唐诗/poet.song.234000.json','["輪奐危危百尺樓，闌干徙倚豁雙眸。", "插天萬仞黄山聳，遶郭千尋練水流。", "風月不消錢可買，主賓須要味相投。", "四時景物俱收斂，引得詩人競唱酬。"]'),
('3d3caa28-8e2a-4c72-b3df-fa98a6b5c70e','殘梅','楊公遠','宋','宋诗','song-poetry','','[]','暗香消歇粉粧殘，點點虛庭碧蘚間。',32,'全唐诗/poet.song.234000.json','["暗香消歇粉粧殘，點點虛庭碧蘚間。", "却怪貧家新富貴，地茵純用鹿胎斑。"]'),
('e209abe5-ff26-4310-9eef-4311d82ec184','還劉曉窗吟卷就用卷端韻','楊公遠','宋','宋诗','song-poetry','','[]','細觀吟卷壓陽春，字字新奇絕點塵。',64,'全唐诗/poet.song.234000.json','["細觀吟卷壓陽春，字字新奇絕點塵。", "既已學詩兼學禮，底須憂道更憂貧。", "鳥啼花落蕭閒日，月白風清自在身。", "內景通明誰會得，窗寒曙色正精神。"]'),
('544de448-d089-49c5-b9e1-6af41ef21824','詩家','楊公遠','宋','宋诗','song-poetry','','[]','松下雲根迂菊徑，梅邊竹外著茆茨。',32,'全唐诗/poet.song.234000.json','["松下雲根迂菊徑，梅邊竹外著茆茨。", "天教管領閒風月，得句無非妙色絲。"]'),
('6a4b705c-7768-451b-ac50-6c783c46f866','詩壇','楊公遠','宋','宋诗','song-poetry','','[]','突兀騷壇依漢立，英豪元帥凜霜威。',32,'全唐诗/poet.song.234000.json','["突兀騷壇依漢立，英豪元帥凜霜威。", "四時景物知多少，一一投降聽指揮。"]'),
('67a19a59-9eb0-41be-be33-c8789d0e9351','詩將','楊公遠','宋','宋诗','song-poetry','','[]','草木森羅歸隊伍，溪山遼遶作城池。',32,'全唐诗/poet.song.234000.json','["草木森羅歸隊伍，溪山遼遶作城池。", "運籌決勝應無敵，郊島從旁作鼓旗。"]'),
('830d86a5-4122-4da0-b2e6-3749cdbafbc2','詩匠','楊公遠','宋','宋诗','song-poetry','','[]','吳剛運斧惟修月，輪扁揮斤妙斲輪。',32,'全唐诗/poet.song.234000.json','["吳剛運斧惟修月，輪扁揮斤妙斲輪。", "好句何須勞斧鑿，無痕無跡自天真。"]'),
('64130b53-50e4-4b66-a094-fb735df9c2ae','詩筆','楊公遠','宋','宋诗','song-poetry','','[]','銀管空虛藏兔穎，冰懷磊磈吐天葩。',32,'全唐诗/poet.song.234000.json','["銀管空虛藏兔穎，冰懷磊磈吐天葩。", "有時揮掃渾無礙，盡道毫鋒自有花。"]'),
('c566df65-46f7-47b1-b514-aa6925486fc7','詩筒','楊公遠','宋','宋诗','song-poetry','','[]','短篇吟了長篇續，舊韻酬成新韻催。',32,'全唐诗/poet.song.234000.json','["短篇吟了長篇續，舊韻酬成新韻催。", "一節此君緘錦繡，奚奴携去又携來。"]'),
('2bd58114-6948-4312-ae89-be012225a1c2','詩牌','楊公遠','宋','宋诗','song-poetry','','[]','閒亭虛閣多標揭，舊句新篇各鬭工。',32,'全唐诗/poet.song.234000.json','["閒亭虛閣多標揭，舊句新篇各鬭工。", "爲拂塵埃題數語，敢期他日碧沙籠。"]'),
('3828262c-1c95-4ff2-97d0-ed591965eaf7','詩壁','楊公遠','宋','宋诗','song-poetry','','[]','一方素壁龍蛇走，幾首新詩冰雪清。',32,'全唐诗/poet.song.234000.json','["一方素壁龍蛇走，幾首新詩冰雪清。", "語好驚人看不足，教儂技癢動吟情。"]'),
('4bcbc0fa-94ec-423e-847e-0b68cb23fa67','詩癖','楊公遠','宋','宋诗','song-poetry','','[]','生來性癖耽佳句，吟得詩成似有神。',32,'全唐诗/poet.song.234000.json','["生來性癖耽佳句，吟得詩成似有神。", "險語豈惟驚鬼膽，直須字字要驚人。"]'),
('c7833283-166a-4ab7-8830-ee1ca43bcc99','詩狂','楊公遠','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','掬取長江供硯水，借將碧漢作蠻牋。',32,'全唐诗/poet.song.234000.json','["掬取長江供硯水，借將碧漢作蠻牋。", "興來拈起如椽筆，大詠高吟欲上天。"]'),
('53e93676-977e-4988-967d-c33b8dcc226a','蝶  其一','楊公遠','宋','宋诗','song-poetry','','[]','磔索銀鬚細，翩翩粉翅柔。',24,'全唐诗/poet.song.234000.json','["磔索銀鬚細，翩翩粉翅柔。", "百花巡已遍，入夢戲莊周。"]'),
('2e6d2027-7478-4da0-89a1-9fb582696b3d','蝶  其二','楊公遠','宋','宋诗','song-poetry','','[]','款款穿芳徑，雙雙度短牆。',24,'全唐诗/poet.song.234000.json','["款款穿芳徑，雙雙度短牆。", "不知身是幻，抵死戀花香。"]'),
('8cab6b58-947c-435d-80bc-c9ec4e3a4c3e','自笑  其一','楊公遠','宋','宋诗','song-poetry','','[]','自笑人生立世難，甘辛滋味飽曾參。',64,'全唐诗/poet.song.234000.json','["自笑人生立世難，甘辛滋味飽曾參。", "頭顱潦倒梅橫雪，心地通明月印潭。", "詩欠驚人徒著意，事多忤俗更休談。", "何如領略三杯酒，不必如泥只半酣。"]'),
('f7ff2713-d4bb-4dc4-b9a8-4b609ee72a8c','自笑  其二','楊公遠','宋','宋诗','song-poetry','','[]','東郊結屋恰三間，景物供吟要細參。',64,'全唐诗/poet.song.234000.json','["東郊結屋恰三間，景物供吟要細參。", "紅日射芒穿密樹，青山倒影浴寒潭。", "樵雖分席當時話，客爲同心盡日談。", "最是北窗高卧處，如雷鼻息睡偏酣。"]'),
('ab13d1ed-e3f9-4a7d-bb8a-0c4c9ae4ff23','癸未中秋','楊公遠','宋','宋诗','song-poetry','','[]','凉入郊墟暑漸微，奈何節序暗推移。',64,'全唐诗/poet.song.234000.json','["凉入郊墟暑漸微，奈何節序暗推移。", "景逢三五秋分夜，光異尋常月滿時。", "按舞霓裳仙綽約，長舂靈藥兔迷離。", "廣寒宮桂花空發，近世無人折一枝。"]'),
('c3d79142-fe9b-4825-98d5-97dcafe03eb8','次程國舍','楊公遠','宋','宋诗','song-poetry','','[]','欲坐春風欠宿緣，識荆琳宇憶當年。',64,'全唐诗/poet.song.234000.json','["欲坐春風欠宿緣，識荆琳宇憶當年。", "初逢脫略知心地，再見從容值暑天。", "萬卷詩書君有種，一犁煙雨我無田。", "曉來喜報簷前鵲，忽得珠璣璨兩篇。"]'),
('d03dac4b-4b51-4a21-9578-882afaec1353','夷齊','楊公遠','宋','宋诗','song-poetry','','[]','因請休兵諫不行，首陽遁跡似沽名。',32,'全唐诗/poet.song.234000.json','["因請休兵諫不行，首陽遁跡似沽名。", "既言不食周家粟，薇蕨誰家土上生。"]'),
('1ba99530-d137-42a0-9166-6068a60be8af','呈康總管相公','楊公遠','宋','宋诗','song-poetry','','[]','古汴文章伯，來爲我郡侯。',48,'全唐诗/poet.song.234000.json','["古汴文章伯，來爲我郡侯。", "一心天不夜，千里月長秋。", "政壓龔黄輩，詩儕李杜儔。", "雷門持布鼓，肯矚電光不。"]'),
('9495f3d6-6ac2-438e-a1c4-18d755e2a1d9','九日','楊公遠','宋','宋诗','song-poetry','','[]','滿城風雨霍然開，不負登臨亦快哉。',64,'全唐诗/poet.song.234000.json','["滿城風雨霍然開，不負登臨亦快哉。", "時俗半無烏帽墮，世情那有白衣來。", "且沽薄酒酬佳節，欲賦新詩愧短才。", "折得黄花簪兩鬢，任渠兩鬢自毰毸。"]'),
('2320c8ba-a433-4d42-802a-c487ea29376e','十日宋省齋有詩謂不及同登南山獨步烏聊山','楊公遠','宋','宋诗','song-poetry','','[]','我輩登高嶮更遥，聞君獨步上烏聊。',64,'全唐诗/poet.song.234000.json','["我輩登高嶮更遥，聞君獨步上烏聊。", "休嗟昨日渾無興，須信明年尚有條。", "節後黄花香未減，年高黑鬢雪偏饒。", "拂箋續罷新詩句，回首重陽越一朝。"]'),
('6f8478de-ba41-4618-8d50-d65bdce82987','孫芝田見示吟編一詩捲錦','楊公遠','宋','宋诗','song-poetry','','[]','細誦芝田詩一編，了無斧鑿自天然。',64,'全唐诗/poet.song.234000.json','["細誦芝田詩一編，了無斧鑿自天然。", "豪雄虹抹斜陽外，雅淡梅橫缺月邊。", "點石化金非是幻，脫胎換骨欲成仙。", "箇般才調真難敵，行看雞林聲價傳。"]'),
('b574ab0e-6f27-4a25-8a51-34ceef37a742','重陽已過半月菊花方開  其一','楊公遠','宋','宋诗','song-poetry','','[]','過了重陽半月餘，菊花方見放東籬。',64,'全唐诗/poet.song.234000.json','["過了重陽半月餘，菊花方見放東籬。", "香清不減登山日，色好偏過泛酒時。", "餐落英真成浪語，存荒徑豈是虛辭。", "生來寧耐風霜挫，晚節騰芳滿世知。"]'),
('90dc8ca9-7a0a-4cf4-aec4-ab4075b520ca','重陽已過半月菊花方開  其二','楊公遠','宋','宋诗','song-poetry','','[]','西風轉北又旬餘，才見黄花粲短籬。',64,'全唐诗/poet.song.234000.json','["西風轉北又旬餘，才見黄花粲短籬。", "底事不開重九日，何心却趁小春時。", "芳傳栗里陶潛逕，香入離騷屈子辭。", "不肯趨時真隠逸，豈教塵世俗人知。"]'),
('7a84dde8-6674-4363-bb32-c5aaeaec05a6','子陵','楊公遠','宋','宋诗','song-poetry','','[]','三聘玄纁莫可辭，此行爲滿故人思。',32,'全唐诗/poet.song.234000.json','["三聘玄纁莫可辭，此行爲滿故人思。", "一宵共榻論心事，却被司天太史知。"]'),
('f639630c-5d97-4a09-9528-0c4e9e4a0693','和靖','楊公遠','宋','宋诗','song-poetry','','[]','湖上吟翁道味長，孤墳今已草成荒。',32,'全唐诗/poet.song.234000.json','["湖上吟翁道味長，孤墳今已草成荒。", "姓名猶寄梅花上，一度開時一度香。"]'),
('f0f73c6a-d37e-43d8-a678-3623017f535b','萬竹乃竹洲曾孫也萬竹子常新恩棄儒於乾明入道伯父友梅以詩餞之因次韻','楊公遠','宋','宋诗','song-poetry','','[]','洲上檀欒竹萬竿，此君得所一般般。',64,'全唐诗/poet.song.234000.json','["洲上檀欒竹萬竿，此君得所一般般。", "根雖易地終無異，操直參天也不難。", "冠借皮爲疑斗燦，杖憑枝作覺龍寒。", "步虛詞罷幽閒處，好勘黄庭悟寸丹。"]'),
('93d94746-8cf6-4eb1-a4d2-363481956fa8','昨携拙稿呈康使君郢正以詩促之','楊公遠','宋','宋诗','song-poetry','','[]','昨携拙稿乞揮斤，安敢顒顒覬賞音。',64,'全唐诗/poet.song.234000.json','["昨携拙稿乞揮斤，安敢顒顒覬賞音。", "明月清風聊寓意，孤峰絕岸頗留心。", "駑逢伯樂方增重，劍遇張華免陸沈。", "肯把靈丹攻鄙俗，珍藏何啻萬黄金。"]'),
('a09067ed-329b-435a-aad8-ece515681490','次文長老','楊公遠','宋','宋诗','song-poetry','','[]','久向人間脫俗緣，了無罣礙度年年。',64,'全唐诗/poet.song.234000.json','["久向人間脫俗緣，了無罣礙度年年。", "一塵不惹菩提樹，四大俱空兜率天。", "閒爇篆香供鼻觀，靜翻貝葉養心田。", "推敲對景清吟處，應是渾無蔬笋篇。"]'),
('d9db678f-47a8-4f29-bab4-e863aa3551da','次乾明觀汪新恩','楊公遠','宋','宋诗','song-poetry','','[]','家世桃源越幾年，驀携書卷覓安全。',64,'全唐诗/poet.song.234000.json','["家世桃源越幾年，驀携書卷覓安全。", "來尋竹所山房處，爲結梅花紙帳緣。", "白鶴詞歌明月下，黄庭經勘晚風前。", "他時九轉功成後，穩駕真人蓮葉船。"]'),
('4886ea62-41ad-4402-bf48-767bfb1835bf','次程直學對鏡','楊公遠','宋','宋诗','song-poetry','','[]','青銅頻啟看，瘦劣沈東陽。',48,'全唐诗/poet.song.234000.json','["青銅頻啟看，瘦劣沈東陽。", "鬢染秋霜色，身期晚節香。", "閒情耽水石，幽夢遶池塘。", "何似伊川脈，淵源道味長。"]'),
('fa488f91-5c58-4b15-bc55-9f9938ac4616','白水池次俞山長韻','楊公遠','宋','宋诗','song-poetry','','[]','石眼泉流乳，盈池永不乾。',48,'全唐诗/poet.song.234000.json','["石眼泉流乳，盈池永不乾。", "空明涵玉潤，湛徹带雲寒。", "月浸知無異，鷗來認却難。", "何郎今在否，好向此凭闌。"]'),
('bac20eeb-e682-4229-a78b-253aefb7df61','次宋省齋菊花五絕  其一','楊公遠','宋','宋诗','song-poetry','','[]','東籬粲處正秋高，氣骨清寒等孟郊。',32,'全唐诗/poet.song.234000.json','["東籬粲處正秋高，氣骨清寒等孟郊。", "試問羣芳誰是侶，梅花差可作平交。"]'),
('19f001bf-f33e-435c-b882-8ba15d2ac45e','次宋省齋菊花五絕  其二','楊公遠','宋','宋诗','song-poetry','','[]','凡卉徒妖迥不同，輸渠籬下自叢叢。',32,'全唐诗/poet.song.234000.json','["凡卉徒妖迥不同，輸渠籬下自叢叢。", "趨時未肯隠君子，畢竟依然带晉風。"]'),
('0fa2c6d4-6764-40e9-9323-4be7d739c85f','次宋省齋菊花五絕  其三','楊公遠','宋','宋诗','song-poetry','','[]','細嚼芳英清肺腑，離騷一語傳千古。',32,'全唐诗/poet.song.234000.json','["細嚼芳英清肺腑，離騷一語傳千古。", "靈均去後誰知心，幸有柴桑人作主。"]'),
('8aebd5e4-e05f-4cea-a99d-c6307863c73d','次宋省齋菊花五絕  其四','楊公遠','宋','宋诗','song-poetry','','[]','千花萬卉已俱亡，獨占秋光點點黄。',32,'全唐诗/poet.song.234000.json','["千花萬卉已俱亡，獨占秋光點點黄。", "露冷霜濃難著脚，甘心寧耐此荒凉。"]'),
('39a2bfc3-d644-4875-80f9-7565fd2c19e2','次宋省齋菊花五絕  其五','楊公遠','宋','宋诗','song-poetry','','[]','萬木歸根葉漸空，淡煙斜照有無中。',32,'全唐诗/poet.song.234000.json','["萬木歸根葉漸空，淡煙斜照有無中。", "客懷對此無情思，頼有知心老菊叢。"]'),
('899f5ef4-f0d2-4ee8-a2a8-00928e4993a7','省齋寄詩用韻走筆以謝  其一','楊公遠','宋','宋诗','song-poetry','','[]','每思分袂歲寒天，又見荷錢貼水圓。',64,'全唐诗/poet.song.234000.json','["每思分袂歲寒天，又見荷錢貼水圓。", "月落梁間清夜後，雲生江上晚風前。", "題詩繭紙無由達，結夢花屏又復還。", "會晤未龜空悵恨，何時握手共歡然。"]'),
('73a75a37-de1a-479c-b821-d57ec781e50c','省齋寄詩用韻走筆以謝  其二','楊公遠','宋','宋诗','song-poetry','','[]','竟日昏昏醉夢中，俄驚綠暗石榴紅。',64,'全唐诗/poet.song.234000.json','["竟日昏昏醉夢中，俄驚綠暗石榴紅。", "兩三箇月書全杳，四五篇詩信忽通。", "身世愧無鴻鵠志，交情歎作馬牛風。", "如今暫效相如計，較著無聲迥不同。"]'),
('1a6b941d-2b75-440b-808f-a5f8afd1fec7','黄山中用省齋韻見寄次韻謝  其一','楊公遠','宋','宋诗','song-poetry','','[]','話別匆匆二月天，回眸兩見月虧圓。',64,'全唐诗/poet.song.234000.json','["話別匆匆二月天，回眸兩見月虧圓。", "數聲乾鵲纔聞後，一幅鸞牋忽墮前。", "風雨對牀何日遂，鴈魚傳信幾時還。", "每逢騷客論心處，說著山中意悄然。"]'),
('02d96a7c-5ff1-42dd-b8a5-467031cd3fa1','黄山中用省齋韻見寄次韻謝  其二','楊公遠','宋','宋诗','song-poetry','','[]','幽窗兀兀坐愁中，忽拜山中小篆紅。',64,'全唐诗/poet.song.234000.json','["幽窗兀兀坐愁中，忽拜山中小篆紅。", "心事盡從詩裏見，交情全在帖間通。", "從容笑語知何日，老草賡酬寄便風。", "多謝綈袍尤戀戀，箇般襟度有誰同。"]'),
('8dcabbc9-27a2-47c0-be4c-bf90af913ba0','康使君惠詩借韻謝','楊公遠','宋','宋诗','song-poetry','','[]','幾幅生綃掃麝煤，枯梢黏蘚石封苔。',64,'全唐诗/poet.song.234000.json','["幾幅生綃掃麝煤，枯梢黏蘚石封苔。", "布成野水雲山去，博得金章玉句來。", "眉白自慚非我有，眼青多藉爲儂開。", "一經題品多增價，古錦光芒亦壯哉。"]'),
('6540841c-9767-43bd-adf2-2de8e723e9ef','次劉曉窗九日韻  其一','楊公遠','宋','宋诗','song-poetry','','[]','門前何用白衣來，旋買官醪亦可杯。',32,'全唐诗/poet.song.234000.json','["門前何用白衣來，旋買官醪亦可杯。", "笑問黄花前日事，未生陶令爲誰開。"]'),
('83eff944-4049-431f-98d5-feee2efadc4b','次劉曉窗九日韻  其二','楊公遠','宋','宋诗','song-poetry','','[]','自憐萍梗老羈孤，暫寓僧寮不用租。',32,'全唐诗/poet.song.234000.json','["自憐萍梗老羈孤，暫寓僧寮不用租。", "九日有錢還可醉，不然萸菊酒俱無。"]'),
('ae61cfc8-01b3-4554-9cd8-e1759914f267','次劉曉窗九日韻  其三','楊公遠','宋','宋诗','song-poetry','','[]','秋菊何嘗委片英，都緣氣韻稟清寧。',32,'全唐诗/poet.song.234000.json','["秋菊何嘗委片英，都緣氣韻稟清寧。", "欲將此意靈均道，只恐靈均喚不醒。"]'),
('451e7780-62c1-462f-ab18-c7afec9b8375','次劉曉窗九日韻  其四','楊公遠','宋','宋诗','song-poetry','','[]','西風摇落鴈南飛，黄葉深深擁竹扉。',32,'全唐诗/poet.song.234000.json','["西風摇落鴈南飛，黄葉深深擁竹扉。", "佳節只消拚酩酊，牛山何事淚沾衣。"]'),
('10915139-3eb3-49ee-bc2d-935cb4cf580c','次劉曉窗九日韻  其五','楊公遠','宋','宋诗','song-poetry','','[]','籬下寒花色自妍，折來泛酒更新鮮。',32,'全唐诗/poet.song.234000.json','["籬下寒花色自妍，折來泛酒更新鮮。", "化工底事寧多巧，鑄出黄金滿地錢。"]'),
('02b2df26-9803-4665-bd26-2b47daba43e5','次劉曉窗九日韻  其六','楊公遠','宋','宋诗','song-poetry','','[]','佩萸囊菊陟崔嵬，世俗想傳有自來。',32,'全唐诗/poet.song.234000.json','["佩萸囊菊陟崔嵬，世俗想傳有自來。", "顧我此身强健在，不消囊佩亦無災。"]'),
('3e893628-1246-449c-acd6-3defacaf0198','次劉曉窗九日韻  其七','楊公遠','宋','宋诗','song-poetry','','[]','菊花偏作道家粧，開遍重巖與斷岡。',32,'全唐诗/poet.song.234000.json','["菊花偏作道家粧，開遍重巖與斷岡。", "醉後折來簪短鬢，老夫翻學少年狂。"]'),
('e92b15b3-bd1c-419f-9497-c25815baa2c7','次劉曉窗九日韻  其八','楊公遠','宋','宋诗','song-poetry','','[]','黄花堆積若錢流，粧點詩家富貴秋。',32,'全唐诗/poet.song.234000.json','["黄花堆積若錢流，粧點詩家富貴秋。", "元亮不將渠貰酒，空留遺恨尚悠悠。"]'),
('6686c13e-f0b9-47aa-87df-f68b8a87b387','次劉曉窗九日韻  其九','楊公遠','宋','宋诗','song-poetry','','[]','人皆九日醉流霞，君汲山泉自煮茶。',32,'全唐诗/poet.song.234000.json','["人皆九日醉流霞，君汲山泉自煮茶。", "可是詩成無點俗，祇應吟筆燦生花。"]'),
('abb2b7d7-a028-42d3-931a-e0e224c94bcd','月下看白蓮  其一','楊公遠','宋','宋诗','song-poetry','','[]','藕花呈素質，兔魄散清光。',24,'全唐诗/poet.song.234000.json','["藕花呈素質，兔魄散清光。", "我試平章看，嫦娥伴六郎。"]'),
('f8424b5a-4f46-4d66-b1c3-c060d4e79271','月下看白蓮  其二','楊公遠','宋','宋诗','song-poetry','','[]','別岸花孤裊，冰姿带月痕。',24,'全唐诗/poet.song.234000.json','["別岸花孤裊，冰姿带月痕。", "波沈花月影，疑是謫仙魂。"]'),
('37fbe19b-968a-4b3f-b8b5-dab10c140bdb','月下看白蓮','楊公遠','宋','宋诗','song-poetry','','[]','十里荷花带月看，花和月色一般般。',32,'全唐诗/poet.song.234000.json','["十里荷花带月看，花和月色一般般。", "祇應舞徹霓裳曲，宮女三千下廣寒。"]'),
('f9965b7b-1856-4980-9969-ee058f481655','酬黄仲宣見寄','楊公遠','宋','宋诗','song-poetry','','[]','倦走南州與北州，竹籬茅舍足清幽。',64,'全唐诗/poet.song.234000.json','["倦走南州與北州，竹籬茅舍足清幽。", "但教有酒名從事，何必爲官見督郵。", "謝友寄詩通間闊，拂箋泚筆細賡酬。", "雖然可寫胸中意，難寫胸中半點愁。"]'),
('d867c42d-c227-4def-95c6-eeb21a4ed54b','立春旬日雨作不止','楊公遠','宋','宋诗','song-poetry','','[]','檢起牀頭歷又新，吁嗟老境漸侵尋。',64,'全唐诗/poet.song.234000.json','["檢起牀頭歷又新，吁嗟老境漸侵尋。", "十朝春恰九朝雨，一日晴還半日陰。", "滴碎空階聲已厭，寒欺薄酒力難禁。", "絕憐窗外蒼苔地，積得殘梅寸許深。"]'),
('e548156f-463b-40c5-b6d9-5b33ae9a7c0a','回嶺觀瀑','楊公遠','宋','宋诗','song-poetry','','[]','瘦筇支我上山頭，拂石盤桓看瀑流。',32,'全唐诗/poet.song.234000.json','["瘦筇支我上山頭，拂石盤桓看瀑流。", "莫訝喧豗何太急，要歸江海濟行舟。"]'),
('9320f6f2-4622-4771-a2a2-76ce2bace52d','悶書  其一','楊公遠','宋','宋诗','song-poetry','','[]','轉眼纔餘五日春，東奔西走廢光陰。',64,'全唐诗/poet.song.234000.json','["轉眼纔餘五日春，東奔西走廢光陰。", "一泓硯裏謀生意，幾句詩中寫客心。", "貫斗衝牛雷煥劍，高山流水伯牙琴。", "莫將未遇添惆悵，自有名公爲賞音。"]'),
('f16a9fdc-60e3-41c3-9ad5-411969efa075','悶書  其二','楊公遠','宋','宋诗','song-poetry','','[]','客裏因循斷送春，况逢天氣半晴陰。',64,'全唐诗/poet.song.234000.json','["客裏因循斷送春，况逢天氣半晴陰。", "生來百事少如意，老去千般都上心。", "長鋏空彈馮氏劍，良材還斲蔡翁琴。", "愁懷正此無分付，多謝黄鸝送好音。"]'),
('7073d40d-b347-4698-b067-64a84ab2cedc','回嶺','楊公遠','宋','宋诗','song-poetry','','[]','梯級層層步頗艱，嶺頭清吹逼人寒。',64,'全唐诗/poet.song.234000.json','["梯級層層步頗艱，嶺頭清吹逼人寒。", "四邊絕壁詩懷壯，一片蒼空眼界寬。", "何處山坳吞落照，長年石罅噴鳴湍。", "支筇對景盤桓久，領略留將作畫看。"]'),
('9d818329-bc39-4a17-8e8d-b8024b995abd','寓婺源紫虛觀','楊公遠','宋','宋诗','song-poetry','','[]','書卷携來寓紫虛，憑高凝眺更無餘。',64,'全唐诗/poet.song.234000.json','["書卷携來寓紫虛，憑高凝眺更無餘。", "五山結邑龍盤踞，一水依城带卷舒。", "旦暮鼓鐘喧梵宇，高低樓閣壯神居。", "年時除却酬香者，闤闠行人往復疎。"]'),
('04f727ae-89ac-4ae4-96bf-56f1120f29ee','回溪道中','楊公遠','宋','宋诗','song-poetry','','[]','山束溪流窄逕迂，眼前景物入詩無。',64,'全唐诗/poet.song.234000.json','["山束溪流窄逕迂，眼前景物入詩無。", "田中蝌蚪古文字，柳下舂鉏新畫圖。", "巨室儲茶供客販，小旗誇酒誘人沽。", "行行不記幾多里，回首林端日又晡。"]'),
('666f591d-5543-41f6-80e8-fbd2ee597176','到陳村','楊公遠','宋','宋诗','song-poetry','','[]','半日脩途適到陳，因思尼父倍傷神。',64,'全唐诗/poet.song.234000.json','["半日脩途適到陳，因思尼父倍傷神。", "行囊抖擻幸餘半，旅館蕭條苦乏薪。", "喚僕買杯蘇脚倦，拂塵題句效眉顰。", "孤村落日黄昏後，一覺明朝又問津。"]'),
('6de73d95-7307-4031-8656-fda342a32d94','次韻酬孫艮齋  其一','楊公遠','宋','宋诗','song-poetry','','[]','抱膝孤吟欠範模，願隨雞犬藉丹爐。',32,'全唐诗/poet.song.234000.json','["抱膝孤吟欠範模，願隨雞犬藉丹爐。", "儻能化得塵凡骨，差勝無聲水墨圖。"]'),
('400efba4-590e-4400-aa86-cef3339f6c23','次韻酬孫艮齋  其二','楊公遠','宋','宋诗','song-poetry','','[]','風竹蕭蕭密掩門，苔封支徑曲通村。',32,'全唐诗/poet.song.234000.json','["風竹蕭蕭密掩門，苔封支徑曲通村。", "野人自有家林趣，那得榮華入夢魂。"]'),
('d2a7e23d-1138-42b9-9ceb-8ad09219d142','次韻酬孫艮齋  其三','楊公遠','宋','宋诗','song-poetry','','[]','想倚危樓十二闌，詩成可是過方干。',32,'全唐诗/poet.song.234000.json','["想倚危樓十二闌，詩成可是過方干。", "好風吹墮寒窗底，勝得仙翁九轉丹。"]'),
('772b3660-1290-43be-9192-ddb540d75046','次韻立秋','楊公遠','宋','宋诗','song-poetry','','[]','白帝交承下令時，蒲葵絺葛豎降旗。',64,'全唐诗/poet.song.234000.json','["白帝交承下令時，蒲葵絺葛豎降旗。", "書親燈火兒曹喜，鴈過沙場士卒悲。", "夜月一簾雖舊識，西風半榻是新知。", "從今景物皆清致，多辦吟箋剩賦詩。"]'),
('083fd9f6-0943-447f-b26f-76247fb9c7bc','九日登高次宋省齋韻','楊公遠','宋','宋诗','song-poetry','','[]','久出嘗思賦式微，半生心事少人知。',64,'全唐诗/poet.song.234000.json','["久出嘗思賦式微，半生心事少人知。", "登高且泛寒花酒，扶老須憑勁竹枝。", "樵逕緩躋山詰曲，羈懷難琢句新奇。", "絕憐萬里澄秋霽，辜負潘郎風雨詩。"]'),
('78547b0c-19c8-47a4-9b2b-399b8893f042','見山真意','楊公遠','宋','宋诗','song-poetry','','[]','栗里幽深自結廬，東籬採菊足清娛。',32,'全唐诗/poet.song.234000.json','["栗里幽深自結廬，東籬採菊足清娛。", "偶然觸目南山好，相對沈吟一語無。"]'),
('d079165c-c8ee-4d52-bd87-ff7ca5485e87','早行','楊公遠','宋','宋诗','song-poetry','','[]','黄粱已熟夢初醒，束擔匆匆促去程。',64,'全唐诗/poet.song.234000.json','["黄粱已熟夢初醒，束擔匆匆促去程。", "手挈杖端和袖裹，氣呵髭上覺冰生。", "山銜斗柄兩三點，犬吠籬根四五聲。", "何處梅花開較早，清香暗度動詩情。"]'),
('26049f29-cef6-4e0f-b0aa-71334e71b424','菊梅交承','楊公遠','宋','宋诗','song-poetry','','[]','寒花璨璨遶東籬，露洗霜欺未肯萎。',32,'全唐诗/poet.song.234000.json','["寒花璨璨遶東籬，露洗霜欺未肯萎。", "褪却清香誰領略，北風吹上小梅枝。"]'),
('52fbcea8-477c-4d02-b010-35d0944502c4','夜坐  其一','楊公遠','宋','宋诗','song-poetry','','[]','門外霜風獵獵聲，擁爐坐對一燈明。',64,'全唐诗/poet.song.234000.json','["門外霜風獵獵聲，擁爐坐對一燈明。", "閒思浮世古今事，倦聽荒城長短更。", "滿榻詩書終有味，半生名利竟無成。", "從人笑我衣冠別，雖不趨時却自清。"]'),
('b5740ff0-94c8-4e22-833b-9dc9548e7268','夜坐  其二','楊公遠','宋','宋诗','song-poetry','','[]','相伴青燈坐矮窗，老來計拙負年光。',64,'全唐诗/poet.song.234000.json','["相伴青燈坐矮窗，老來計拙負年光。", "畫灰有句羞才短，就枕無眠畏夜長。", "世路難躋緣峻嶮，人情易見爲炎凉。", "知心却藉風和月，時度梅花一線香。"]'),
('a2656946-09d5-47ef-b758-ff0c5f6bc858','再韻  其一','楊公遠','宋','宋诗','song-poetry','','[]','聽徹茶烹蚓竅聲，挑燈開卷眼能明。',64,'全唐诗/poet.song.234000.json','["聽徹茶烹蚓竅聲，挑燈開卷眼能明。", "□□□□□□□，過了殘冬歲又更。", "世事間關人易老，容懷蕭索寐難成。", "推窗且對梅花月，便覺塵襟一晌清。"]'),
('496cc961-87a7-4923-9866-a1141ffcb124','再韻  其二','楊公遠','宋','宋诗','song-poetry','','[]','榾柮爐紅密掩窗，傷嗟勞役度時光。',64,'全唐诗/poet.song.234000.json','["榾柮爐紅密掩窗，傷嗟勞役度時光。", "朝三雖怒暮還四，鳬短難添鶴自長。", "老憶少年成感慨，吟殘永夜越凄凉。", "教兒檢點銅匜看，報道猶存一縷香。"]'),
('c9ef692c-6be3-4d3f-ba65-37d752143330','生朝  其一','楊公遠','宋','宋诗','song-poetry','','[]','生朝自頌豈非呆，吟得詩成亦快哉。',64,'全唐诗/poet.song.234000.json','["生朝自頌豈非呆，吟得詩成亦快哉。", "六十平頭慳兩歲，百千往事付三杯。", "在家清苦僧留髮，立世支離櫟不材。", "却是與梅緣分厚，年年此日向儂開。"]'),
('c474b6a2-08d9-49d9-ba4c-b1e6366afbca','生朝  其二','楊公遠','宋','宋诗','song-poetry','','[]','七年客裏度初生，詩骨依然只鶴形。',64,'全唐诗/poet.song.234000.json','["七年客裏度初生，詩骨依然只鶴形。", "梅亦清臞鬚却白，吾將潦倒鬢還青。", "愧無德可書銀管，幸有酒堪儲玉缾。", "一點靈臺塵不滓，何消修鍊勘黄庭。"]'),
('7b6b4a74-61fe-4df8-837d-9af171ff4161','冬晴','楊公遠','宋','宋诗','song-poetry','','[]','歲序從教自改更，老天有意活蒼生。',64,'全唐诗/poet.song.234000.json','["歲序從教自改更，老天有意活蒼生。", "一冬晴暖雨全少，三日陰寒雪不成。", "謾擁地爐然榾柮，每憂時事驗欃槍。", "庭前問訊枯梅樹，怕有南枝綻玉英。"]'),
('c55799dc-3da5-4339-b966-47bc3bf4a8ab','觀梅','楊公遠','宋','宋诗','song-poetry','','[]','老來寵辱兩無聞，纔見梅花喜十分。',64,'全唐诗/poet.song.234000.json','["老來寵辱兩無聞，纔見梅花喜十分。", "冰雪相看雖屬我，乾坤獨步却輸君。", "受知和靖黄昏月，入夢昌齡落寞雲。", "從此暗香來不斷，何消更把水沈焚。"]'),
('7cbc3be6-c3de-4de5-81b1-aaa263190862','探梅','楊公遠','宋','宋诗','song-poetry','','[]','竹杖芒鞋作興來，來時準擬有花開。',32,'全唐诗/poet.song.234000.json','["竹杖芒鞋作興來，來時準擬有花開。", "誰知老樹荒烟裏，地冷孤根暖未回。"]'),
('bbc06b4c-9374-4f7b-a226-cead851b8e94','訪梅','楊公遠','宋','宋诗','song-poetry','','[]','荒寒茅屋是誰家，獨木橋橫小逕斜。',32,'全唐诗/poet.song.234000.json','["荒寒茅屋是誰家，獨木橋橫小逕斜。", "却是無人行到處，春風先已到梅花。"]'),
('ae8e1313-fccc-41c1-919a-e2f0a28b9cd1','寄梅','楊公遠','宋','宋诗','song-poetry','','[]','方愧無由洗俗塵，喜逢竹外一枝春。',32,'全唐诗/poet.song.234000.json','["方愧無由洗俗塵，喜逢竹外一枝春。", "看來未敢輕攀折，待侑詩篇贈故人。"]'),
('8b37a647-003c-4761-b08d-8ee2e57e1cca','賦梅','楊公遠','宋','宋诗','song-poetry','','[]','雪月雲煙件件宜，騷人墨客費尋思。',32,'全唐诗/poet.song.234000.json','["雪月雲煙件件宜，騷人墨客費尋思。", "怕渠因得逋仙句，不要人言半字詩。"]'),
('53d81fea-e404-4197-bacb-344ab4de61d1','觀梅','楊公遠','宋','宋诗','song-poetry','','[]','東閣觀梅效少陵，巡簷索笑面生春。',32,'全唐诗/poet.song.234000.json','["東閣觀梅效少陵，巡簷索笑面生春。", "試將心事從渠道，恰又無言領略人。"]'),
('cf7e28de-2b36-4d78-99e6-288c86481adf','折梅','楊公遠','宋','宋诗','song-poetry','','[]','折時須揀带苔枝，兩蘂三花儘自奇。',32,'全唐诗/poet.song.234000.json','["折時須揀带苔枝，兩蘂三花儘自奇。", "簪向銀缾全俗了，古銅缾浸恰相宜。"]'),
('ab891e61-9006-40f6-a667-f91faad28cc3','寫梅','楊公遠','宋','宋诗','song-poetry','','[]','爲渠模寫未爲難，只要稀疎不要繁。',32,'全唐诗/poet.song.234000.json','["爲渠模寫未爲難，只要稀疎不要繁。", "雪月風煙俱屬我，一時收拾付毫端。"]'),
('b44badaa-b149-41c3-abe7-b65f3267a9e5','紅梅','楊公遠','宋','宋诗','song-poetry','','[]','特立孤高耐歲寒，渥丹顔貌带儒酸。',32,'全唐诗/poet.song.234000.json','["特立孤高耐歲寒，渥丹顔貌带儒酸。", "荆公詩句休拈出，北地人今已熟看。"]'),
('9c319694-8185-4c5d-990c-79045a5f7116','千葉梅','楊公遠','宋','宋诗','song-poetry','','[]','千葉梅開一樣清，向人含笑似多情。',32,'全唐诗/poet.song.234000.json','["千葉梅開一樣清，向人含笑似多情。", "化工只麽寧多巧，碎剪瓊瑶細簇成。"]'),
('bc39511e-99dc-49c9-b0d9-3072c7b3cac0','雪梅','楊公遠','宋','宋诗','song-poetry','','[]','凍合頑雲四幕垂，須臾六出攪空飛。',32,'全唐诗/poet.song.234000.json','["凍合頑雲四幕垂，須臾六出攪空飛。", "梅花自稟清臞相，底事添渠十倍肥。"]'),
('656316a7-9200-49f7-99e8-66e8ac9a0abf','月梅','楊公遠','宋','宋诗','song-poetry','','[]','梢如鹿角月如眉，月到梢頭分外宜。',32,'全唐诗/poet.song.234000.json','["梢如鹿角月如眉，月到梢頭分外宜。", "梅得月來無限好，月和梅看越清奇。"]'),
('cc5748dd-1a0c-4920-bb7e-7da14c3e2ed9','烟梅','楊公遠','宋','宋诗','song-poetry','','[]','玉妃謫墮作梅花，不與羣芳定等差。',32,'全唐诗/poet.song.234000.json','["玉妃謫墮作梅花，不與羣芳定等差。", "莫是清高嫌俗眼，故張翠幕淡籠遮。"]'),
('4725e5d2-50d1-415d-813a-8736d997acc2','霜梅','楊公遠','宋','宋诗','song-poetry','','[]','梅到更闌自主張，依然不住散清香。',32,'全唐诗/poet.song.234000.json','["梅到更闌自主張，依然不住散清香。", "橫陳青女無端甚，也要教渠學粉妝。"]'),
('a480cd9a-4153-41b7-a614-6f87972689ba','冰梅','楊公遠','宋','宋诗','song-poetry','','[]','絕憐花带雪璘瓏，彷彿惟存蠟蔕紅。',32,'全唐诗/poet.song.234000.json','["絕憐花带雪璘瓏，彷彿惟存蠟蔕紅。", "一夜清寒風結凍，分明身在水晶宮。"]'),
('e7f21192-4325-4b87-adc0-7bf2f78d1b33','照水梅','楊公遠','宋','宋诗','song-poetry','','[]','梢橫鶴膝小池東，幾點疎花冷淡中。',32,'全唐诗/poet.song.234000.json','["梢橫鶴膝小池東，幾點疎花冷淡中。", "自是曉妝勻未了，故擡粉面對青銅。"]'),
('3a9b5912-5e72-448a-94ab-72255b032a9e','梅影','楊公遠','宋','宋诗','song-poetry','','[]','柴門相對月華新，月上梅梢絕點塵。',32,'全唐诗/poet.song.234000.json','["柴門相對月華新，月上梅梢絕點塵。", "却是嫦娥工性巧，不須泓穎畫全身。"]'),
('e47244c7-3a83-4278-8505-53df974b3fe6','早梅','楊公遠','宋','宋诗','song-poetry','','[]','籬下叢叢菊老時，清香飛上向南枝。',32,'全唐诗/poet.song.234000.json','["籬下叢叢菊老時，清香飛上向南枝。", "化工未必無私意，試問春風知不知。"]'),
('63f34776-9083-4585-9f11-307864317493','遲梅','楊公遠','宋','宋诗','song-poetry','','[]','盡道孤根逗暖回，緣何春至未肧胎。',32,'全唐诗/poet.song.234000.json','["盡道孤根逗暖回，緣何春至未肧胎。", "東皇想是憐孤獨，留與羣芳作伴開。"]'),
('7ec1cd6f-eef0-4862-bd2f-6c14a460c436','殘梅','楊公遠','宋','宋诗','song-poetry','','[]','可惜梢頭爛漫芳，無心要趁壽陽妝。',32,'全唐诗/poet.song.234000.json','["可惜梢頭爛漫芳，無心要趁壽陽妝。", "寧教片片隨風去，點在苔痕骨也香。"]'),
('8dc4236e-9044-4d54-bb40-d51d15cac88c','梅實','楊公遠','宋','宋诗','song-poetry','','[]','纍纍青子綴枝丫，一味含酸軟齒牙。',32,'全唐诗/poet.song.234000.json','["纍纍青子綴枝丫，一味含酸軟齒牙。", "不獨曹軍資止渴，也曾調鼎佐商家。"]'),
('703be6f3-fde0-4f00-b729-9eaf1761784c','十二月二十九夜大雪  其一','楊公遠','宋','宋诗','song-poetry','','[]','六出霏霏餞歲華，終宵撩亂撲窗紗。',64,'全唐诗/poet.song.234000.json','["六出霏霏餞歲華，終宵撩亂撲窗紗。", "未言造化工夫巧，且看乾坤景象奢。", "□□□□□□□，□□□□□□花。", "明朝正旦常年別，瓊戶瑶階一樣誇。"]'),
('6ac48dc0-b7c3-4483-8045-85b5048c17fc','十二月二十九夜大雪  其二','楊公遠','宋','宋诗','song-poetry','','[]','歲已云除四日春，正嗟無雪慰農心。',64,'全唐诗/poet.song.234000.json','["歲已云除四日春，正嗟無雪慰農心。", "重衾夜覺十分冷，平地朝看一尺深。", "剡曲舟雖無月載，灞橋景更有誰吟。", "今宵拚飲椒花酒，醉後烹茶自賞音。"]'),
('5c17bba5-82a4-414b-a237-b6a7d8a957dd','十二月二十九夜大雪  其三','楊公遠','宋','宋诗','song-poetry','','[]','天教滕六下良宵，恰值人間正頌椒。',64,'全唐诗/poet.song.234000.json','["天教滕六下良宵，恰值人間正頌椒。", "萬屋高低皆玉潔，四山遠邇絕塵囂。", "蒼髯鐵面亦華髮，直節虛心也折腰。", "可惜梅花無覓處，祇應低亞小溪橋。"]'),
('b99481cf-8acc-45b5-bc9b-16bb812c4638','友梅吳編校壽宮之側築庵曰全歸有詩十詠敬次之  其一','楊公遠','宋','宋诗','song-poetry','','[]','達人謀事豈躊躇，壽域天開不費鉏。',32,'全唐诗/poet.song.234000.json','["達人謀事豈躊躇，壽域天開不費鉏。", "結得庵成無點俗，栽梅蒔竹當幽居。"]'),
('92cd6ce6-1f64-4851-aeff-e44bacdd88be','友梅吳編校壽宮之側築庵曰全歸有詩十詠敬次之  其二','楊公遠','宋','宋诗','song-poetry','','[]','蓋世功名水一杯，君曾勘破箇中來。',32,'全唐诗/poet.song.234000.json','["蓋世功名水一杯，君曾勘破箇中來。", "平生不問凡紅紫，莫逆交情只是梅。"]'),
('d13cc87a-e8b9-49de-843a-b89ec272c207','友梅吳編校壽宮之側築庵曰全歸有詩十詠敬次之  其三','楊公遠','宋','宋诗','song-poetry','','[]','壽宅雖然已預營，手栽松柏待亭亭。',32,'全唐诗/poet.song.234000.json','["壽宅雖然已預營，手栽松柏待亭亭。", "童顔鶴髮身强健，長對商山萬古青。"]'),
('c3555758-6392-43d3-a8d6-7d82afeeb0c6','友梅吳編校壽宮之側築庵曰全歸有詩十詠敬次之  其四','楊公遠','宋','宋诗','song-poetry','','[]','休論馬鬣卧牛形，後擁前堆要有情。',32,'全唐诗/poet.song.234000.json','["休論馬鬣卧牛形，後擁前堆要有情。", "自是主人心地好，老天分付不應輕。"]'),
('f64f3497-0f19-478b-851f-f3e6f85195f9','友梅吳編校壽宮之側築庵曰全歸有詩十詠敬次之  其五','楊公遠','宋','宋诗','song-poetry','','[]','屋瞰梅間倚竹林，一爐香篆一張琴。',32,'全唐诗/poet.song.234000.json','["屋瞰梅間倚竹林，一爐香篆一張琴。", "有時月上黄昏後，三弄寒梅夜正深。"]'),
('d567ae52-0c1d-4a84-bdd4-2b17c62f14d2','友梅吳編校壽宮之側築庵曰全歸有詩十詠敬次之  其六','楊公遠','宋','宋诗','song-poetry','','[]','梅花本是一難兄，山谷當時錯用情。',32,'全唐诗/poet.song.234000.json','["梅花本是一難兄，山谷當時錯用情。", "畢竟渠家知己在，仙礬贏得浪馳聲。"]'),
('5c8965f9-73c6-4cb3-9c3e-56033ba7efe7','友梅吳編校壽宮之側築庵曰全歸有詩十詠敬次之  其七','楊公遠','宋','宋诗','song-poetry','','[]','游山瓢具竹邊安，石鼎松邊瀹鳳團。',32,'全唐诗/poet.song.234000.json','["游山瓢具竹邊安，石鼎松邊瀹鳳團。", "更向梅邊觀鶴舞，好將模作畫圖看。"]'),
('6cae04ff-aa91-422d-89ef-eefc35ab80bc','友梅吳編校壽宮之側築庵曰全歸有詩十詠敬次之  其八','楊公遠','宋','宋诗','song-poetry','','[]','庵外山環翠作堆，庵前山秀長臺萊。',32,'全唐诗/poet.song.234000.json','["庵外山環翠作堆，庵前山秀長臺萊。", "主人日日携琴去，直到松梢月上回。"]'),
('4730971c-9374-4a62-bedb-59035321f1ae','友梅吳編校壽宮之側築庵曰全歸有詩十詠敬次之  其九','楊公遠','宋','宋诗','song-poetry','','[]','顔貌元非借酒紅，那堪和氣更春風。',32,'全唐诗/poet.song.234000.json','["顔貌元非借酒紅，那堪和氣更春風。", "梅邊索笑閒吟處，句法清圓字字工。"]'),
('85be387b-04cf-4d82-820c-6ff156a30da9','友梅吳編校壽宮之側築庵曰全歸有詩十詠敬次之  其一○','楊公遠','宋','宋诗','song-poetry','','[]','竹滿長洲蔬滿畦，四時豐富足豚雞。',32,'全唐诗/poet.song.234000.json','["竹滿長洲蔬滿畦，四時豐富足豚雞。", "况君賸有羊腔祿，笑我猶餘幾甕虀。"]'),
('b0f548a5-fd4b-43ac-b4d1-e0e043fc7f3b','上巳同省齋直軒郊游直軒有詩次韻是日又值寒食節','楊公遠','宋','宋诗','song-poetry','','[]','韶光又是二分過，日月如梭可奈何。',64,'全唐诗/poet.song.234000.json','["韶光又是二分過，日月如梭可奈何。", "對景詩成新意少，持杯量減舊時多。", "禁烟修禊偶同日，落絮飛花逐逝波。", "祇恐陰晴天不定，明朝有興亦蹉跎。"]'),
('3a0335b0-2843-4e2b-a2ae-610c9466af54','春夜聽雨','楊公遠','宋','宋诗','song-poetry','','[]','小樓炙燭未成眠，好雨知時聽不厭。',64,'全唐诗/poet.song.234000.json','["小樓炙燭未成眠，好雨知時聽不厭。", "風急斜敲窗上紙，簷高微灑楯邊簾。", "花應憔悴啼丹臉，麥定惺愡磔翠髯。", "添得明朝詩興好，池塘草長水漸漸。"]'),
('3be2e6e6-5396-4dc2-b11a-af764de1a971','見王書史係按察司所委平反勸課','楊公遠','宋','宋诗','song-poetry','','[]','翩翩旌旆下吾邦，六邑喧傳姓字香。',64,'全唐诗/poet.song.234000.json','["翩翩旌旆下吾邦，六邑喧傳姓字香。", "不著一塵秋夜月，謹施三尺曉天霜。", "平反獄訟縲囚喜，勸課農桑惰叟忙。", "昨拜荆州天與幸，敢趨行幕獻詩章。"]'),
('746223f4-060a-4e71-b079-1c03ce2b4915','再用韻奉酬','楊公遠','宋','宋诗','song-poetry','','[]','褰帷暫駐小山邦，正值芳春百卉香。',64,'全唐诗/poet.song.234000.json','["褰帷暫駐小山邦，正值芳春百卉香。", "洞徹胸襟欺雪月，英豪名譽冷風霜。", "評分曲直奸人畏，詩費賡酬竟日忙。", "寒士無聲增重處，珠璣璀璨賜平章。"]'),
('50015946-d29e-49ed-9a7a-54b14c3082ca','三用韻奉酬','楊公遠','宋','宋诗','song-poetry','','[]','山水新安斗大邦，也煩臨按馬蹄香。',64,'全唐诗/poet.song.234000.json','["山水新安斗大邦，也煩臨按馬蹄香。", "扶持秀士蛟逢雨，糾察貪夫草遇霜。", "對景詩成吟思好，劭農心切去裝忙。", "自慚野叟何爲者，白雪陽春拜兩章。"]'),
('ce43d43b-5ffa-4455-8fc2-f66c04b76972','四用韻奉酬','楊公遠','宋','宋诗','song-poetry','','[]','文獻中州仰大邦，姓名由此带天香。',64,'全唐诗/poet.song.234000.json','["文獻中州仰大邦，姓名由此带天香。", "襟懷月照江湖水，談笑風生齒頰霜。", "天理每從閒處見，詩篇常向靜中忙。", "明朝小隊郊坰去，儻有新吟寄一章。"]'),
('d7e53897-1227-4c57-9fb2-7c65101bebb0','五用韻奉酬見寄  其一','楊公遠','宋','宋诗','song-poetry','','[]','揚鞭迤邐歷鄉邦，留得清名處處香。',64,'全唐诗/poet.song.234000.json','["揚鞭迤邐歷鄉邦，留得清名處處香。", "六邑春風濃似酒，一輪秋月冷於霜。", "蘇回民瘼宦情好，聽徹鵑聲歸興忙。", "滿路溪山無限好，祇應裁剪入詞章。"]'),
('b7114e49-a1e7-4210-82a2-917fcce84182','五用韻奉酬見寄  其二','楊公遠','宋','宋诗','song-poetry','','[]','潦倒無成困一邦，江湖姓字可曾香。',64,'全唐诗/poet.song.234000.json','["潦倒無成困一邦，江湖姓字可曾香。", "興來且泛三杯酒，老去從添兩鬢霜。", "畫思詩情雖我有，名韁利鎖任渠忙。", "寒窗兀坐渾無事，閒閲離騷誦九章。"]'),
('322aea57-9615-424f-a7a4-86ac1b07dcc6','寄陸同府','楊公遠','宋','宋诗','song-poetry','','[]','憶昔輕舟衣錦還，青紅旗幟滿江邊。',64,'全唐诗/poet.song.234000.json','["憶昔輕舟衣錦還，青紅旗幟滿江邊。", "正逢時節梅將潦，又見池塘柳欲綿。", "千古棠陰思召伯，一封芝詔下堯天。", "行看大展經綸手，霖雨蒼生四海傳。"]'),
('e060fa06-705e-44f4-9a3d-34954e13ef35','呈趙提領','楊公遠','宋','宋诗','song-poetry','','[]','從容依綠泛蓮紅，吾郡生民有幸逢。',64,'全唐诗/poet.song.234000.json','["從容依綠泛蓮紅，吾郡生民有幸逢。", "政事分明天外月，風標翹楚雪中松。", "携琴領鶴宦情好，橫笛倚樓詩興濃。", "騰茂蜚英聞帝里，行看寵錫祿千鍾。"]'),
('ed78d3c8-213f-4f26-95aa-23174a0dbaa8','迓王書史六邑勸課回四絕  其一','楊公遠','宋','宋诗','song-poetry','','[]','雕鞍駿馬驟如飛，正是春風柳絮時。',32,'全唐诗/poet.song.234000.json','["雕鞍駿馬驟如飛，正是春風柳絮時。", "夾道居民爭看處，青紅小隊曳旌旗。"]'),
('ce8265e8-a075-4dc0-99d9-d359376735ef','迓王書史六邑勸課回四絕  其二','楊公遠','宋','宋诗','song-poetry','','[]','一犁雨足快耕農，可卜今年歲事豐。',32,'全唐诗/poet.song.234000.json','["一犁雨足快耕農，可卜今年歲事豐。", "喜見四郊生意好，秧針刺水麥梳風。"]'),
('34d96f6e-419a-41d5-bf8e-9a427ba7e24c','迓王書史六邑勸課回四絕  其三','楊公遠','宋','宋诗','song-poetry','','[]','杜鵑聲裏莫春天，桑柘村村綠似烟。',32,'全唐诗/poet.song.234000.json','["杜鵑聲裏莫春天，桑柘村村綠似烟。", "分繭稱絲將有日，吳蠶今已起三眠。"]'),
('d0c8cd43-538b-4f58-b41d-80223b1fb4a0','迓王書史六邑勸課回四絕  其四','楊公遠','宋','宋诗','song-poetry','','[]','匆匆出郭又經旬，和氣薰蒸處處春。',32,'全唐诗/poet.song.234000.json','["匆匆出郭又經旬，和氣薰蒸處處春。", "料得錦囊詩拍塞，寄來曾拜一篇新。"]'),
('4db47054-8814-4b3c-903a-7bd47355b967','再韻奉酬  其一','楊公遠','宋','宋诗','song-poetry','','[]','穿簾燕子作雙飛，恰是春光欲老時。',32,'全唐诗/poet.song.234000.json','["穿簾燕子作雙飛，恰是春光欲老時。", "公退祇應無箇事，山泉石鼎煮鎗旗。"]'),
('a565ac64-61ca-4e38-9254-69f3c2591a82','再韻奉酬  其二','楊公遠','宋','宋诗','song-poetry','','[]','夫耕婦餉念斯農，蠶麥將登慶小豐。',32,'全唐诗/poet.song.234000.json','["夫耕婦餉念斯農，蠶麥將登慶小豐。", "不是今年天意好，皆由教雨與仁風。"]'),
('aba1e329-4a24-4170-bc62-d6d32374e5ff','再韻奉酬  其三','楊公遠','宋','宋诗','song-poetry','','[]','楊花一任雪漫天，清坐鈎簾對篆烟。',32,'全唐诗/poet.song.234000.json','["楊花一任雪漫天，清坐鈎簾對篆烟。", "應是日長詩酒罷，困來閒向北窗眠。"]'),
('eb82e81e-ce33-4d38-959d-c5333613bd44','再韻奉酬  其四','楊公遠','宋','宋诗','song-poetry','','[]','自愧浮生又六旬，苦無情况度殘春。',32,'全唐诗/poet.song.234000.json','["自愧浮生又六旬，苦無情况度殘春。", "謾吟俚句塵清聽，多謝賡酬字字新。"]'),
('d2f2be19-7dc2-497d-8be0-7d898bffd874','三用韻奉酬  其一','楊公遠','宋','宋诗','song-poetry','','[]','龍蛇滿紙勢如飛，浄几明窗得句時。',32,'全唐诗/poet.song.234000.json','["龍蛇滿紙勢如飛，浄几明窗得句時。", "一陣好風吹過我，吟餘束手豎降旗。"]'),
('4e79c4e8-9e6d-4854-bfba-c2b7be571c46','三用韻奉酬  其二','楊公遠','宋','宋诗','song-poetry','','[]','不是騷人不是農，筆耕墨耒願年豐。',32,'全唐诗/poet.song.234000.json','["不是騷人不是農，筆耕墨耒願年豐。", "有時啜罷盧仝茗，習習能生兩腋風。"]'),
('5eb98390-576a-42f9-96bc-c0ac2cf048da','三用韻奉酬  其三','楊公遠','宋','宋诗','song-poetry','','[]','乍雨微寒養麥天，村村斜日起炊烟。',32,'全唐诗/poet.song.234000.json','["乍雨微寒養麥天，村村斜日起炊烟。", "老夫但愧缾無酒，芳草如茵好醉眠。"]'),
('9f10713e-b3a1-4495-bd2b-def9afbd932f','三用韻奉酬  其四','楊公遠','宋','宋诗','song-poetry','','[]','今日韶光滿九旬，浮生又了一年春。',32,'全唐诗/poet.song.234000.json','["今日韶光滿九旬，浮生又了一年春。", "莫言虛度渾無補，學得先生句法新。"]'),
('36338e43-c0f5-421d-8edb-b721a880cd7b','餞王書史','楊公遠','宋','宋诗','song-poetry','','[]','攬轡來時柳未烟，榴花又見火初然。',64,'全唐诗/poet.song.234000.json','["攬轡來時柳未烟，榴花又見火初然。", "一春人坐冰霜國，四野農歌蠶麥天。", "教雨仁風彌歙境，屏山練水入吟編。", "明朝馬首東歸去，佇看清名到日邊。"]'),
('a7b3ac87-0fba-4661-bda2-5daccab04eea','初夏旅中  其一','楊公遠','宋','宋诗','song-poetry','','[]','烏兔雙飛去若梭，又逢天氣正清和。',64,'全唐诗/poet.song.234000.json','["烏兔雙飛去若梭，又逢天氣正清和。", "綠空桑柘蠶成繭，青遍田疇犢卧莎。", "好景常供詩料足，浮生每歎客愁多。", "家山不是無風月，斗粟區區可奈何。"]'),
('ae9f6cb8-74d6-4112-a827-8383fa56b44c','初夏旅中  其二','楊公遠','宋','宋诗','song-poetry','','[]','早起窗前擁弊裘，鬢毛蕭散冷颼颼。',64,'全唐诗/poet.song.234000.json','["早起窗前擁弊裘，鬢毛蕭散冷颼颼。", "葵榴花發已云夏，竹樹風生却似秋。", "驟雨乍晴雙港漲，宿雲初斂四山幽。", "客懷頓覺添蕭灑，且放吟情出一頭。"]'),
('8f619882-dafb-4b9b-9c83-215c3ec1b937','初夏旅中  其三','楊公遠','宋','宋诗','song-poetry','','[]','往來蕭寺幾經年，時向僧窗聽說禪。',64,'全唐诗/poet.song.234000.json','["往來蕭寺幾經年，時向僧窗聽說禪。", "一事不成空老去，三椽聊寓幸安眠。", "詩篇冰雪無蔬氣，粥飯齏鹽有道緣。", "欲卜歸期猶未定，况聞綠樹有啼鵑。"]'),
('183bc65a-bccc-4378-88c6-173d412d05d1','初夏旅中  其四','楊公遠','宋','宋诗','song-poetry','','[]','吟髭細撚祇堪傷，幾度徘徊立夕陽。',64,'全唐诗/poet.song.234000.json','["吟髭細撚祇堪傷，幾度徘徊立夕陽。", "詩不療饑徒著意，酒能作病莫持觴。", "此心軒豁出雲月，浮世間關逆水航。", "多謝老天憐我在，長教窮健又何妨。"]'),
('b551e10b-d35b-4ef5-bcf3-4a886b3942ee','初夏旅中  其五','楊公遠','宋','宋诗','song-poetry','','[]','每憶吾廬隠者居，天然景物足清娛。',64,'全唐诗/poet.song.234000.json','["每憶吾廬隠者居，天然景物足清娛。", "樹林陰翳鶑求友，簾幕深沈燕引雛。", "可釣可耕盤谷序，堪詩堪畫輞川圖。", "何當歸去北窗卧，能勝羲皇以上無。"]'),
('8711d28c-6589-43bd-98eb-48724bc5e87d','竹夫人','楊公遠','宋','宋诗','song-poetry','','[]','羞領青奴號，由來節操剛。',48,'全唐诗/poet.song.234000.json','["羞領青奴號，由來節操剛。", "有生惟具眼，不妬爲無腸。", "戀戀言何寂，娟娟體自凉。", "棄捐知素分，那敢望專房。"]'),
('52b90957-13bc-4699-9dad-c42a7cb79ae6','餞康侯  其一','楊公遠','宋','宋诗','song-poetry','','[]','報政三年滿，還容借寇麽。',48,'全唐诗/poet.song.234000.json','["報政三年滿，還容借寇麽。", "絲綸來帝幄，襦袴藹民歌。", "遺愛棠陰茂，留傳錦句多。", "蒼生今有待，霖雨早滂沱。"]'),
('b8927c37-9231-41e7-971d-f17778d4becc','餞康侯  其二','楊公遠','宋','宋诗','song-poetry','','[]','古歙何多幸，民叨撫育恩。',48,'全唐诗/poet.song.234000.json','["古歙何多幸，民叨撫育恩。", "清聲冠今古，浩氣滿乾坤。", "夜月一船載，秋風三逕存。", "莫能攀去轍，戀戀勸金樽。"]'),
('4a772c89-4e4a-49e8-bb1d-3df947a4395f','新安江上次程南仲韻','楊公遠','宋','宋诗','song-poetry','','[]','石闌斜護崎嶇逕，村酒頻澆磊磈胸。',32,'全唐诗/poet.song.234000.json','["石闌斜護崎嶇逕，村酒頻澆磊磈胸。", "好是黄山供望眼，白雲分出兩三峰。"]'),
('d000972e-e9dd-48bd-9501-a3362da8cac0','次韻凌義山  其一','楊公遠','宋','宋诗','song-poetry','','[]','自憐老境漸侵尋，檢點頭顱雪旋深。',64,'全唐诗/poet.song.234000.json','["自憐老境漸侵尋，檢點頭顱雪旋深。", "無酒澆愁還獨嘯，有時得句但長吟。", "一天月色涵秋意，四壁蛩聲惱客心。", "好是夜凉清似水，蕭蕭風度古松林。"]'),
('979c3fb7-4819-4342-9c59-6d90d9305342','次韻凌義山  其二','楊公遠','宋','宋诗','song-poetry','','[]','眼前詩料底消尋，移入蠻牋別淺深。',64,'全唐诗/poet.song.234000.json','["眼前詩料底消尋，移入蠻牋別淺深。", "無斧鑿痕方造妙，超塵俗表始堪吟。", "物情體狀須留意，句眼推敲好用心。", "試看咏梅千萬首，影香獨數老逋林。"]'),
('da174e4e-8d8f-45f1-835b-499221c1e55c','促織用前韻','楊公遠','宋','宋诗','song-poetry','','[]','兒童探穴戲搜尋，隱跡苔階深復深。',64,'全唐诗/poet.song.234000.json','["兒童探穴戲搜尋，隱跡苔階深復深。", "見敵有時能勇鬭，無情終夜只清吟。", "喚回枕上羈人夢，惱碎閨中織婦心。", "莫向當今機局去，拋梭絡緯已林林。"]'),
('7a8e8117-943b-4163-a1bc-0a01966422b9','水西行散次韻程南仲','楊公遠','宋','宋诗','song-poetry','','[]','散步招提去，禪房幽更深。',48,'全唐诗/poet.song.234000.json','["散步招提去，禪房幽更深。", "開經醒俗眼，瀹茗洗塵心。", "石罅泉長溜，林巔蟬獨吟。", "詩成書雪壁，恐或有知音。"]'),
('6c722c46-e063-46d8-a871-abdaf4e99867','次韻黄仲宣九日','楊公遠','宋','宋诗','song-poetry','','[]','又逢重九日，七載寓僧廬。',48,'全唐诗/poet.song.234000.json','["又逢重九日，七載寓僧廬。", "送酒人何在，迎風帽自如。", "萸肥含味遠，菊瘦著花疎。", "祇麽酬佳節，詩成繭紙書。"]'),
('86922342-1732-4d53-bc23-a95d8aeaed38','九日同王月溪訪紫陽有詩次韻','楊公遠','宋','宋诗','song-poetry','','[]','西風凄緊未成霜，拄杖橫拖訪紫陽。',64,'全唐诗/poet.song.234000.json','["西風凄緊未成霜，拄杖橫拖訪紫陽。", "遶郭溪山千古勝，泛杯萸菊一時香。", "鬢邊有雪身還健，筆底無塵句不狂。", "佳節直須拚酩酊，渾如仙在白雲鄉。"]'),
('e97a77d0-3527-4dbf-8931-3cd8e137e644','用前韻酬鄭山長','楊公遠','宋','宋诗','song-poetry','','[]','短鬢蕭蕭已半霜，從教憔悴勝東陽。',64,'全唐诗/poet.song.234000.json','["短鬢蕭蕭已半霜，從教憔悴勝東陽。", "磨穿老硯畫成趣，撚斷吟髭句不香。", "月下行歌閒放逸，酒邊起舞發清狂。", "欲過鄭老論心事，可惜相逢各異鄉。"]'),
('b43abc50-9d4a-422a-8462-dfefdcbacfe5','用前韻酬項性初','楊公遠','宋','宋诗','song-poetry','','[]','連年客裏度星霜，過了重陽又一陽。',64,'全唐诗/poet.song.234000.json','["連年客裏度星霜，過了重陽又一陽。", "籬下正憐叢菊老，風前將領早梅香。", "寧同子美吟詩瘦，豈效寬饒肆酒狂。", "欲卜歸期猶未定，空勞魂夢遶江鄉。"]'),
('76292a7d-8bec-4032-abef-4b5bb0b8c764','次韻鄭山長九日','楊公遠','宋','宋诗','song-poetry','','[]','詩逢佳節應酬忙，三斗何妨效汝陽。',64,'全唐诗/poet.song.234000.json','["詩逢佳節應酬忙，三斗何妨效汝陽。", "帽任欹斜雙鬢白，菊無今古數枝黄。", "龍山景物自消長，栗里琴書今在亡。", "往事莫談添感慨，醒時也作次公狂。"]'),
('eefb087e-bd10-4f85-b3fa-08131e26961f','江天曉望次南仲韻','楊公遠','宋','宋诗','song-poetry','','[]','江天向曉縕輕寒，霧捲雲收眼界寬。',64,'全唐诗/poet.song.234000.json','["江天向曉縕輕寒，霧捲雲收眼界寬。", "鴈起沙頭兵出戍，鷺翹柳上雪成團。", "數聲柔櫓船初發，一片寒蘆葉半乾。", "無奈滿前詩料富，耽吟幾致廢朝餐。"]'),
('b635d863-caf4-457b-9f21-60c763201985','飲歸次南仲韻','楊公遠','宋','宋诗','song-poetry','','[]','霜後楓林渾似纈，籬邊菊老香初歇。',32,'全唐诗/poet.song.234000.json','["霜後楓林渾似纈，籬邊菊老香初歇。", "昏昏醉夢了時光，一任頭顱堆白雪。"]'),
('a4343fb5-b2c1-41a2-b928-0006c632c200','次汪菊坡秋深韻','楊公遠','宋','宋诗','song-poetry','','[]','秋深天氣肅，風緊襲人衣。',48,'全唐诗/poet.song.234000.json','["秋深天氣肅，風緊襲人衣。", "攪夢蛩聲碎，驚心鴈陣飛。", "事嗟今日別，身愧昔年非。", "欲辦青蓑笠，滄浪理釣磯。"]'),
('5839bf66-9d4d-4585-83d4-501d05c9d831','寄餞東麓趙贊府之官湖南','楊公遠','宋','宋诗','song-poetry','','[]','憶昔鳴騶闖草廬，歡然把酒話襟期。',64,'全唐诗/poet.song.234000.json','["憶昔鳴騶闖草廬，歡然把酒話襟期。", "自從六月袂分後，又是重陽節過時。", "江左英賢姑佐邑，湖南松竹助哦詩。", "餞違不及空惆悵，儻或逢梅寄一枝。"]'),
('6d264349-0d57-4d28-81c7-4c1c5f4abe99','泊浙江東岸次斗山韻','楊公遠','宋','宋诗','song-poetry','','[]','渺渺江空闊，停帆首屢回。',48,'全唐诗/poet.song.234000.json','["渺渺江空闊，停帆首屢回。", "漁家編葦荻，蜃氣幻樓臺。", "逸少亭應在，鴟夷棹不來。", "一鈎新月上，時把篾篷推。"]'),
('9550ac77-2d4f-451a-83ab-d3d21ce2205d','謁和靖先生墓借斗山韻','楊公遠','宋','宋诗','song-poetry','','[]','孤山仙塚草菲菲，姓字留將後世知。',64,'全唐诗/poet.song.234000.json','["孤山仙塚草菲菲，姓字留將後世知。", "遣稿文無封禪事，名家梅有影香詩。", "祇慚老子携琴晚，不見蒼頭放鶴時。", "一瓣心香聊敢敬，寒泉自掬酹甆巵。"]'),
('f9065700-d4b4-4fe2-9dd4-d990446b2334','黄盆渡次友人韻','楊公遠','宋','宋诗','song-poetry','','[]','到得黄盆九月天，呼童弛擔駐征韉。',64,'全唐诗/poet.song.234000.json','["到得黄盆九月天，呼童弛擔駐征韉。", "迢迢江水天連楚，漠漠淮鄉稻滿田。", "酒旆風翻疎柳外，漁家網曬夕陽邊。", "買將郭索傾杯處，對景詩成恰一篇。"]'),
('5cde383f-2414-4c67-90ed-b4df6ea86fd3','芳溪閒步','楊公遠','宋','宋诗','song-poetry','','[]','竹杖芒鞋度斷岡，崎嶇小逕遶寒塘。',64,'全唐诗/poet.song.234000.json','["竹杖芒鞋度斷岡，崎嶇小逕遶寒塘。", "野梅照水初含白，山菊支霜未委黄。", "對景每番成感慨，把杯幾度放疎狂。", "此生但只安吾分，無辱無榮壽且康。"]'),
('3f6470ad-4e05-489a-99cf-2f3dfda724c7','呈許使君  其一','楊公遠','宋','宋诗','song-poetry','','[]','河嶽中原地，英賢間世生。',48,'全唐诗/poet.song.234000.json','["河嶽中原地，英賢間世生。", "氣雄虹萬丈，心浄月三更。", "韓柳文同妙，龔黄政共清。", "新安人有分，月旦願推評。"]'),
('a54d13f5-20cc-456e-ae8c-c037bebf3b65','呈許使君  其二','楊公遠','宋','宋诗','song-poetry','','[]','蒙泉清徹底，更不著纖塵。',48,'全唐诗/poet.song.234000.json','["蒙泉清徹底，更不著纖塵。", "滕閣曾逢月，花屏又遇春。", "采芹尊秀士，拔薤抑强民。", "祇恐芝泥召，催歸侍紫宸。"]'),
('6230e72a-b618-43d3-9285-33d4c99103c4','張道士山房次程南仲韻','楊公遠','宋','宋诗','song-poetry','','[]','丹房蕭灑絕纖埃，石逕縈紆闢草萊。',64,'全唐诗/poet.song.234000.json','["丹房蕭灑絕纖埃，石逕縈紆闢草萊。", "窗外果從猿摘去，山中芝藉鶴銜回。", "一甌白雪湯輕注，三尺青蛇匣不開。", "如許清虛塵世隔，明朝再約抱琴來。"]'),
('87637ae8-ffe8-4a6b-95c9-34111e9694b2','謝許侯特顧','楊公遠','宋','宋诗','song-poetry','','[]','傳呼門外駭還驚，忙著荷衣倒屣迎。',64,'全唐诗/poet.song.234000.json','["傳呼門外駭還驚，忙著荷衣倒屣迎。", "皂蓋朱幡人從簡，雕鞍繡勒馬蹄輕。", "羣中駑頓增高價，爨下桐方有烈聲。", "多謝使君青顧後，免教汩沒度浮生。"]'),
('398bae69-fec7-4f9b-a60e-7d70591e68ae','冬夜次南仲韻','楊公遠','宋','宋诗','song-poetry','','[]','風號緊緊閉柴門，榾柮爐邊了不聞。',32,'全唐诗/poet.song.234000.json','["風號緊緊閉柴門，榾柮爐邊了不聞。", "窗外月明誰是主，輸渠梅竹自平分。"]'),
('38072df0-9c74-4467-b7d7-dc51747c5865','壽許侯','楊公遠','宋','宋诗','song-poetry','','[]','冬孟猶餘一葉蓂，中原賢哲此時生。',64,'全唐诗/poet.song.234000.json','["冬孟猶餘一葉蓂，中原賢哲此時生。", "星輝南極躔吳分，月出東山照歙城。", "耐與寒花香晚節，清如冷蕊味和羹。", "童顔鶴髮神仙骨，便是崆峒老廣成。"]'),
('8e8f2a22-947c-4a7c-bbb4-8e77093142db','次南仲韻','楊公遠','宋','宋诗','song-poetry','','[]','回首明年六十春，依然不改古衣巾。',64,'全唐诗/poet.song.234000.json','["回首明年六十春，依然不改古衣巾。", "畫圖蕭灑詩千首，心地通明月一輪。", "鐘鼎虛名雖是貴，簞瓢陋巷且安貧。", "客來問我平生事，寵辱俱無老逸民。"]'),
('d8e99d80-d129-41cf-a03d-88b02ff15d5c','謁秋崖先生方吏部墓借斗山韻','楊公遠','宋','宋诗','song-poetry','','[]','崖翁底事姓名香，照世文章日月光。',64,'全唐诗/poet.song.234000.json','["崖翁底事姓名香，照世文章日月光。", "葭塢留荷啼曉露，繭窩埋玉黯斜陽。", "碑刊地記生前撰，甃蝕苔痕去後荒。", "一炷爐薰瞻敬罷，教人空結九回腸。"]'),
('c5737f9e-cf0b-496c-abad-7ab4362e070c','次韻塞下曲','楊公遠','宋','宋诗','song-poetry','','[]','貂裘氈帽紫驊騮，挾彈彎弧架鐵矛。',32,'全唐诗/poet.song.234000.json','["貂裘氈帽紫驊騮，挾彈彎弧架鐵矛。", "飛放歸來天欲暮，數聲羌笛起高樓。"]'),
('ddbafabd-fb72-4aea-bd2a-6a1eedb69c5f','觀中桃花次友人韻','楊公遠','宋','宋诗','song-poetry','','[]','琳宮深處小桃紅，當日玄都事已空。',32,'全唐诗/poet.song.234000.json','["琳宮深處小桃紅，當日玄都事已空。", "今見花開渾似舊，不知又隔幾春風。"]'),
('32dacda9-c4b0-497e-9f4c-216831774690','拙稿呈許侯','楊公遠','宋','宋诗','song-poetry','','[]','拙稿携將謁使君，區區那敢冀知聞。',64,'全唐诗/poet.song.234000.json','["拙稿携將謁使君，區區那敢冀知聞。", "編成初卷如終卷，賦就三分誦七分。", "妄意僭干修月斧，刪蕪端藉運風斤。", "一經題品便佳士，庶別叢間蕕與薰。"]'),
('8eec7727-7510-4a56-b346-728a0d28c8ed','贄林路教','楊公遠','宋','宋诗','song-poetry','','[]','千載孤山處士星，只將閒逸了平生。',64,'全唐诗/poet.song.234000.json','["千載孤山處士星，只將閒逸了平生。", "一聯好句香猶在，幾世聞孫聲最清。", "泮水工夫施教雨，梅花標格待和羹。", "不知野叟何緣分，邂逅城闉幸識荆。"]'),
('d504e78f-4ab1-4ba3-842e-c224d40ab5a8','許侯贈詩借韻謝  其一','楊公遠','宋','宋诗','song-poetry','','[]','揮灑雲烟筆有神，衮褒字字燭吾真。',32,'全唐诗/poet.song.234000.json','["揮灑雲烟筆有神，衮褒字字燭吾真。", "從今詩畫多增重，寒谷頓回天地春。"]'),
('a1cb9bd7-4a5f-44e6-b507-20bee2aca260','許侯贈詩借韻謝  其二','楊公遠','宋','宋诗','song-poetry','','[]','政徹宸旒久有聲，何消入夢更圖形。',32,'全唐诗/poet.song.234000.json','["政徹宸旒久有聲，何消入夢更圖形。", "行看大展經綸手，整頓乾坤萬國寧。"]'),
('6fccb3ad-a6e1-438a-84b3-789fff12089b','初度','楊公遠','宋','宋诗','song-poetry','','[]','行止由來不自如，八年初度寓僧廬。',64,'全唐诗/poet.song.234000.json','["行止由來不自如，八年初度寓僧廬。", "半生閒逸雲無定，兩鬢蕭騷雪尚疎。", "豈願身榮如衛鶴，祇慙技拙類黔馿。", "今朝六十從頭起，數到稀年更有餘。"]'),
('72b31285-07c0-4e70-9bff-82b2069ab0a3','借吳直軒韻別黄仲宣','楊公遠','宋','宋诗','song-poetry','','[]','世路間關迥不同，生涯淡薄硯池中。',64,'全唐诗/poet.song.234000.json','["世路間關迥不同，生涯淡薄硯池中。", "買蓑去伴玄真子，著句來違黄石公。", "雖慰曉猿兼夜鶴，却嗟社燕與秋鴻。", "從今雪月交光夜，乘興當思泛短篷。"]'),
('a0642a6a-e082-4e13-ab14-db1ad482e4db','次吳友梅假山韻','楊公遠','宋','宋诗','song-poetry','','[]','石骨嵌巖聳怪形，主人對此快詩情。',32,'全唐诗/poet.song.234000.json','["石骨嵌巖聳怪形，主人對此快詩情。", "若教老筆來模倣，盤礴終朝畫不成。"]'),
('f5a3029f-4ed6-427b-a547-70a8bb9c6985','花朝','楊公遠','宋','宋诗','song-poetry','','[]','花朝恰了一分春，雨雪陰霾占兩旬。',64,'全唐诗/poet.song.234000.json','["花朝恰了一分春，雨雪陰霾占兩旬。", "物態未妍寒瑟縮，人生易老事因循。", "洗瓷杯酌浮蛆酒，擁地爐燒带葉薪。", "翻憶昔年成感慨，長官出郭劭耕民。"]'),
('5956d30c-97c2-4d68-a44a-8ede0bb1ca3f','上疏齋盧按察','楊公遠','宋','宋诗','song-poetry','','[]','歙境爭先覩使星，玉川風致是前生。',64,'全唐诗/poet.song.234000.json','["歙境爭先覩使星，玉川風致是前生。", "壯懷學富五千卷，明月光分十一城。", "吏立寒冰驚號令，民沾和氣樂耘耕。", "政聲久徹宸旒聽，行看金甌覆姓名。"]'),
('7d303c02-a1f6-4cec-a35a-abce5a9940d0','又','楊公遠','宋','宋诗','song-poetry','','[]','自憐雙鬢已星星，書劍無成老此生。',64,'全唐诗/poet.song.234000.json','["自憐雙鬢已星星，書劍無成老此生。", "願識荆州輕萬戶，要令和璧重連城。", "敲推風月詩隨興，模寫江山筆代耕。", "聞道珠璣囊拍塞，願分顆粒振聲名。"]'),
('a820e4cf-2b76-4ec1-9e42-d9e2a5532e11','詩謁按察疏齋賜賤號二大字賦詩以謝','楊公遠','宋','宋诗','song-poetry','','[]','幸披雲霧覩青天，盡道山人有宿緣。',64,'全唐诗/poet.song.234000.json','["幸披雲霧覩青天，盡道山人有宿緣。", "得坐春風纔半日，勝居塵世已千年。", "槎枯許到銀河畔，葭老容依玉樹邊。", "兩字光芒關不住，私心猶敢覓新篇。"]'),
('48ef1e55-fa85-4e89-8106-c4aed629ad2d','病起  其一','楊公遠','宋','宋诗','song-poetry','','[]','一病已兼旬，朝來試整襟。',48,'全唐诗/poet.song.234000.json','["一病已兼旬，朝來試整襟。", "眼前驚霧散，耳底怪蟬吟。", "檢點塵侵硯，爬搔雪滿簪。", "春歸渾未省，綠樹又成陰。"]'),
('ca724b6b-076c-40fe-ae2e-aa59423a24b8','病起  其二','楊公遠','宋','宋诗','song-poetry','','[]','彈指歎吟身，慳慳滿六旬。',48,'全唐诗/poet.song.234000.json','["彈指歎吟身，慳慳滿六旬。", "維摩寧久病，孺子豈長貧。", "雖欠詩邊興，還存筆底春。", "莫言憔悴損，梅瘦越精神。"]'),
('2c58e245-d605-4a25-a143-81a3b124185b','病起  其三','楊公遠','宋','宋诗','song-poetry','','[]','病起覺癡聾，徐行脚躡空。',48,'全唐诗/poet.song.234000.json','["病起覺癡聾，徐行脚躡空。", "杖能供半力，藥已奏全功。", "整頓身仍健，優游道未窮。", "呼兒滌泓穎，拂素貌漁翁。"]'),
('8b2eb120-6bd8-4f7d-8730-12c966e9e379','清明','楊公遠','宋','宋诗','song-poetry','','[]','清明又向客中過，憶著家山事若何。',64,'全唐诗/poet.song.234000.json','["清明又向客中過，憶著家山事若何。", "未及掃松徒悵恨，偶因得句漫吟哦。", "六旬身世憂懷少，九十春光陰雨多。", "對景豈宜虛負却，把杯須拚醉顔酡。"]'),
('58d9c6f6-0e4b-4cc9-9052-b1ec6fe9cb5c','游水西次吳秋磵韻','楊公遠','宋','宋诗','song-poetry','','[]','松陰石逕絕纖埃，緩步行春得得來。',64,'全唐诗/poet.song.234000.json','["松陰石逕絕纖埃，緩步行春得得來。", "風景一川詩料足，樓臺兩岸畫圖開。", "山花亂插髼鬆鬢，村酒頻傾瀲灧杯。", "扶醉歸來天欲莫，數聲鼓角又相催。"]'),
('f00baf7e-61a5-442d-bcd4-a22c0fdd7582','餞盧按察','楊公遠','宋','宋诗','song-poetry','','[]','軺車至日歲將更，又趁薰風理去程。',64,'全唐诗/poet.song.234000.json','["軺車至日歲將更，又趁薰風理去程。", "歷遍山城留好句，蘇回民瘼快輿情。", "人言但有官如此，世道應無事不平。", "祇恐江東難久駐，看看詔趣秉鈞衡。"]'),
('869a4064-2445-446e-bcf8-253385599bd2','借虛翁湧金門城望五詩韻以寫幽居之興  其一','楊公遠','宋','宋诗','song-poetry','','[]','數竿脩竹半池荷，密掩柴門少客過。',64,'全唐诗/poet.song.234000.json','["數竿脩竹半池荷，密掩柴門少客過。", "筆底畫能希李郭，囊中詩欠似陰何。", "一心夜月炯長在，兩鬢秋霜積未多。", "花甲明年重數起，幸逢塵世息兵戈。"]'),
('c0797afc-b43d-4212-be6c-a02f9ca5aa7e','借虛翁湧金門城望五詩韻以寫幽居之興  其二','楊公遠','宋','宋诗','song-poetry','','[]','半生跡未歷江湖，闢地東郊旋剪蕪。',64,'全唐诗/poet.song.234000.json','["半生跡未歷江湖，闢地東郊旋剪蕪。", "結屋池邊塵自少，蒔梅窗外俗全無。", "偶來啜茗謝良友，不肯趨時愧腐儒。", "却笑一寒難措手，欲裨短褐拆天吳。"]'),
('37744e87-24a1-40f6-8136-d79c6009347f','借虛翁湧金門城望五詩韻以寫幽居之興  其三','楊公遠','宋','宋诗','song-poetry','','[]','時光迅速走雙輪，忽憶前朝事已陳。',64,'全唐诗/poet.song.234000.json','["時光迅速走雙輪，忽憶前朝事已陳。", "門外難交騎馬客，竹邊惟結話詩人。", "生來豈羨陶朱富，老去寧甘原憲貧。", "處世自憐渾不解，江山聊助筆頭春。"]'),
('c205b26c-f296-47ac-a14c-c3a61386bbd3','借虛翁湧金門城望五詩韻以寫幽居之興  其四','楊公遠','宋','宋诗','song-poetry','','[]','細撚吟髭謾賦詩，騷人那敢與爭馳。',64,'全唐诗/poet.song.234000.json','["細撚吟髭謾賦詩，騷人那敢與爭馳。", "傾杯對月風清夜，倚杖觀山雲斂時。", "世事安危渾莫問，人生得失底須悲。", "何當琢就梅花句，付與高樓畫角吹。"]'),
('89a953e8-a9db-4091-a883-68a9d98cb865','借虛翁湧金門城望五詩韻以寫幽居之興  其五','楊公遠','宋','宋诗','song-poetry','','[]','堂標野趣豈虛傳，坐看朝嵐與夕烟。',64,'全唐诗/poet.song.234000.json','["堂標野趣豈虛傳，坐看朝嵐與夕烟。", "支逕縈迂斜傍竹，幽池清淺倒涵天。", "少年心付沾泥絮，晚景身猶順水船。", "却喜傳家惟老硯，麝煤磨盡可曾穿。"]'),
('25b2302e-8345-4716-82b3-cdbfbbfc2b1a','避暑次葉教授韻','楊公遠','宋','宋诗','song-poetry','','[]','炎天無處滌煩心，拂拭蒼苔坐茂林。',32,'全唐诗/poet.song.234000.json','["炎天無處滌煩心，拂拭蒼苔坐茂林。", "貪撚吟髭搜好句，不知日轉已移陰。"]'),
('09fadc9f-7918-409b-90bd-65104065d383','感懷  其一','楊公遠','宋','宋诗','song-poetry','','[]','桂薪玉米轉煎熬，口體區區不勝勞。',64,'全唐诗/poet.song.234000.json','["桂薪玉米轉煎熬，口體區區不勝勞。", "今日難謀明日計，老年徒羨少年豪。", "皮膚剝落詩方熟，鬢髮滄浪畫愈高。", "自顧一寒成感慨，有誰能肯解綈袍。"]'),
('1ac1a186-bee0-426d-93f1-d5051ef8da0d','感懷  其二','楊公遠','宋','宋诗','song-poetry','','[]','長吟抱膝更欷歔，較著前時迥不如。',64,'全唐诗/poet.song.234000.json','["長吟抱膝更欷歔，較著前時迥不如。", "世事看來巢幕燕，人生勘破上竿魚。", "投非所好緣工瑟，見匪相知嬾曳裾。", "造物豈應私困我，還須水到自成渠。"]'),
('83c891f4-4f91-43f1-b416-f50f8094a673','次金東園農家雜詠  其一','楊公遠','宋','宋诗','song-poetry','','[]','買酒割雞祠社後，踏歌搥鼓閙清明。',32,'全唐诗/poet.song.234000.json','["買酒割雞祠社後，踏歌搥鼓閙清明。", "柔桑葉長蠶苗出，從此關門禁客行。"]'),
('b4bd32fe-20f6-4142-99f1-4fb2b0746e02','次金東園農家雜詠  其二','楊公遠','宋','宋诗','song-poetry','','[]','林下欹傾茅草屋，門前詰曲竹笆籬。',32,'全唐诗/poet.song.234000.json','["林下欹傾茅草屋，門前詰曲竹笆籬。", "數聲清笛知何處，牛背斜陽牧豎吹。"]'),
('bc937e90-7fa8-4661-a352-e902f77579de','次金東園農家雜詠  其三','楊公遠','宋','宋诗','song-poetry','','[]','遲日麗時秧刺水，午風暄處麥掀髯。',32,'全唐诗/poet.song.234000.json','["遲日麗時秧刺水，午風暄處麥掀髯。", "一村桃杏紅如錦，旋數青銅傍酒帘。"]'),
('8997bb1b-76b0-4210-87da-f5e09767fc28','次金東園農家雜詠  其四','楊公遠','宋','宋诗','song-poetry','','[]','趁雨足時翻畎畝，插秧遍後便耔耘。',32,'全唐诗/poet.song.234000.json','["趁雨足時翻畎畝，插秧遍後便耔耘。", "願天頻把甘霖霔，佇看豐年萬頃雲。"]'),
('8eace3de-cec7-4fcf-888c-30179c57d221','次金東園農家雜詠  其五','楊公遠','宋','宋诗','song-poetry','','[]','嘗稻翻匙誇白雪，腰鎌荷擔刈黄雲。',32,'全唐诗/poet.song.234000.json','["嘗稻翻匙誇白雪，腰鎌荷擔刈黄雲。", "逢人謾說空辛苦，償債輸官費九分。"]'),
('0fc997bd-9d2b-42a6-b83c-6a8fbe397fcf','次金東園農家雜詠  其六','楊公遠','宋','宋诗','song-poetry','','[]','四郊䆉稏高低熟，幾處連耞澎湃聲。',32,'全唐诗/poet.song.234000.json','["四郊䆉稏高低熟，幾處連耞澎湃聲。", "婦餉區區無寸暇，績麻猶趁月華明。"]'),
('baa8d10a-1ad2-4735-b218-07c7bff0378a','次金東園農家雜詠  其七','楊公遠','宋','宋诗','song-poetry','','[]','戰伐已聞初卸甲，耘耔却喜近添丁。',32,'全唐诗/poet.song.234000.json','["戰伐已聞初卸甲，耘耔却喜近添丁。", "明年小稔應堪望，雪後平疇宿麥青。"]'),
('89c38dbe-a5bb-451e-9e45-623a0226be14','次金東園農家雜詠  其八','楊公遠','宋','宋诗','song-poetry','','[]','婦作生涯勤杼軸，夫營活計在桑田。',32,'全唐诗/poet.song.234000.json','["婦作生涯勤杼軸，夫營活計在桑田。", "老翁榾柮爐邊坐，幼稚簷前負日暄。"]'),
('0e831c5f-bda8-4bdb-bad7-a723ffaf2305','次金東園漁家雜詠  其一','楊公遠','宋','宋诗','song-poetry','','[]','繫纜旋編新箬笠，喜晴仍曬舊蓑衣。',32,'全唐诗/poet.song.234000.json','["繫纜旋編新箬笠，喜晴仍曬舊蓑衣。", "岸飛柳絮河魨上，春漲幾添一尺肥。"]'),
('db7b768c-d159-40e6-8f9f-33c920907905','次金東園漁家雜詠  其二','楊公遠','宋','宋诗','song-poetry','','[]','篙撐舴艋閒來往，手把絲綸自卷舒。',32,'全唐诗/poet.song.234000.json','["篙撐舴艋閒來往，手把絲綸自卷舒。", "妻子已諳風露慣，篷窗便可當茅廬。"]'),
('16c74fd7-8f0e-47a4-aaf7-19a1f362a23b','次金東園漁家雜詠  其三','楊公遠','宋','宋诗','song-poetry','','[]','醉來要把鵬爲餌，夜後長將月作鈎。',32,'全唐诗/poet.song.234000.json','["醉來要把鵬爲餌，夜後長將月作鈎。", "浮利浮名渾不問，數聲欵乃轉船頭。"]'),
('5d372625-da54-4406-aa76-a57d3bb07981','次金東園漁家雜詠  其四','楊公遠','宋','宋诗','song-poetry','','[]','經行葦荻沙頭熟，出沒風濤膽氣麤。',32,'全唐诗/poet.song.234000.json','["經行葦荻沙頭熟，出沒風濤膽氣麤。", "博得酒歸明月夜，呼兒作膾旋批鱸。"]'),
('b5213189-49f2-4ae4-ab92-a648871e5153','次金東園漁家雜詠  其五','楊公遠','宋','宋诗','song-poetry','','[]','愛玄真子吟佳句，笑老姜公用直鈎。',32,'全唐诗/poet.song.234000.json','["愛玄真子吟佳句，笑老姜公用直鈎。", "一片水鄉供活計，四時風月在扁舟。"]'),
('bcee1607-7d13-499f-bf22-01b457a034fa','次金東園漁家雜詠  其六','楊公遠','宋','宋诗','song-poetry','','[]','兩岸蘆花飛雪絮，一江秋水接銀河。',32,'全唐诗/poet.song.234000.json','["兩岸蘆花飛雪絮，一江秋水接銀河。", "平生不結榮華夢，只把青蓑當綺羅。"]'),
('6097e023-d74f-467f-8c50-b67e9934d8cf','次金東園漁家雜詠  其七','楊公遠','宋','宋诗','song-poetry','','[]','那有清霜來鬢上，略無閒事上眉頭。',32,'全唐诗/poet.song.234000.json','["那有清霜來鬢上，略無閒事上眉頭。", "傍人借問家何處，一葉輕舟水面浮。"]'),
('6d8247ba-ca7a-45c9-8d21-fc5262bb2d12','次金東園漁家雜詠  其八','楊公遠','宋','宋诗','song-poetry','','[]','風緊岸邊安釣艇，雲濃空裏散楊花。',32,'全唐诗/poet.song.234000.json','["風緊岸邊安釣艇，雲濃空裏散楊花。", "披蓑頂笠携魚去，遥指前村問酒家。"]'),
('e45c59ac-bde1-4689-884d-e0043156b328','書懷','楊公遠','宋','宋诗','song-poetry','','[]','檢點頭顱髮半絲，老來剗地費支持。',64,'全唐诗/poet.song.234000.json','["檢點頭顱髮半絲，老來剗地費支持。", "技緣冷淡知音寡，事每差池賦命奇。", "一暴十寒良可歎，三平二滿且隨宜。", "杜門嬾出過從少，自錄唐詩旋課兒。"]'),
('5fb9dd20-bcbf-4c20-95ca-0acc7a457a44','荷花','楊公遠','宋','宋诗','song-poetry','','[]','竹邊窗外小池塘，青蓋亭亭擁靚妝。',64,'全唐诗/poet.song.234000.json','["竹邊窗外小池塘，青蓋亭亭擁靚妝。", "莫把仙娥相比擬，合將君子爲平章。", "凋時堪供真人艇，老去猶充楚客裳。", "幾夜月明風露下，輸儂受用許清香。"]'),
('b1a0cb4f-1801-44e2-90f7-829a9a7577ba','白蓮','楊公遠','宋','宋诗','song-poetry','','[]','橫塘清淺藕花開，綽約冰姿絕點埃。',64,'全唐诗/poet.song.234000.json','["橫塘清淺藕花開，綽約冰姿絕點埃。", "雨過渾疑湯餠試，風生却訝玉山頹。", "未經太液承恩去，先向東林結社來。", "銓次羣芳須第一，妖紅麗紫盡輿臺。"]'),
('4cdaeb55-a185-4c51-afae-5b71c999734b','餞趙可齋朝京','楊公遠','宋','宋诗','song-poetry','','[]','秋高秣馬理征鞍，琴鶴相隨上帝關。',64,'全唐诗/poet.song.234000.json','["秋高秣馬理征鞍，琴鶴相隨上帝關。", "已有聲名聞草木，又將詩句動夷蠻。", "金鑾未賜金蓮炬，玉陛將催玉笋班。", "管取來年三二月，定看晝著錦衣還。"]'),
('056f3ce4-5b0b-475c-aa87-eac9f4943845','寄東麓趙贊府  其一','楊公遠','宋','宋诗','song-poetry','','[]','佐邑{氵貲}陽綽有聲，文章政事冠羣英。',67,'全唐诗/poet.song.234000.json','["佐邑{氵貲}陽綽有聲，文章政事冠羣英。", "南牆松想乘閒詠，北海樽聞已戒傾。", "橫笛倚樓襟度逸，携琴带鶴宦情輕。", "結知當路交飛剡，行看除書下玉京。"]'),
('d718d7df-6f8f-42d7-8afa-7acb4bee319d','寄東麓趙贊府  其二','楊公遠','宋','宋诗','song-poetry','','[]','黄花開後驟征鞍，再見黄花秋又殘。',64,'全唐诗/poet.song.234000.json','["黄花開後驟征鞍，再見黄花秋又殘。", "隻字未能通間闊，長箋先辱問平安。", "共看明月隔千里，獨對西風愧一寒。", "祇有麓翁知我者，何時會面話辛酸。"]'),
('72f33c64-c07c-47e0-aa87-21ec587612ba','壽許侯','楊公遠','宋','宋诗','song-poetry','','[]','星輝南極彩雲邊，律轉黄鍾一日前。',64,'全唐诗/poet.song.234000.json','["星輝南極彩雲邊，律轉黄鍾一日前。", "河嶽間生賢太守，椿松齊算老神仙。", "心猶秋月燭千里，人在春風度兩年。", "祇恐練溪難久駐，行看飛詔下堯天。"]'),
('8022f56f-22d2-4824-acf4-10bd2c6c0494','連日雪次黄仲宣韻  其一','楊公遠','宋','宋诗','song-poetry','','[]','天遣馮夷剪水飛，拏空萬木凍龍癡。',64,'全唐诗/poet.song.234000.json','["天遣馮夷剪水飛，拏空萬木凍龍癡。", "寒思坡老玉樓句，清想劉叉冰柱詩。", "謾擁地爐然竹火，更垂紙帳當羅帷。", "誰知預作豐年瑞，不療貧家眼下饑。"]'),
('d415c2c1-2cd9-47e0-b236-25b1200c8383','連日雪次黄仲宣韻  其二','楊公遠','宋','宋诗','song-poetry','','[]','連朝飛雪滿山城，恰負人言雪易晴。',64,'全唐诗/poet.song.234000.json','["連朝飛雪滿山城，恰負人言雪易晴。", "梅頓添肥香不減，竹雖暫屈節還清。", "閉門僵卧嗟寒士，煮水烹茶任巨卿。", "但喜遺蝗深入地，休誇李愬把吳平。"]'),
('e38bdf40-14ec-48d8-9ffa-a3a3b9aa3079','始生書懷  其一','楊公遠','宋','宋诗','song-poetry','','[]','連年客裏度生朝，自草新詩慰寂寥。',32,'全唐诗/poet.song.234000.json','["連年客裏度生朝，自草新詩慰寂寥。", "却喜窗前風景好，梅花初放雪初消。"]'),
('d37b52c2-307e-4488-b441-dcf21f432b4c','始生書懷  其二','楊公遠','宋','宋诗','song-poetry','','[]','浮生六十度春秋，無辱無榮儘自由。',32,'全唐诗/poet.song.234000.json','["浮生六十度春秋，無辱無榮儘自由。", "但得此身强健在，明年花甲又從頭。"]'),
('186792b8-51b4-4112-ba7c-6c0526b65c8a','始生書懷  其三','楊公遠','宋','宋诗','song-poetry','','[]','一片閒雲出岫遲，詩情畫思老來宜。',32,'全唐诗/poet.song.234000.json','["一片閒雲出岫遲，詩情畫思老來宜。", "莫言末技渾無用，傳入雞林未可知。"]'),
('1b83bdf5-7058-4ae8-b33e-f292634078bc','次程南仲韻  其一','楊公遠','宋','宋诗','song-poetry','','[]','老來鶴髮更雞皮，計解曾無六出奇。',64,'全唐诗/poet.song.234000.json','["老來鶴髮更雞皮，計解曾無六出奇。", "耕釣雲烟三寸管，剪裁風月幾聯詩。", "逢人多謝開青眼，顧我惟慙匪白眉。", "世路近來雖著脚，不如退步學聾癡。"]'),
('54ba2afc-5c5e-49b1-afbe-25a65f1fbf9d','次程南仲韻  其二','楊公遠','宋','宋诗','song-poetry','','[]','生意窗前草不除，翛翛蒼玉自扶疎。',64,'全唐诗/poet.song.234000.json','["生意窗前草不除，翛翛蒼玉自扶疎。", "貧將入骨誰憐我，富欲掀天命屬渠。", "學圃頻觀種樹傳，杜門幾似絕交書。", "有時間有過從者，分席非樵即是漁。"]'),
('93c1f3d8-aef0-4851-bfba-78292e1282e9','次程南仲韻  其三','楊公遠','宋','宋诗','song-poetry','','[]','興來呼酒乏瓷巵，自笑醄醄作麽爲。',64,'全唐诗/poet.song.234000.json','["興來呼酒乏瓷巵，自笑醄醄作麽爲。", "細誦坡仙前後賦，更歌元亮去來辭。", "一心湛徹長如水，兩鬢髼鬆半欲絲。", "畢竟不消惆悵得，蒼松獨傲歲寒時。"]'),
('d52108be-a4c9-4a89-b193-99fa6bb8d833','次程南仲韻  其四','楊公遠','宋','宋诗','song-poetry','','[]','倒指頭顱六十餘，尤堪抱甕灌園蔬。',64,'全唐诗/poet.song.234000.json','["倒指頭顱六十餘，尤堪抱甕灌園蔬。", "生來自得江山趣，身後何消竹帛書。", "無事關懷心寂寂，有時敲句意徐徐。", "乘閒問柳尋花去，緩步安然當小車。"]'),
('94ab0ee3-8f1f-45e2-8640-807925b6e483','次程南仲韻  其五','楊公遠','宋','宋诗','song-poetry','','[]','賸喜壺中別是天，誅茆結屋竹梅邊。',64,'全唐诗/poet.song.234000.json','["賸喜壺中別是天，誅茆結屋竹梅邊。", "伴人有意一泓硯，笑我無緣二頃田。", "半醉半醒知酒聖，非空非色悟僧禪。", "門前青嶂渾如畫，雲去雲來樹倚巔。"]'),
('b1b69bdd-318a-4ebd-8162-e2e511c2dea2','烟雨樓','唐天麟','宋','宋诗','song-poetry','','[]','百尺樓高足賞心，我來猶記舊登臨。',64,'全唐诗/poet.song.234000.json','["百尺樓高足賞心，我來猶記舊登臨。", "四時天色有晴雨，一片湖光無古今。", "遠塔連雲知寺隠，小舟穿柳覺村深。", "凭闌多少斜陽景，分付漁歌替晚吟。"]'),
('57ee92f8-b159-4e04-8a60-9d6f5791a8ac','淳祐七年丁未十一月朔蔡久軒自江東提刑歸抵家時三館諸公以風霜隨氣節河漢下文章分韻賦詩送別得章字','楊世奕','宋','宋诗','song-poetry','','[]','富貴寧如節義香，也教青史播餘芳。',64,'全唐诗/poet.song.234000.json','["富貴寧如節義香，也教青史播餘芳。", "四年諫省歸何暮，七十新參老欲彊。", "孺子早聞辭爵位，君謨今又去班行。", "軺車玉節江東路，清夢時應繞建章。"]'),
('f898951d-3a43-476e-9e2d-9477bb937dbd','浯溪','莊崇節','宋','宋诗','song-poetry','','[]','元翁作頌魯公書，峭壁雲煙萬古垂。',64,'全唐诗/poet.song.234000.json','["元翁作頌魯公書，峭壁雲煙萬古垂。", "三絕堂前月浸碧，兩峰亭下草生悲。", "英風義概有存者，流水高山誰會之。", "便使中原歸趙璧，磨崖再勒中興碑。"]'),
('f6973643-e066-47cc-9f4d-c0c0a4147861','浯溪','丁叔巖','宋','宋诗','song-poetry','','[]','相去祁陽五里餘，撼山爲谷斷爲谿。',64,'全唐诗/poet.song.234000.json','["相去祁陽五里餘，撼山爲谷斷爲谿。", "河南刺史老文學，石上真□健筆題。", "風月滿堂無地着，雲烟半壁與天齊。", "英雄說着唐朝事，淚濺長安蜀道西。"]'),
('eef1003b-1be4-4954-ba0d-9fea88caffad','遊浯溪','王壺','宋','宋诗','song-poetry','','[]','□□□□□□□，□值淒涼八百秋。',64,'全唐诗/poet.song.234000.json','["□□□□□□□，□值淒涼八百秋。", "入院伽藍先稽首，題詩神鬼暗添愁。", "幾章鎸石珠璣燦，一带臨江泉石幽。", "讀罷中興碑去後，逢人便舉伴茶甌。"]'),
('83988bf6-9890-44fa-b685-a0a8f59f85ec','奉寄文丞相','蔡郁','宋','宋诗','song-poetry','','[]','嗟哉此綱常，一朝已散失。',168,'全唐诗/poet.song.234000.json','["嗟哉此綱常，一朝已散失。", "臣豈無賢良，君豈有慚德。", "君臣義未明，大道致閉塞。", "誰實篤忠貞，矢志不可屈。", "先生真英豪，提戈呼叱咤。", "一心收桑榆，戎行瞻黼黻。", "間關五嶺南，誓師存百粵。", "有仍田一成，足以張征伐。", "南陽戴真人，足以興漢室。", "天道豈無知，爲此冠裳惻。", "昨聞戰城南，王師奮鈇鉞。", "萬馬似群羊，鬭敗鼓聲竭。", "百年養士恩，報之在朝夕。", "多慚遲暮身，涕淚望鄉國。"]'),
('3438d913-c5a3-41b8-95c0-69ea9b2b893b','題趙子昂竹','衛富益','宋','宋诗','song-poetry','','[]','漢宮日暮風雷遠，南國秋深水殿寒。',32,'全唐诗/poet.song.234000.json','["漢宮日暮風雷遠，南國秋深水殿寒。", "留得一枝烟雨裏，又隨人去報平安。"]'),
('f480ef7a-1c8b-44e7-b150-073152448e59','遊黄山寺','葛起文','宋','宋诗','song-poetry','','[]','偶爲尋幽出，扶筇亦懶拈。',48,'全唐诗/poet.song.234000.json','["偶爲尋幽出，扶筇亦懶拈。", "鸛巢依古塔，燕語入虛欄。", "筆下詩初就，樽中酒屢添。", "此遊堪喜處，膝上一掀髯。"]'),
('975294d6-06c0-4b4b-b9b1-3a19b5b9666f','詠竹閣','葛起文','宋','宋诗','song-poetry','','[]','歲寒編竹閣，蝸縮度窮年。',48,'全唐诗/poet.song.234000.json','["歲寒編竹閣，蝸縮度窮年。", "日暴南窗紙，風垂北戶簾。", "鑪深全火氣，鐺小聚茶煙。", "爲索梅花笑，微醺步矮簷。"]'),
('686fd64f-ec07-4bcd-8793-295cfd832419','窖嶺道中','葛起文','宋','宋诗','song-poetry','','[]','屨穿蒼蘚滑，水複更山重。',48,'全唐诗/poet.song.234000.json','["屨穿蒼蘚滑，水複更山重。", "有圃春偏晚，無人碓自舂。", "亂雲生峭壁，一鳥沒高峰。", "隨處桃花發，仙源似可逢。"]'),
