('9a5a385f-48d0-417f-8318-1a08b457b5ab','東城','滕塛','宋','宋诗','song-poetry','','[]','東城有高樓，峩峩冠城闕。',60,'全唐诗/poet.song.234000.json','["東城有高樓，峩峩冠城闕。", "我來屬昏暮，見此初上月。", "遥天羅江山，極目如霽雪。", "江山秀如此，豈不生豪傑。", "臨風一高歌，達曙何由歇。"]'),
('bb9618fc-f7bf-41a4-9e0f-d1cf61229f4b','溪村','滕塛','宋','宋诗','song-poetry','','[]','獨步溪村午，時時一二家。',48,'全唐诗/poet.song.234000.json','["獨步溪村午，時時一二家。", "綠波浮錦鴨，翠草點黄花。", "釣石臨溪古，連山繞徑斜。", "幽人吟未極，西日散平沙。"]'),
('f2547d6f-7b03-4349-b990-c0960dafef48','拜岳將軍墓','滕塛','宋','宋诗','song-poetry','','[]','大墳老樹列其中，小塚旁堆樹亦同。',64,'全唐诗/poet.song.234000.json','["大墳老樹列其中，小塚旁堆樹亦同。", "不世孝忠惟父子，極天憤痛在英雄。", "上方有劍誰能請，中國輸金使不通。", "相對含悲石翁仲，老衰無淚落秋風。"]'),
('885069ff-3a04-4f76-b57d-b6bc77c98989','飲酒','趙必岊','宋','宋诗','song-poetry','','[]','窮居無與娛，弱子戲我右。',60,'全唐诗/poet.song.234000.json','["窮居無與娛，弱子戲我右。", "寧知千載前，不是桑榆友。", "今爲骨肉親，結愛豈不厚。", "不知後千載，當復如此否。", "且盡人間事，幽遠非所叩。"]'),
('71112373-5ad2-4a52-bfbd-064de1678057','題蔣詩翁故居','鄭會龍','宋','宋诗','song-poetry','','[]','詩翁仙去舊壇荒，雲滿空山花自香。',32,'全唐诗/poet.song.234000.json','["詩翁仙去舊壇荒，雲滿空山花自香。", "老盡遊人春不問，杜鵑聲裏幾斜陽。"]'),
('2bed4545-f261-4e91-976c-0a83afe2a4c6','宮詞十首  其一','張樞','宋','宋诗','song-poetry','','[]','堯殿融春大宴開，山呼纔了樂聲催。',32,'全唐诗/poet.song.234000.json','["堯殿融春大宴開，山呼纔了樂聲催。", "侍臣宣勸君恩重，宰相親王對舉杯。"]'),
('678e4b7d-d1c1-4a8f-94aa-b25ba82d0b80','宮詞十首  其二','張樞','宋','宋诗','song-poetry','','[]','觀堂鐘響待催班，步入朱廊十二間。',32,'全唐诗/poet.song.234000.json','["觀堂鐘響待催班，步入朱廊十二間。", "宣坐賜茶開講席，花磚咫尺對天顔。"]'),
('917470ef-241a-4f8f-8caf-5d56426b9817','宮詞十首  其三','張樞','宋','宋诗','song-poetry','','[]','月籠梅影夜深時，白玉排簫索獨吹。',32,'全唐诗/poet.song.234000.json','["月籠梅影夜深時，白玉排簫索獨吹。", "傳得官家暗宣賜，黄金約臂翠花枝。"]'),
('fd118177-5d77-41af-95b5-dd017cfc71f9','宮詞十首  其四','張樞','宋','宋诗','song-poetry','','[]','翠枝斜插滴金花，特髻低蟠貼水荷。',32,'全唐诗/poet.song.234000.json','["翠枝斜插滴金花，特髻低蟠貼水荷。", "應奉人多宣喚少，海棠花下看飛梭。"]'),
('f4e02b77-6e80-4e85-a1b3-9f73cf9dad6d','宮詞十首  其五','張樞','宋','宋诗','song-poetry','','[]','笙歌散後歸深院，花柳陰中過曲廊。',32,'全唐诗/poet.song.234000.json','["笙歌散後歸深院，花柳陰中過曲廊。", "靜掩金鋪三十六，黄昏處處爇衙香。"]'),
('b7a01fdb-1d1d-4516-8e16-f827ebced065','宮詞十首  其六','張樞','宋','宋诗','song-poetry','','[]','燦錦堂西過夕陽，水風吹起芰荷香。',32,'全唐诗/poet.song.234000.json','["燦錦堂西過夕陽，水風吹起芰荷香。", "內監催掃池邊地，準備官家納晚凉。"]'),
('7d5837ca-7c75-44b3-ac66-9f41ddd32015','宮詞十首  其七','張樞','宋','宋诗','song-poetry','','[]','晚涼開院近中秋，香染金風倚桂樓。',32,'全唐诗/poet.song.234000.json','["晚涼開院近中秋，香染金風倚桂樓。", "花月新篇初唱徹，內人傳旨索歌頭。"]'),
('98783378-50ea-4463-98f1-03af7042c952','宮詞十首  其八','張樞','宋','宋诗','song-poetry','','[]','銀簧乍靘參差竹，玉軸新調尺合絃。',32,'全唐诗/poet.song.234000.json','["銀簧乍靘參差竹，玉軸新調尺合絃。", "奏罷六么花十八，水晶簾底賜金錢。"]'),
('f6db105f-54e4-47e5-a488-3f100af88dca','宮詞十首  其九','張樞','宋','宋诗','song-poetry','','[]','迴廊隔樹簾簾捲，曲水穿橋路路通。',32,'全唐诗/poet.song.234000.json','["迴廊隔樹簾簾捲，曲水穿橋路路通。", "禁漏滴斜花外日，御香薰暖柳邊風。"]'),
('2cf7b64b-6a62-4b15-971a-77544b5127a7','宮詞十首  其一○','張樞','宋','宋诗','song-poetry','','[]','紫閣深嚴邃殿西，書林飛白揭宸奎。',32,'全唐诗/poet.song.234000.json','["紫閣深嚴邃殿西，書林飛白揭宸奎。", "黄封繳進昇平奏，直筆夫人看內批。"]'),
('76bef4e8-b49a-4ee4-bf9b-f4fc867d1434','游大滌','張樞','宋','宋诗','song-poetry','','[]','一曲朱欄百尺餘，仙人自是愛樓居。',32,'全唐诗/poet.song.234000.json','["一曲朱欄百尺餘，仙人自是愛樓居。", "松風不動千山靜，月滿天壇人步虛。"]'),
('947b46d6-2126-4e7f-a329-5678dea3c7c3','茅山','張樞','宋','宋诗','song-poetry','','[]','今古茅山是勝遊，秀峰突兀繞滄洲。',64,'全唐诗/poet.song.234000.json','["今古茅山是勝遊，秀峰突兀繞滄洲。", "雲含老樹迷還散，石擁甘泉咽復留。", "未見巖風晨下鶴，祇聞澗月夜鳴蜩。", "道人不是悲秋客，黄菊丹楓相對愁。"]'),
('3535ba7d-3660-4d6d-861a-1bcc43efaa73','登書樓有感和秋思韻','錢默','宋','宋诗','song-poetry','','[]','坐擁遺衾百尺樓，湘簾高捲不勝秋。',32,'全唐诗/poet.song.234000.json','["坐擁遺衾百尺樓，湘簾高捲不勝秋。", "半窗凉月三更夢，一枕凄風萬斛愁。"]'),
('159c0391-f41f-4cd1-a71e-055351c00122','溪上','錢槱','宋','宋诗','song-poetry','','[]','秋老蘆花冉冉飛，曉天寒氣襲人衣。',32,'全唐诗/poet.song.234000.json','["秋老蘆花冉冉飛，曉天寒氣襲人衣。", "輕橈棹入鷗群去，釣得鱸魚带雨歸。"]'),
('4984c59f-cdd7-40fd-aa7b-b98be3b2ea4e','贈內','劉玉','宋','宋诗','song-poetry','','[]','春風休記舊繁華，舉案園林樂事賒。',64,'全唐诗/poet.song.234000.json','["春風休記舊繁華，舉案園林樂事賒。", "月引池光歸座榻，雲含花氣入窗紗。", "鹿門本是龐公宅，栗里誰尋舊令家。", "相對莫論終歲計，酒狂詩癖自生涯。"]'),
('431cf344-ab65-4dd5-8b15-cd087f6760e7','路入武陽','趙禕','宋','宋诗','song-poetry','','[]','路入武陽信馬行，野花香好不知名。',32,'全唐诗/poet.song.234000.json','["路入武陽信馬行，野花香好不知名。", "官卑無補公家事，時向田間問耦耕。"]'),
('ee37396d-c5d4-4813-96dd-093879767cba','春晚書懷','趙禕','宋','宋诗','song-poetry','','[]','三分春色二分休，是處紅稀綠已稠。',64,'全唐诗/poet.song.234000.json','["三分春色二分休，是處紅稀綠已稠。", "芳草池邊空有思，落花亭畔不勝愁。", "人情似昔猶難合，身世于今豈易謀。", "若欲忘憂須是酒，醉鄉安穩勝封侯。"]'),
('fe24f866-b5e4-44b8-b6b2-7eb2ea591f44','橫山聳翠','柳敘','宋','宋诗','song-poetry','','[]','蘭陰山跨瀔破峰顔三月三。',60,'全唐诗/poet.song.234000.json','["蘭陰山跨瀔破峰顔三月三。", "松柏森森翻野籟，竹梧隠隠撲晴嵐。", "高摩雲漢千尋路，倒浸峰巒百尺潭。", "此外未知誰洞府，試春遊騎必停驂。"]'),
('07359b6d-c1be-4e12-91c3-d374be6dfe42','殿院曾淵子宅酒酣放歌','廖應淮','宋','宋诗','song-poetry','','[]','禽聲兮啾啾，草色兮幽幽。',58,'全唐诗/poet.song.234000.json','["禽聲兮啾啾，草色兮幽幽。", "風𤍿𤍿兮火怒，泉殷殷兮血流。", "屋將焚兮燕呢喃以未已，鼎沸兮虱婆娑其不休。", "歸去來兮，不歸兮焉求。"]'),
('f206ea14-c965-4aac-9c3c-96213b279d65','上崔中丞古意二首  其一','何夢桂','宋','宋诗','song-poetry','','[]','明月墮我檐，白雲生我屋。',48,'全唐诗/poet.song.234000.json','["明月墮我檐，白雲生我屋。", "明發起振衣，出戶聊躑躅。", "青冥下輶軒，皇華照幽谷。", "乾坤散清氣，固不在惡木。"]'),
('9c2909eb-423d-47a1-8248-41a5fe3c8976','上崔中丞古意二首  其二','何夢桂','宋','宋诗','song-poetry','','[]','岩岩南山石，上有孤生竹。',48,'全唐诗/poet.song.234000.json','["岩岩南山石，上有孤生竹。", "結根不擇地，天地聊自足。", "卷耳不盈筐，綠芻不盈掬。", "願言勿采采，留此媚幽獨。"]'),
('50daef59-5b5e-4092-916c-a81031c79dcb','贈方星翁','何夢桂','宋','宋诗','song-poetry','','[]','憶別二十年，再見驚莽渺。',108,'全唐诗/poet.song.234000.json','["憶別二十年，再見驚莽渺。", "黔髮上星霜，紅顔化枯槁。", "隔世或相逢，往事漫不考。", "季子舌尚存，長卿心未老。", "妙算出星躔，窮搜入冥窅。", "病質愧衰遲，高論驚絕倒。", "天地兩無情，大化長浩浩。", "逝者如川流，朝露溘春草。", "行行重行行，貞名以爲寶。"]'),
('5ad7f75e-bf14-43e6-a5f9-15a09f317d82','入夏初晴','何夢桂','宋','宋诗','song-poetry','','[]','屏翳盜天權，豐隆據天宇。',132,'全唐诗/poet.song.234000.json','["屏翳盜天權，豐隆據天宇。", "沴陰抗六陽，入夏苦旬雨。", "煉石無媧皇，天漏誰與補。", "羲和駕赤輪，倏覩朝旭吐。", "泥蟲起躑躅，淖羽鼓掀舞。", "倚杖擬郊行，脫屣始出戶。", "喜氣薄林巒，生意溢蘅杜。", "天公本無心，造物誰實主。", "今昔倏變化，陰晴孰吹煦。", "我欲叫蒼蒼，叩閽撾天鼓。", "蒼生在巔崖，何時脫辛苦。"]'),
('8c8c1814-6594-472b-98c3-475c73e5d340','贈唐樂天星翁','何夢桂','宋','宋诗','song-poetry','','[]','有客傲今世，去古見是人。',144,'全唐诗/poet.song.234000.json','["有客傲今世，去古見是人。", "得姓遺唐譜，自號樂天民。", "毋乃香山老，重來現後身。", "問君何能解，滿口談天星。", "術高價難酬，索詩抵千金。", "我政坐詩窮，敢以窮累君。", "君謂窮不憂，詩賦樂我貧。", "不見石友死，錦帆不歛形。", "不見鄧侯餓，銅山化爲塵。", "命固受於天，誰能躍陶鈞。", "外物不可必，吾已反吾真。", "君看世上兒，疾走方紜紜。"]'),
('e297c94b-2322-4c63-8b82-84756dee5b9a','送自然子夏德甫','何夢桂','宋','宋诗','song-poetry','','[]','子以自然名，詰我自然理。',84,'全唐诗/poet.song.234000.json','["子以自然名，詰我自然理。", "至理本無言，有言已非是。", "畏隹時怒號，厲風從何起。", "晚得復怒生，春雨果誰使。", "使然與不然，萬化誰與紀。", "君詰我不知，不如兩忘已。", "君苟未忘言，請問柱下史。"]'),
('6668bd5f-eaab-4791-8db3-71fff5eb5961','送天約子胡子春','何夢桂','宋','宋诗','song-poetry','','[]','世人方熙熙，我獨處落落。',84,'全唐诗/poet.song.234000.json','["世人方熙熙，我獨處落落。", "世人方昭昭，我獨混濁濁。", "我行世固疑，世棄我自樂。", "馬蹄踐霜雪，寧期受刻雒。", "彘尻登俎豆，何如食糟粕。", "不知帝懸解，甘受人犍韄。", "回首觀環中，乾坤本寥廓。"]'),
('f70e7e77-11d6-4179-9885-e5b641a0e149','贈天遊子潘知非','何夢桂','宋','宋诗','song-poetry','','[]','浩浩天上水，悠悠天際雲。',72,'全唐诗/poet.song.234000.json','["浩浩天上水，悠悠天際雲。", "靜觀萬物化，誰使之芸芸。", "吾道在宇宙，與物同涬溟。", "牛馬誰毀譽，龍蠖自屈伸。", "浮游寄一世，儻然忘我人。", "究竟弗可詰，與子俱愚芚。"]'),
('db3944d9-f49c-4052-a7da-d5e4c76a8979','贈天台陳道人','何夢桂','宋','宋诗','song-poetry','','[]','山中老希夷，長抱白雲睡。',60,'全唐诗/poet.song.234000.json','["山中老希夷，長抱白雲睡。", "睡覺呼蹇馿，悠然出山去。", "道上忽相逢，爲問天下事。", "長笑不復言，不言有深意。", "蒼生在巔崖，感此淚如雨。"]'),
('a3371fbd-d0d0-440f-96a9-d58532412a91','方釣隠挾星學求詩且業醫','何夢桂','宋','宋诗','song-poetry','','[]','駢拇不礙履，枝指不害持。',48,'全唐诗/poet.song.234000.json','["駢拇不礙履，枝指不害持。", "兩者各自適，意其天所爲。", "決之足反蹇，齕之手反萎。", "萬物固有命，勸君休說醫。"]'),
('ff03480d-a56b-437f-abe3-6072a3f24af0','贈楊古澹','何夢桂','宋','宋诗','song-poetry','','[]','南山有岑樓，岑樓高落星。',72,'全唐诗/poet.song.234000.json','["南山有岑樓，岑樓高落星。", "娟娟樓上女，悠悠撫朱繩。", "高年猗蘭操，翻作長短清。", "世無千古人，惟遺千古心。", "心長韻愈遠，疏越難可聞。", "曲盡無人聽，月高風滿城。"]'),
('4f518b6d-9a63-4088-9f89-7bb4412f40d5','和徐榷院唐佐見寄七首  其一','何夢桂','宋','宋诗','song-poetry','','[]','苒苒歲月晚，悠悠美人思。',60,'全唐诗/poet.song.234000.json','["苒苒歲月晚，悠悠美人思。", "皎皎在天月，娟娟落水涯。", "相思何所寄，日莫折瓊枝。", "哀鴻翅翎短，苦爲稻粱縻。", "願言化爲雲，長與龍相隨。"]'),
('e457cd5a-476c-4e9b-9c72-1c92013e6f7e','和徐榷院唐佐見寄七首  其二','何夢桂','宋','宋诗','song-poetry','','[]','白雲古樹杪，下有山人家。',84,'全唐诗/poet.song.234000.json','["白雲古樹杪，下有山人家。", "與君曾讀易，探索入聖涯。", "盤桓坐白石，汲泉燒鼎茶。", "至今山中兒，羨我兩客嘉。", "客去不復來，屋上凝朝霞。", "有時撫孤琴，猿鶴聽無譁。", "何當賦招隠，共駕青牛車。"]'),
('36b28da1-e421-4ea7-a179-c97cd2ad00ea','和徐榷院唐佐見寄七首  其三','何夢桂','宋','宋诗','song-poetry','','[]','月冷岸葭蒼，風勁山木震。',48,'全唐诗/poet.song.234000.json','["月冷岸葭蒼，風勁山木震。", "搗砧誰家婦，聲急心緒紊。", "爲問聲何哀，聲聲怨時運。", "何許從英皇，蒼梧叫虞舜。"]'),
('1f067a7d-2b6c-4a4c-8acb-63a1c8623857','和徐榷院唐佐見寄七首  其四','何夢桂','宋','宋诗','song-poetry','','[]','孟冬寒氣至，蟋蟀入床下。',72,'全唐诗/poet.song.234000.json','["孟冬寒氣至，蟋蟀入床下。", "我早索衣裘，婦尚繫裙布。", "時序倏改變，悽慘感霜露。", "姑老遠行役，鞠子誰乳哺。", "夜半山壑移，人生况旅寓。", "傷心重傷心，江空歲華暮。"]'),
('645af16f-116b-442d-8d35-c48e05a2210b','和徐榷院唐佐見寄七首  其五','何夢桂','宋','宋诗','song-poetry','','[]','南山有高樓，青雲可俯踐。',96,'全唐诗/poet.song.234000.json','["南山有高樓，青雲可俯踐。", "樓上有佳人，當年慣識面。", "忽覺在他鄉，綽約思目見。", "綠綺無知音，心長曲未遍。", "青雲在山頭，將去還復戀。", "人生不如雲，欲見萬里遠。", "恃有青銅鏡，與君各分半。", "忽來雙鯉魚，白璧何足羨。"]'),
('71214ce3-5841-4f80-a3b3-b881633a1022','和徐榷院唐佐見寄七首  其六','何夢桂','宋','宋诗','song-poetry','','[]','望有玉山果，細實如房蜂。',60,'全唐诗/poet.song.234000.json','["望有玉山果，細實如房蜂。", "世味羞桃李，棄此盤盎巾。", "膚頑味更澀，僅能殺三蟲。", "頼以著微績，始襲炎帝封。", "不意得君采，致身願相從。"]'),
('65c29299-0f63-47b8-8e2e-67c3bfc01404','和徐榷院唐佐見寄七首  其七','何夢桂','宋','宋诗','song-poetry','','[]','人懷千歲憂，常苦百年速。',72,'全唐诗/poet.song.234000.json','["人懷千歲憂，常苦百年速。", "千歲與百年，黄泉總相逐。", "漆園何誕妄，養生託緣督。", "邯鄲非渺茫，夢覺驚黍熟。", "生死如彼何，愛惡亦徒欲。", "俛仰宇宙間，吾姑抱吾獨。"]'),
('1a73cf3d-a43e-41a7-918e-3c8b2006f2e8','和盧可菴悲秋十首  其一','何夢桂','宋','宋诗','song-poetry','','[]','秋風來庭際，奄忽老蓐收。',48,'全唐诗/poet.song.234000.json','["秋風來庭際，奄忽老蓐收。", "夜寒耿無寐，起坐焚膏油。", "孤燈照我影，對坐自倡酬。", "偈參意未竟，參橫轉西樓。"]'),
('97fba0e6-bd62-4bd3-b642-afb95a470bce','和盧可菴悲秋十首  其二','何夢桂','宋','宋诗','song-poetry','','[]','秋風來高樓，樓上棟雲飛。',48,'全唐诗/poet.song.234000.json','["秋風來高樓，樓上棟雲飛。", "登樓杳西望，陰陰天雲垂。", "天闊渺無極，遊子去不歸。", "不歸在何許，意採南山芝。"]'),
('949f51e6-daca-4a68-ac7c-f4a3f0a3bfe8','和盧可菴悲秋十首  其三','何夢桂','宋','宋诗','song-poetry','','[]','秋風來戶牖，出戶天地寬。',48,'全唐诗/poet.song.234000.json','["秋風來戶牖，出戶天地寬。", "俯仰何跼蹐，天地猶盤盤。", "况復中間人，機險一黄間。", "毋懷千歲憂，且盡百年歡。"]'),
('1d522ce7-94db-4ab9-9f8d-9d88e27f68c7','和盧可菴悲秋十首  其四','何夢桂','宋','宋诗','song-poetry','','[]','秋風來木末，忽忽吹晚晴。',48,'全唐诗/poet.song.234000.json','["秋風來木末，忽忽吹晚晴。", "木落雁南歸，嚦嚦多悲聲。", "少壯老復至，歲月方遄奔。", "我欲歌秋風，愁聽簫鼓鳴。"]'),
('f0f151cc-9c99-475b-8ea9-01ce075d5d51','和盧可菴悲秋十首  其五','何夢桂','宋','宋诗','song-poetry','','[]','秋風來萬壑，蜴蜥吐冰雹。',48,'全唐诗/poet.song.234000.json','["秋風來萬壑，蜴蜥吐冰雹。", "雷吼彈丸飛，四海沍陰濁。", "誰能彎天弧，與我一矢落。", "奈何山嶽移，回頭已非昨。"]'),
('90f5a4cf-2144-4d16-8e35-5f0db8f17535','和盧可菴悲秋十首  其六','何夢桂','宋','宋诗','song-poetry','','[]','秋風來岩谷，萬竅生寂虛。',48,'全唐诗/poet.song.234000.json','["秋風來岩谷，萬竅生寂虛。", "畏隹忽怒號，披拂其誰居。", "天地等一馬，逝者無停車。", "君看郭外塚，荒丘無人鋤。"]'),
('38c935c7-0fb4-4dce-b8f5-c3c877a91d7b','和盧可菴悲秋十首  其七','何夢桂','宋','宋诗','song-poetry','','[]','秋風來江臯，槌鼓誰載酒。',48,'全唐诗/poet.song.234000.json','["秋風來江臯，槌鼓誰載酒。", "徒羨謫仙人，百篇醉一斗。", "將軍告身在，尚可易醇酎。", "萬事休皺眉，一笑且開口。"]'),
('675b6ae7-6251-4803-a2d5-fc74a4637241','和盧可菴悲秋十首  其八','何夢桂','宋','宋诗','song-poetry','','[]','秋風來天河，天河淺且清。',48,'全唐诗/poet.song.234000.json','["秋風來天河，天河淺且清。", "天孫撫機杼，終日織不成。", "自從夫君去，聽盡金雞鳴。", "妾身倘未死，妾心百煉精。"]'),
('acc4dfe0-8bca-42b2-a6ff-4cf5d3a6391e','和盧可菴悲秋十首  其九','何夢桂','宋','宋诗','song-poetry','','[]','秋風來大地，萬里成丘墟。',48,'全唐诗/poet.song.234000.json','["秋風來大地，萬里成丘墟。", "床頭何所有，惟有一卷書。", "曳縱朗長誦，環堵樂有餘。", "自笑飯顆山，少陵真腐儒。"]'),
('f6212149-ce43-41b0-9afb-fff2035606db','和盧可菴悲秋十首  其一○','何夢桂','宋','宋诗','song-poetry','','[]','秋風來太虛，逍遥浮大庭。',48,'全唐诗/poet.song.234000.json','["秋風來太虛，逍遥浮大庭。", "吾身與天地，等如水上萍。", "弄丸閒往來，意行還微吟。", "吟盡無人聽，惟遺空外音。"]'),
('823729b3-1cde-4d66-b98b-c2a1853fcca2','上夾谷書隠先生六首  其一','何夢桂','宋','宋诗','song-poetry','','[]','堪輿渺無極，俯仰慨古初。',72,'全唐诗/poet.song.234000.json','["堪輿渺無極，俯仰慨古初。", "皇風戰涿鹿，草野傷血塗。", "勳華襲文明，不肯私均朱。", "誓命纘王業，侵伐紛霸圖。", "春秋二百祀，已矣吾道孤。", "天不生夫子，民極誰其扶。"]'),
('dffce97d-94f8-4eb9-b403-f677b0362a22','上夾谷書隠先生六首  其二','何夢桂','宋','宋诗','song-poetry','','[]','反袂歎麟折，過門傷鳳衰。',72,'全唐诗/poet.song.234000.json','["反袂歎麟折，過門傷鳳衰。", "奠楹不復作，世喪禮樂隳。", "世喪道不喪，文豈不在茲。", "千載而有人，三代猶可追。", "吾聞夾谷翁，文獻尚有遺。", "斯世微斯人，皇皇吾安歸。"]'),
('22a80fcd-8649-46d4-b4ce-b1ec3b05b8f8','上夾谷書隠先生六首  其三','何夢桂','宋','宋诗','song-poetry','','[]','錦峰有使星，光芒夜燭天。',60,'全唐诗/poet.song.234000.json','["錦峰有使星，光芒夜燭天。", "聞道繡衣來，上應此星躔。", "兒童爭迎拜，不敢持一錢。", "一錢不足云，愛心重留連。", "輒持一盂水，滴滴釣臺前。"]'),
('c8aa059d-8a83-46a1-911c-14a7afbc90e5','上夾谷書隠先生六首  其四','何夢桂','宋','宋诗','song-poetry','','[]','衣冠墮塗炭，血肉膏斤斧。',60,'全唐诗/poet.song.234000.json','["衣冠墮塗炭，血肉膏斤斧。", "喜聞使車來，猶歌來何暮。", "蒼生在顛崖，惟恐隔風雨。", "誰爲埋車輪，渾家白雲住。", "下有羊裘翁，清風清萬古。"]'),
('be656c8b-e074-4c05-b821-f401cdc6e10f','上夾谷書隠先生六首  其五','何夢桂','宋','宋诗','song-poetry','','[]','平生學屠龍，終乃成履豨。',60,'全唐诗/poet.song.234000.json','["平生學屠龍，終乃成履豨。", "國亡身未殯，戮死竟何如。", "衣带日以緩，鬢髮日以疏。", "晨風懷苦心，不能高奮飛。", "獨抱三聖易，終焉老吾廬。"]'),
('60cf403a-ad1a-4ea9-85a2-f2595f96cec0','上夾谷書隠先生六首  其六','何夢桂','宋','宋诗','song-poetry','','[]','驥老不適用，狐首復何幾。',72,'全唐诗/poet.song.234000.json','["驥老不適用，狐首復何幾。", "身名與世隔，誰以告彼姝。", "衷腸遠難訴，載訴出戶衣。", "出戶亦不辭，疑我故步非。", "袖中懷綠綺，自傷知音稀。", "爲君試一彈，霑襟涕漣濡。"]'),
('96db6e58-980d-47f0-beb1-6cfe3f3904b8','擬古五首  其一','何夢桂','宋','宋诗','song-poetry','','[]','木落不離根，菊槁不離枝。',72,'全唐诗/poet.song.234000.json','["木落不離根，菊槁不離枝。", "人懷父母心，豈願生別離。", "皇路謇幽蔽，民用嬰百罹。", "南枝栖越鳥，忍逐北風飛。", "北風藐萬里，分此無回期。", "骨朽化爲塵，魂魄將南歸。"]'),
('cc21787c-b135-4fd9-8572-bb70b51eec56','擬古五首  其二','何夢桂','宋','宋诗','song-poetry','','[]','生爲結髮婚，死爲同穴鬼。',84,'全唐诗/poet.song.234000.json','["生爲結髮婚，死爲同穴鬼。", "豈意冰上緣，淪沒隔萬里。", "半鏡隨塵沙，嫁衣在巾笥。", "紅絲倘未絕，白首尚歸止。", "心隨碣石雲，淚落銅盤水。", "雲飛會南來，水流還北注。", "此生不可期，心期勖來世。"]'),
('118c7112-c708-4e18-aebd-7ea99883fe0f','擬古五首  其三','何夢桂','宋','宋诗','song-poetry','','[]','萬馬蕭蕭來，萬矢的的鳴。',72,'全唐诗/poet.song.234000.json','["萬馬蕭蕭來，萬矢的的鳴。", "蛾眉逐羈馽，淚盡眥血零。", "偷生愧夫天，寧死化鬼燐。", "昭質誓不污，九死志靡徵。", "紅玉隨劍光，晶熒貫列星。", "遺胔葬螻蟻，冢墓高媧陵。"]'),
('0fdbd6d2-ae6c-44b9-89b0-4e472d2be68b','擬古五首  其四','何夢桂','宋','宋诗','song-poetry','','[]','封狼藐萬里，風雪饒陰山。',84,'全唐诗/poet.song.234000.json','["封狼藐萬里，風雪饒陰山。", "地荒走蛇豕，俘縶去不還。", "高門誰氏子，受驅牧猳犍。", "去時紈袴敝，氈毳不蔽寒。", "夜夜望北斗，不逐南箕旋。", "父母生我初，拊我掌股間。", "豈意越在茲，撫身空自憐。"]'),
('9837c923-3b73-46fd-a3d5-413c7d994a08','擬古五首  其五','何夢桂','宋','宋诗','song-poetry','','[]','杞國天柱傾，哀我鞠子疚。',84,'全唐诗/poet.song.234000.json','["杞國天柱傾，哀我鞠子疚。", "蒼鵞飛沖天，妖星大如斗。", "簾下玉床移，山摧石鰲負。", "河南弔遺黎，原野骨未朽。", "北邙望孤陵，古木叫猿狖。", "朔風吹塵沙，天寒薄翠袖。", "南雲山萬重，去去莫回首。"]'),
('ae1caa12-419a-4819-b430-0f4a58077d0a','岳帥寄烈女古意和韻答之','何夢桂','宋','宋诗','song-poetry','','[]','一琴久絃絕，孤操誰與同。',60,'全唐诗/poet.song.234000.json','["一琴久絃絕，孤操誰與同。", "羅幃長白髮，燕子樓已空。", "夫君邈萬里，目斷隨冥鴻。", "鴻飛不南來，亂鳥啼朔風。", "寧死化爲石，石上生虬松。"]'),
('9e40bb8f-d826-40b0-be8c-e47a60a6c075','賦風花  其一','何夢桂','宋','宋诗','song-poetry','','[]','玄化浩無極，豈爲萬物私。',84,'全唐诗/poet.song.234000.json','["玄化浩無極，豈爲萬物私。", "燕坐觀物化，榮悴故有時。", "春林著寒葩，猶記去年枝。", "日暮還復殞，委運不可羈。", "天機自高下，時命非所知。", "變化紛萬感，逝者長如斯。", "誰能渺獨立，終古以爲期。"]'),
('e774e3d0-e5c1-4ce6-87d4-f3a02eed94dc','賦風花  其二','何夢桂','宋','宋诗','song-poetry','','[]','大鈞播萬物，靜觀自森著。',72,'全唐诗/poet.song.234000.json','["大鈞播萬物，靜觀自森著。", "倏見朝華榮，夕隕亦何遽。", "升沈信天機，高下兩無據。", "世眼空紛籍，往事逐飛絮。", "今年花上枝，去年花落處。", "開落無常期，年來復年去。"]'),
('3155464a-344a-458b-a904-ff8127dc2cfa','雪樓程御史次方山房韻見寄用韻答賦三首  其一','何夢桂','宋','宋诗','song-poetry','','[]','萬物委橋運，逝水無回波。',60,'全唐诗/poet.song.234000.json','["萬物委橋運，逝水無回波。", "美人渺何許，道遠空寤歌。", "願言結瑶珮，乘虬下陽阿。", "陽阿有瑶草，爲我起宿痾。", "行行望高臺，日暮將奈何。"]'),
('78f93481-3cdb-4ee0-bcd1-ff9ba7fc3fa2','雪樓程御史次方山房韻見寄用韻答賦三首  其二','何夢桂','宋','宋诗','song-poetry','','[]','青樓有蛾眉，翳袖渺獨處。',72,'全唐诗/poet.song.234000.json','["青樓有蛾眉，翳袖渺獨處。", "日暮賦摽梅，愧我求彼士。", "誰家操孤鸞，感此中夜起。", "明河落天西，玉繩低欲輊。", "結言藉媒勞，恩重報無地。", "明珠在羅襦，誰能諒心事。"]'),
('f50dca28-d89b-458d-88d7-6345a7c3e3b2','雪樓程御史次方山房韻見寄用韻答賦三首  其三','何夢桂','宋','宋诗','song-poetry','','[]','思君隔山陂，矢心誓白水。',72,'全唐诗/poet.song.234000.json','["思君隔山陂，矢心誓白水。", "夔蚿各自憐，人生貴適意。", "馬頭黄金羈，不易牛背睡。", "白髮難再玄，百子空自許。", "南山或可移，愚公有孫子。", "堪輿浩無窮，俯仰一寤寐。"]'),
('f721c50a-ad38-47f4-afdf-c8e95b42fd6f','遠遊丞樵隠王德甫寄詩輒和二章以謝  其一','何夢桂','宋','宋诗','song-poetry','','[]','白日過駒隙，玄髮成衰翁。',60,'全唐诗/poet.song.234000.json','["白日過駒隙，玄髮成衰翁。", "陞天無八翼，苦志懷晨風。", "晨風不可企，下界塵冥濛。", "去去藐八極，安能離彀中。", "爲馬或爲牛，吾將安適從。"]'),
('cdf26f13-990f-4e37-b34e-bf804a455dfc','遠遊丞樵隠王德甫寄詩輒和二章以謝  其二','何夢桂','宋','宋诗','song-poetry','','[]','宿昔夢見君，晨起得詩冊。',60,'全唐诗/poet.song.234000.json','["宿昔夢見君，晨起得詩冊。", "詩中意如何，閔我遠行役。", "上言久別離，下言長寤擗。", "世無魯陽戈，誰能迴白日。", "白髮一夜生，爲君隠陫側。"]'),
('f568ec23-4263-4565-ba3b-eac3988beb72','和夾谷書隠先生寄題蛟峰石峽書院三十韻','何夢桂','宋','宋诗','song-poetry','','[]','堪輿運玄化，萬物品彙分。',288,'全唐诗/poet.song.234000.json','["堪輿運玄化，萬物品彙分。", "狉狉鹿豕羣，中有五色麟。", "聖哲不出世，郊囿可能馴。", "粵從光嶽分，鴻靈咸糾紛。", "征役石漸漸，戰伐車轔轔。", "詩亡春秋作，三嘆悲聖人。", "西狩折其足，反袂那能聞。", "而况千載下，遺軼已絕塵。", "木鐸響不振，安能此身親。", "冥冥晦暮夜，高燎誰煬晨。", "縱橫紛季子，法律慘商君。", "吾道成說輻，君子歎伐輪。", "時無郢人鼻，誰運匠石斤。", "世喪道未喪，氣盛化自神。", "無道固耻穀，有道亦耻貧。", "蛟翁世耆俊，皇華重諏詢。", "次公早識面，次第以禮賓。", "廼聞抗高誼，木石將終身。", "雲間有山峽，劫火不得焚。", "石間有書室，雪迹猶未陳。", "當路風詩書，出此屋壁文。", "青青集衿風，勖爾小子勤。", "斯道未墜地，百世知所因。", "苞栩成集鴇，白茅尚包麕。"]'),
('ebceef2b-d21d-45b9-a7eb-ee734a9edd4e','寄謝夾谷書隠先生四十四韻','何夢桂','宋','宋诗','song-poetry','','[]','粵從太極分，大塊溟涬洩。',288,'全唐诗/poet.song.234000.json','["粵從太極分，大塊溟涬洩。", "人生於其間，三才位成列。", "人極苟不立，清寧將竭裂。", "厥初始斷鰲，萬古功卓絕。", "誰觸不周山，地摧天柱折。", "媧皇不煉石，方圓成陷缺。", "九載困懷襄，東柱至西碣。", "乘載微司空，斯民化魚鱉。", "上下三千年，世變幾更迭。", "誰與持風輪，不至人類滅。", "魯廟祠太牢，漢庭定綿蕝。", "澤國訪羊裘，東都樹名節。", "斯道無存亡，惟人善顯設。", "先後雖殊途，彼此有同轍。", "山冢摧且傾，川流沸將竭。", "托身止徬徨，勞心苦忡惙。", "時無武城偃，誰知堂下蔑。", "吏來方叫囂，我行方蹩躠。", "賓主成寇讎，樽俎化縲絏。", "楚市愧受鉗，山東羞折頞。", "無處籲旻天，甘心死岩穴。", "維北有星躔，煌煌西柄揭。", "皇帝哀不辜，分符理司臬。", "令出風霆行，章分雲漢抉。"]'),
('e393f538-c7f5-4371-8ed9-c16c3ce0ac94','送野塘王經歷三十韻','何夢桂','宋','宋诗','song-poetry','','[]','世變浩無極，俯仰長吁嘻。',288,'全唐诗/poet.song.234000.json','["世變浩無極，俯仰長吁嘻。", "人情恩與讎，相值每不期。", "邯鄲至受兵，何與魯酒醨。", "弄丸本無心，乃解兩家圍。", "懷古意未竟，傷今有餘悲。", "世無武城宰，偃室有誰歸。", "世無吳興令，牛屋奚敢辭。", "不虞涉吾地，叫囂且突隳。", "樽俎化桎梏，賓主生戎夷。", "范雎幾拉骼，蔡澤成頷頤。", "自憐還自笑，此物至奚宜。", "犁牛受鞭縶，文貍墜阱機。", "此豈物有罪，罪在角與皮。", "安之若有命，雖死無悔追。", "俄聞天際星，一夕躔次移。", "光芒照人間，是爲使者車。", "翩然下青冥，持斧衣繡衣。", "文章星斗爛，號令雷霆威。", "幕府遴高選，分遣羽檄飛。", "君來山水縣，草木生光輝。", "洗手奉三尺，不肯枉毫釐。", "登山縛虎兕，入水擒蛟螭。", "斯民久瘡痏，嫗喣以母慈。", "遂使斯道福，溥及山澤癯。"]'),
('ce64f121-3d2c-4d1d-8075-aebcbe4967be','和耜岩讚易傳來韻','何夢桂','宋','宋诗','song-poetry','','[]','三釜養弗違，五斗腹已饜。',288,'全唐诗/poet.song.234000.json','["三釜養弗違，五斗腹已饜。", "歸無買山銀，聊占白石崦。", "崦西有斗室，草色青入簾。", "有時獨悲歌，白雲低覆檐。", "心勞髮成絲，不敢開鏡奩。", "純鈎未曾試，敢謂鉛刀銛。", "行行行復止，恐爲世猜嫌。", "俯仰宇宙窄，吾姑養吾恬。", "濯髮餐沆瀣，載魄吞玉蟾。", "世味紛濁濁，食魚誰溉鬵。", "君來此山中，相逢一掀髯。", "議論不苟同，鹹酸惟梅鹽。", "探索卦爻賾，抉發天地潛。", "君思方浩浩，我足愧霑霑。", "未竟先天奧，已報歸郵籤。", "重來詰玄秘，試與君一拈。", "精神寄四聖，後學未易覘。", "堪輿物最巨，蝡動物至纖。", "雷震與風行，水潤復火炎。", "孰匪陰陽用，豈待蓍策占。", "吾身亦具足，誰能減與添。", "六畫無一辭，三才道已兼。", "大象不可名，小言徒詹詹。", "九師易已病，安得惡石砭。"]'),
('fd58c7d4-43fd-4c80-a197-bbb454fd8106','和何逢原寄韻','何夢桂','宋','宋诗','song-poetry','','[]','世界歸大壑，人事如奔淙。',252,'全唐诗/poet.song.234000.json','["世界歸大壑，人事如奔淙。", "浮生萃草木，萬變成飄風。", "觸蠻兩蝸國，王侯一蟻封。", "下觀黔首愚，咄嗟書虛空。", "怒攘亦蠢蠢，羣飛何夢夢。", "失手弄刀劍，轉眼生兵戎。", "萬騎彀弓矢，千夫駕臨衝。", "原野肆尸血，道路哀離鴻。", "帥師有丈人，在師得師中。", "不辜多全活，不與羣醜同。", "師克未爲績，不殺真膚公。", "乾坤一胞與，感此重戚容。", "涿鹿始爭戰，千古開武功。", "春秋書戰伐，三復爲惙忡。", "南風鼓虞氏，吾誰與王通。", "擊磬斯已矣，荷蕢猶可宗。", "無用媿社櫟，浪出羞澗松。", "君謂叔孫智，人笑酈生庸。", "未能半分補，政墮一動凶。", "歸來友石友，相對仲與翁。", "抱神慎守一，吾欲師崆峒。"]'),
('06a0f49d-a847-4d09-91b0-1d4c463c6ee3','和劉府判寄詩','何夢桂','宋','宋诗','song-poetry','','[]','那有賢貳車，抗節今無儕。',48,'全唐诗/poet.song.234000.json','["那有賢貳車，抗節今無儕。", "拄笏看千峰，冷風散虛齋。", "莊陵一絲絕，白雲鎖雙崖。", "曷時從君遊，聊以紓余懷。"]'),
('c601ff13-bdd2-4fbb-9472-20cf424c3517','贈術士邵易庵','何夢桂','宋','宋诗','song-poetry','','[]','易道皆萬變，萬彙寄一易。',168,'全唐诗/poet.song.234000.json','["易道皆萬變，萬彙寄一易。", "大道降九流，至理散方術。", "譬猶八面窗，八方可從入。", "譬猶九達衢，九軌所由出。", "道術雖二致，殊途極歸一。", "得醫爲倉扁，得法爲軌革。", "郭氏探錦囊，甘心步璇歷。", "勿謂所執微，垂名等籍籍。", "易庵挾四技，每技探易賾。", "技分易不精，君獨精以密。", "我愧絕韋編，所得止一畫。", "一畫未爲病，錯出已什伯。", "四事君盡兼，懼君苦形役。", "持此應世間，化身須百億。"]'),
('f1f90f59-1b4a-4aa4-a435-7868ba5b77e0','贈何覺山','何夢桂','宋','宋诗','song-poetry','','[]','昔有二道士，學道隠此山。',84,'全唐诗/poet.song.234000.json','["昔有二道士，學道隠此山。", "一覺徑超詣，脫屣遺人寰。", "石影未滅沒，半出林巒間。", "空山以名存，高蹤那能攀。", "下有可人翁，老去雙鬢斑。", "天涯蹇行足，日暮倦鳥還。", "神交藐千古，試爲問丸丹。"]'),
('141f55b0-7d8d-4987-8af8-169e7672468f','題邵古香乾坤一亭','何夢桂','宋','宋诗','song-poetry','','[]','一亭亦直寄，作者知爲誰。',84,'全唐诗/poet.song.234000.json','["一亭亦直寄，作者知爲誰。", "結薜開戶牖，柱桂辛夷楣。", "百年此宴樂，常恐生憂悲。", "天地一傳舍，過客安可羈。", "唐肆欲求馬，萬事隙決駒。", "白雲亭上山，流水亭下池。", "夜半撫朱繩，美人生白髭。"]'),
('a9e8bfcc-9040-458e-beeb-dda39de56f2e','送淳安括田省委賈都事','何夢桂','宋','宋诗','song-poetry','','[]','白馬何方來，青絲紅錦韉。',288,'全唐诗/poet.song.234000.json','["白馬何方來，青絲紅錦韉。", "手持省府檄，身著從事衫。", "分麾蒞屬邑，銜命司括田。", "一見爲鸞鳳，不肯爲鷹鸇。", "視民如有疾，見客似無官。", "疲民得賈父，僻壤戴蘇天。", "群情有欲愬，百口難具宣。", "君來五閲月，熟察民顛連。", "嚴爲浙偏壘，淳在嚴萬山。", "按圖覽輿地，邑境若斗然。", "一分布阡陌，九分奠山川。", "墾畝雜沙礫，斸土見水泉。", "桑不給繭絲，農不供粥饘。", "耕鑿地力盡，租稅民用殫。", "江南享有國，錢塘餘百年。", "地偏費實浩，額外賦益繁。", "和買非正絹，茶役皆贏錢。", "民窮未忍死，上慈政令寬。", "三年輸未足，一榜逋悉蠲。", "遺黎戴白叟，尚能話興元。", "天朝大一統，地域跨八埏。", "中邦定成賦，遠氓均受廛。", "吁嗟天地仁，豈使雨露偏。", "君歸勿委蛇，禁中需牧頗。"]'),
('4e9b9d32-d770-4894-a2bf-f38cb532b0ea','感懷再和山房韻','何夢桂','宋','宋诗','song-poetry','','[]','幽人癖好山，結屋山北方。',156,'全唐诗/poet.song.234000.json','["幽人癖好山，結屋山北方。", "於菟出繞屋，寧復劬禿當。", "岩溜晴霢霂，野燒夕燉煌。", "療饑采紫芝，不救病髮蒼。", "何人賦小山，靜聽心茫茫。", "倚歌和招隠，意長曲未央。", "夜夢衣雲錦，乘虬朝帝旁。", "鈞天聽未了，玄運不可常。", "百年少壯心，時醉歌并凉。", "層城閉青蛾，無處覓玄霜。", "亡羊兩得失，奚擇穀與臧。", "齒舌誰墮在，寧計彼軟剛。", "千古雲山高，歃泉酹嚴光。"]'),
('7df92964-9c14-4b26-8803-28df737fa750','慰嚴溪張君貢士','何夢桂','宋','宋诗','song-poetry','','[]','朝日景曈曈，湛露溘已晞。',132,'全唐诗/poet.song.234000.json','["朝日景曈曈，湛露溘已晞。", "日暮風淒淒，啼鳥失其雛。", "時邁感物化，撫事成傷悲。", "嚴溪子張子，有兒讀父書。", "年少雋且文，親顔悅以怡。", "一朝成鬼錄，登臺空望歸。", "望歸不歸來，淚盡雙目眵。", "嬴博招爾魂，忍撫游子衣。", "生子期養親，安知親哭兒。", "古傷鄧伯道，天道不可知。", "穆伯有收子，暮年良可期。"]'),
('262eac74-4ca6-48ce-9b8b-37bbb642880b','贈相士許松坡','何夢桂','宋','宋诗','song-poetry','','[]','天地委爾形，禍福唯所命。',132,'全唐诗/poet.song.234000.json','["天地委爾形，禍福唯所命。", "夭顔壽盜跖，窮憲富猗頓。", "陰陽氣不齊，所受各有分。", "司造秘不言，誰能作天問。", "君今挾相術，兩目烱清鏡。", "開口說是非，竊弄司造柄。", "富貴聞者喜，貧賤聞者慍。", "分定不可移，喜慍兩皆病。", "朝暮芧四三，空使衆狙競。", "安知鳩與鵬，小大各適性。", "勸君且歸休，吾方游神廷。"]'),
('f23f00af-085f-436e-9da4-4c14ae9a20bd','旌表陳節婦古意','何夢桂','宋','宋诗','song-poetry','','[]','庭隅墮缺月，慈烏驚夜啼。',156,'全唐诗/poet.song.234000.json','["庭隅墮缺月，慈烏驚夜啼。", "哀啼心獨苦，抱雛耿孤棲。", "孤棲不自恤，懷人在中閨。", "嫠緯織不成，撫杼羌憯悽。", "煢煢守孤兒，覆額髮未齊。", "矢心負螟蠃，兩手各持携。", "廩粟不自富，歲以粒遺黎。", "大火化劫運，終然完白圭。", "邅迴蹇吾道，三綱墜塗泥。", "鬚眉衆婦女，媿死一寡妻。", "徽名表貞節，光彩生門題。", "斲雪靈山山，濯清沙溪溪。", "三唱衛柏舟，天橫斗柄低。"]'),
('f86783d0-a03c-4d61-ae12-b3ab069d7da8','餞于高士','何夢桂','宋','宋诗','song-poetry','','[]','狙公窮四三，羸馬疲鈎百。',120,'全唐诗/poet.song.234000.json','["狙公窮四三，羸馬疲鈎百。", "歸來南山南，掃門謝俗客。", "有客扣我扃，猿鶴驚褫魄。", "行行杖青藜，吹烟照琴冊。", "雙頄凝丹霞，秋水入瞳碧。", "極談造玄玄，對坐忘岸幘。", "山巔有老杞，枯槁無液澤。", "夜半出精怪，尚或聞犬咋。", "祇今吾喪我，誰能逐轍迹。", "一笑客出門，山空霜月白。"]'),
('aff16c86-4282-470c-a3d7-f98298859484','次山房贈阮尉燭詩韻','何夢桂','宋','宋诗','song-poetry','','[]','翩翩佳公子，青絲絡白顛。',96,'全唐诗/poet.song.234000.json','["翩翩佳公子，青絲絡白顛。", "黄綬映春花，來作吏隠仙。", "鳴琴鎮白下，賦劍起通泉。", "誰分讀書燭，良價重蠟鞭。", "官燭不以照，持此當坐前。", "釜炊陋貴習，炬圍嗤少年。", "東壁得餘光，夜績長不眠。", "好留待他日，列照修史編。"]'),
('fa851201-843a-466f-93d9-02e3d4f8a9fb','次山房岐絲吟韻','何夢桂','宋','宋诗','song-poetry','','[]','南北本同歸，何人泣異岐。',120,'全唐诗/poet.song.234000.json','["南北本同歸，何人泣異岐。", "玄黄本同質，何人悲素絲。", "悲泣不自已，吾故憫翟朱。", "聖賢急救世，猶或與心違。", "二子救世心，豈願戾厥初。", "兼愛與爲我，本昧善惡幾。", "賊人視兼愛，殘忍終罔知。", "失己視爲我，流蕩返故遲。", "安得二子心，不爲世道思。", "吾將責二子，一世將焉知。"]'),
('317de5e3-9e9c-4bdf-947a-7ff2d38dae09','次山房見寄韻','何夢桂','宋','宋诗','song-poetry','','[]','懷人夜寤擗，彼美天西方。',156,'全唐诗/poet.song.234000.json','["懷人夜寤擗，彼美天西方。", "世變急三峽，吾道蹇兩當。", "起坐觀列緯，翕箕正煌煌。", "遊雲起碧落，反覆變白蒼。", "兩儀浩無際，萬期歸渺茫。", "感此不成寐，振衣夜未央。", "思君見梁月，忽若墮我旁。", "月明照我心，知心豈尋常。", "浩歌自起舞，宵景何蒼凉。", "墓梅萃彼鴞，葭露化爲霜。", "雞蟲兩得失，奚用論否臧。", "日月此昭質，天地吾直剛。", "願言勖本心，百世垂耿光。"]'),
('55c87b4c-2cd8-4b91-9b24-dcac5c9e24b6','感懷追和前韻','何夢桂','宋','宋诗','song-poetry','','[]','寒冰不附炭，圓枘豈納方。',156,'全唐诗/poet.song.234000.json','["寒冰不附炭，圓枘豈納方。", "心同媒易合，分隔意難當。", "膏火不晝耀，夕暮長煌煌。", "松柏無春華，霜雪自蒼蒼。", "萬物何定極，百世終混茫。", "瞻彼巢林隼，胡爲水中央。", "夜夢衣雲錦，乘虬朝帝旁。", "鈞天聽未了，玄運不可常。", "百年少壯心，時醉歌并凉。", "層城閉青蛾，無處覓玄霜。", "亡羊兩得失，奚擇穀與臧。", "齒舌誰墮在，豈計彼軟剛。", "千年青銅鏡，寧爲垢損光。"]'),
('3cbdfa17-92ce-4939-b1bd-481ce4044e2d','次山房韻古意四首  其一','何夢桂','宋','宋诗','song-poetry','','[]','思君吹參差，幽路蹇離絕。',96,'全唐诗/poet.song.234000.json','["思君吹參差，幽路蹇離絕。", "綠藍不盈襜，芙蓉在木末。", "采蝱解我憂，憂思誰察識。", "世態反覆手，况復問宿昔。", "韝鷹豈思揚，轍鮒固相沫。", "得時與失勢，離附奚足惑。", "耳餘難爲交，管鮑易全德。", "伐木無良朋，白駒有佳客。"]'),
('1b508582-f1ca-4f0b-bdac-93354c3b5b5f','次山房韻古意四首  其二','何夢桂','宋','宋诗','song-poetry','','[]','佳人藐中洲，倚竹翠袖寒。',96,'全唐诗/poet.song.234000.json','["佳人藐中洲，倚竹翠袖寒。", "捐玦屬蹇修，脈脈一水間。", "夜半下雲旗，逸駕欻可攀。", "結言永爲好，矢報念急難。", "君有金錯刀，我媿白玉盤。", "終然鹽梅心，死不易鹹酸。", "往事化蜩翼，徂生遺鼠肝。", "永言歲寒心，寤擗長起歎。"]'),
('d4adfd3c-0232-455d-9024-fdea337ea182','次山房韻古意四首  其三','何夢桂','宋','宋诗','song-poetry','','[]','牽牛飲天河，河水清可挹。',96,'全唐诗/poet.song.234000.json','["牽牛飲天河，河水清可挹。", "天孫撫機杼，終日不成織。", "相望空寤言，無人諒心迹。", "人生窘良會，百年倏朝夕。", "朝夕不可期，來世固罔極。", "無金鑄鍾子，鼓瑟逝安適。", "帝子竚不來，采芳翳庭實。", "悠悠萬古心，俛仰三嘆息。"]'),
('a9db439b-9a7b-4509-9708-082b4ed1261e','次山房韻古意四首  其四','何夢桂','宋','宋诗','song-poetry','','[]','夜舟不藏壑，川流無回波。',96,'全唐诗/poet.song.234000.json','["夜舟不藏壑，川流無回波。", "百年逐憂樂，晝夜相戛摩。", "逝者不復來，皓首成蹉跎。", "誰歟傷鳳衰，毋乃楚狂歌。", "茲世固難免，縱有朝與鮀。", "猗蘭曲易彈，祇恐聽者訛。", "折楊雜黄荂，每與俚耳和。", "感此歌晨風，忘我將如何。"]'),
('a3ab2170-1e3d-4b2c-97c3-028a453351de','再和  其一','何夢桂','宋','宋诗','song-poetry','','[]','采芳遺所思，所思道幽絕。',96,'全唐诗/poet.song.234000.json','["采芳遺所思，所思道幽絕。", "濯髮沐蘭膏，卷然在髮末。", "鴂啼衆芳萎，微物固先識。", "我方行邁邁，我載歌昔昔。", "操舟入觴深，被髮出梁沫。", "至人本神游，詎知見者惑。", "畏途窘善步，變境乏全德。", "委順天地間，誰主復誰客。"]'),
('63531c35-9eeb-4ab7-afef-dbc5ce4bcd15','再和  其二','何夢桂','宋','宋诗','song-poetry','','[]','火鼠不畏熱，冰蠶不畏寒。',96,'全唐诗/poet.song.234000.json','["火鼠不畏熱，冰蠶不畏寒。", "未能蹈冰火，吾姑襲人間。", "徒駭廣可泳，太行巍可攀。", "世路蹇幽蔽，邅迴行路難。", "君坐歌三調，我起舞七盤。", "歌苦舞未終，觀者心未酸。", "矢言浩無極，恐彼隔肺肝。", "無言賦悄悄，永夜長寤歎。"]'),
('5a4992ff-f800-46ff-9c0c-0a50d0c327c7','再和  其三','何夢桂','宋','宋诗','song-poetry','','[]','渴不待醴酒，行潦聊可挹。',96,'全唐诗/poet.song.234000.json','["渴不待醴酒，行潦聊可挹。", "寒不待羅襦，短布聊自織。", "人生志富貴，役役死塵迹。", "天雞報明晨，暮鐘送歸夕。", "萬化迭故新，來者未終極。", "百年無定期，餘日姑自適。", "擬學種蟠桃，誰能待花實。", "海鷗倦長風，低徊此休息。"]'),
('bf07cfb7-0f19-421c-baa6-cacd921bdc73','再和  其四','何夢桂','宋','宋诗','song-poetry','','[]','劫池出墨灰，厄海騰洪波。',96,'全唐诗/poet.song.234000.json','["劫池出墨灰，厄海騰洪波。", "陰陽互勃蝕，天地相激摩。", "人生壽能幾，百歲易蹉跎。", "毋用戚戚憂，且賦浩浩歌。", "鴬鳩漸溟鵬，修鯨渺沙鮀。", "物性各有極，相企成舛訛。", "順天以全德，安土以敦和。", "及時且娛樂，不樂將奈何。"]'),
('2dea8f4f-6646-4610-bfa8-e92c05be7928','三用韻  其一','何夢桂','宋','宋诗','song-poetry','','[]','大鈞播萬彙，運化元不絕。',96,'全唐诗/poet.song.234000.json','["大鈞播萬彙，運化元不絕。", "芸芸方歸根，倏見上枝末。", "年華逐流波，去去人不識。", "少壯幾何時，忽霍異今昔。", "林蔭美鳩乳，水滑羨魚沫。", "鬒髮忽成霜，乍見忽驚惑。", "玄化不吾常，吾姑守玄德。", "千古萬古人，等如傳舍客。"]'),
('f377dd71-6747-45b4-adc4-cc25ee06b9b3','三用韻  其二','何夢桂','宋','宋诗','song-poetry','','[]','瓊樓藐層雲，絕棟天風寒。',96,'全唐诗/poet.song.234000.json','["瓊樓藐層雲，絕棟天風寒。", "阿誰吹玉龍，哀響落雲間。", "插羽欲相從，百尺那可攀。", "脈脈隔綺窗，欲語兩俱難。", "當年古銅人，夜半失露盤。", "露寒濕如水，見者爲悲酸。", "誰能鑄鐵關，鑱石爲腸肝。", "已夫已矣夫，無言付長歎。"]'),
('19ec21f7-759b-4243-b079-b1a497f0d10b','三用韻  其三','何夢桂','宋','宋诗','song-poetry','','[]','貧女傷莫年，有淚不可挹。',96,'全唐诗/poet.song.234000.json','["貧女傷莫年，有淚不可挹。", "秦川五色錦，半世勞獨織。", "織花空過眼，新故總塵迹。", "撫機悲歲年，顔貌非故夕。", "妾心比錦絲，絲長恨無極。", "綉衾雙鴛鴦，抱此欲誰適。", "沃桑歎黄隕，尚肯賦梅實。", "悠悠世上兒，何處堪食息。"]'),
('859a5599-2e44-4dde-8c70-4bc370780141','三用韻  其四','何夢桂','宋','宋诗','song-poetry','','[]','何年鑄銅柱，請爲問伏波。',96,'全唐诗/poet.song.234000.json','["何年鑄銅柱，請爲問伏波。", "薊子去不遠，金狄誰再摩。", "世變落莽渺，吾意成蹉跎。", "盜跖飫肝膾，孔聖厄絃歌。", "禍福吾欲問，當世無史鮀。", "問天天匪高，祇恐民聽訛。", "形骸天委質，性命天委和。", "吾固聞諸天，如何復如何。"]'),
('b30d5eac-aa51-4b4f-84c2-2a65008cf355','用姪煒之山行韻','何夢桂','宋','宋诗','song-poetry','','[]','惜花急晨遊，起坐旦未達。',72,'全唐诗/poet.song.234000.json','["惜花急晨遊，起坐旦未達。", "騎馬去踏花，朝雨馬蹄滑。", "落花委塵泥，花香在羅襪。", "猗蘭覓餘春，牡丹遲未發。", "遊子何時歸，使我幽憤豁。", "目斷回雁書，遥遥楚天闊。"]'),
('27dd8136-b136-41e8-a933-cfff986bcfeb','誡子','何夢桂','宋','宋诗','song-poetry','','[]','魯語誨時習，商書稱時敏。',264,'全唐诗/poet.song.234000.json','["魯語誨時習，商書稱時敏。", "一字該二義，學者盍重省。", "又日新其德，成湯常自儆。", "三月不違仁，顔子獨深領。", "今日或因循，明日澡即新。", "前月或斷續，此月復即仁。", "聖賢惜分陰，於此猶兢兢。", "學者能用力，其名曰競辰。", "人有一大時，一去不復仍。", "十五入大學，明德與新民。", "二十曰弱冠，既冠責成人。", "勤怠只數年，賢愚係終身。", "過此爲失時，人不再青春。", "譬之農力穡，春耕而夏耘。", "耕耘苟失時，無復望秋成。", "父母上俱存，兄弟下無故。", "飽食無用心，白日任虛度。", "幼壯老復至，一朝忽反顧。", "對人語不了，握筆書輒誤。", "龍鱗映犬豕，面目可憎惡。", "哀哉復哀哉，追悔已遲暮。", "及此尚可圖，勉旃須早悟。"]'),
('95fcf74c-4fd5-4203-82cb-72c393d8c8a7','題林同舍初心詩集','何夢桂','宋','宋诗','song-poetry','','[]','與君別一世，忽見疑夢境。',48,'全唐诗/poet.song.234000.json','["與君別一世，忽見疑夢境。", "感往雙淚懸，華髮各垂領。", "青燈對白酒，相勖敦暮景。", "別後詩逾佳，朗歌竟夜永。"]'),
('6da8becc-c3b3-420d-b744-fc24a2c19dd4','贈徐教諭愛蘭','何夢桂','宋','宋诗','song-poetry','','[]','朝采水中芹，莫采水中茆。',120,'全唐诗/poet.song.234000.json','["朝采水中芹，莫采水中茆。", "采采不盈掬，意不在寸草。", "顧瞻爾子衿，憂思鬰中抱。", "濯江暴秋陽，豈不日杲杲。", "杲杲雖麗天，寒荄易枯槁。", "君來升文堂，鐘鼓試擊考。", "轟霆起羣蟄，沈淖頼雪澡。", "以中養不中，寬慈以爲寶。", "惟皇均降衷，三代此直道。", "迪教敦民彝，端拜謝師造。"]'),
('4daa7e39-0d48-4f13-940c-215cac1b768a','贈天台遇仙翁','何夢桂','宋','宋诗','song-poetry','','[]','天台華頂飛丹霞，飛梁絕壁仙人家。',237,'全唐诗/poet.song.234000.json','["天台華頂飛丹霞，飛梁絕壁仙人家。", "劉郎歸去不復返，千年藥徑生蠙蛙。", "老翁家住山谷口，入山往往逢青華。", "授之長生不死藥，山頭采采札與砂。", "煉養火鼎成黄芽，日虀蔓菁飯胡麻。", "方瞳丹頰生鼎花，猶爲人世憂龍蛇。", "下遊汗漫周八遐，手持藥管青牛車。", "更資易數餘齒牙，占步禍福百不差。", "朅來訪我一舍蝸，劇談世事長吁嗟。", "我語君，君試聽，勸君不用六十四卦推天星。", "但願得君肘後之丹經，普度百萬億生靈。", "君不見安期生、李少君，一匕神樓生羽翎。", "入無間，升蒼冥。", "造物雖有數，不能囿無形。", "人人絕粒餐瓊英，免墮巔崖受苦辛。"]'),
('885aec6b-07a2-431b-acc4-01eb92f9146a','和寄可庵盧教諭','何夢桂','宋','宋诗','song-poetry','','[]','平生浪說齊諧志，杞國有天驚墮地。',383,'全唐诗/poet.song.234000.json','["平生浪說齊諧志，杞國有天驚墮地。", "不周摧折天柱傾，咄咄古今真怪事。", "元氣不死橋運興，千古日月長懸奔。", "照見可庵一片心脾真硉兀，揮斥八極游天根。", "兩眼癡蟇不能食，坐觀蝡動自形色。", "獨吸泠風飲沆瀣，去向南溟六月息。", "不學神仙慕安期，陶潛曠達其庶幾。", "卜築前窀從與老，太行世路從顛危。", "桓魋石槨嘻未達，昭陵玉匣荒丘垤。", "東門樹檟四時青，獨對青山問明月。", "孤山梅，逋仙一去喚不回。", "三逕竹，空懷二仲人如玉。", "處士松，世無鄭老遺高風。", "何如及今收拾千岩萬壑秀，飛廉道前豐隆後。", "美人服薜带女蘿，自起傞傞舞長袖。", "得時爲鳴鳳，失時爲卧龍，且問君王乞三峰。", "百年三萬六千日，倏忽起滅天際虹。", "散髮披襟任坦率，時澆磊磈斟寒碧。", "眼高一世四海空，婢膝奴顔死人役。", "君不見烏棲曲、白紵歌，長繩不繫白日梭，時耶命耶將奈何。", "前有香山翁，後有洛陽老。", "嘉會不數逢，千載誰復道。", "蛟翁此來遊，三珠烱相照。", "憑誰畫作五老圖，著我坐隅添一笑。"]'),
('bbafba54-85bb-499e-b95e-b61e32f94e23','贈徐霞錦','何夢桂','宋','宋诗','song-poetry','','[]','昔日山陰老魏仙，丹成飛去三千年。',184,'全唐诗/poet.song.234000.json','["昔日山陰老魏仙，丹成飛去三千年。", "倒影滅沒不可得，誰駕玉犬驂雲駢。", "當年從事君家祖，獨向爐邊得丹譜。", "刀圭入口羽翰生，至今去作羣仙父。", "丹砂散地無人收，聚作丹霞如錦毬。", "騰騰五采狎獵起，夜半精光衝斗牛。", "問君從事適孫子，渾家住坐丹霞裏。", "夜窺璇璣落星躔，晝負丹囊踏山水。", "有時賣易掛白錢，醉卧圯橋墮雙履。", "問君何事落人間，謫業已盡當復還。", "人間處處風雨惡，不如歸去蓬萊山。", "山上朝霞猶可餐。"]'),
('ef100d92-abd9-430a-987e-26dc0f318fb8','汾陽徐祥英還家','何夢桂','宋','宋诗','song-poetry','','[]','君不見當年原上武陵家，有人隨水覓桃花。',134,'全唐诗/poet.song.234000.json','["君不見當年原上武陵家，有人隨水覓桃花。", "桃花未落君歸去，到得重來無覓處。", "又不見石室山中一局棋，有誰採樵不知歸。", "斧柯爛盡俗緣起，歸到人間長孫子。", "君今採藥入山中，一笑相逢樽酒同。", "鳥啼花落隔人世，不知世上誰雌雄。", "令威千年化作鶴，回頭猶念舊城郭。", "城郭雖故人民非，歸去歸去遄高飛。"]'),
('119d5cd3-d71d-4783-93fa-1cfd8b072c15','贈星學葉冰壺','何夢桂','宋','宋诗','song-poetry','','[]','祝融擲火驅六龍，火輪吐焰燒長空。',144,'全唐诗/poet.song.234000.json','["祝融擲火驅六龍，火輪吐焰燒長空。", "彤雲掛樹凝翠歇，九根灼爛紅爐中。", "黑菟喘嘯風不起，紫蛟嗔卧潛幽宮。", "燕然山高倚絕壁，下有凌陰厚千尺。", "阿誰琢雪開瓊花，貯向玉壺寒照骨。", "層冰底下浴蠶蟲，口吐繭絲成五色。", "冰姿入火熱不焦，那識人間爍金石。", "蒼生病暍死道途，左擁右扇喚不甦。", "願化冰蠶作冰繭，上天下地成冰壺。"]'),
('1378804e-f360-4670-aabc-a1832d6c251a','得雨行','何夢桂','宋','宋诗','song-poetry','','[]','萬井泉枯民徙市，誰碾火輪燒海底。',384,'全唐诗/poet.song.234000.json','["萬井泉枯民徙市，誰碾火輪燒海底。", "蛇翳墮甕鞭弗靈，豐隆困卧屏翳死。", "天驅鬼格啄黔氓，神龍蓄雨不敢行。", "萬樹翠乾禾赤熛，田田兆坼龜縱橫。", "卜侯閔雨無處禱，下問三老及五更。", "爲言烏龍有聖水，絕頂一泓如鑑平。", "尋常澍雨多芳沼，頗怪年來雲氣少。", "有時掣電現光怪，或見盤空形攫矯。", "猩鼯藜藿人不經，侯往願乞水一瓶。", "得水入城甫三日，一夕載雨來江亭。", "生來不識此山狀，見說人行躡雲上。", "殷雷下界嬰兒聲，培塿千峰那可望。", "山高地迥生神靈，莫嫌潴水纔盆盎。", "鬃頭一滴落人間，平地鯨鯢生巨浪。", "世事春花與秋葉，野馬紅塵雲起滅。", "龍山萬古龍常存，年年幻變生鱗鬣。", "歛藏神用潛幽宮，畜眼草草那識龍。", "賢侯異政今魯恭，此心直與神龍通。", "吁嗟疲民隔天日，那值歲祲十六七。", "麥爛蠶死穀復饑，溝壑委填憂旦夕。", "及今雨足稻粱紅，預期一飽吹豳風。", "龍不有功歸我公，公不復有歸太空。", "誰解作頌美形容，發微抉眇聲金舂。", "老我擊壤歌山中，瓣香敬爲曾南豐。"]'),
('f52c5ad3-10a7-4316-b415-b2a71d2f0cec','飯牛歌爲胡子徽作','何夢桂','宋','宋诗','song-poetry','','[]','朝飯牛，飯牛原上草。',197,'全唐诗/poet.song.234000.json','["朝飯牛，飯牛原上草。", "夜飯牛，飯牛霜下藁。", "草香藁軟牛飽肥，黄犢跳梁犍卧噍。", "煙蓑雨笠犢鼻褌，髫齔飯牛今已老。", "有時扣角苦勞碌，人世觸蠻等雙角。", "古今名利成戰場，不似倒騎牛背樂。", "君不見齊甯戚，長夜飯牛歌白石。", "漫漫待旦骭衣單，待旦未明何嗟及。", "又不見百里奚未遇時，未遇飯牛人不知。", "平生爵祿不入心，何故要秦五羊皮。", "老翁牽牛傍流水，水不飲牛寧洗耳。", "入去山中深更深，蘆管一聲千古意。", "乾坤旦暮不曾知，那問人間榮辱事。"]'),
('3fece252-5d6f-4d61-a95c-21366749de05','知盧可菴教諭鼓歌','何夢桂','宋','宋诗','song-poetry','','[]','崇牙樅樅，賁鼓逢逢。',283,'全唐诗/poet.song.234000.json','["崇牙樅樅，賁鼓逢逢。", "始作之以荆衡底貢之新革，試叩之以巴蜀故産之孤桐。", "雷震一聲草木拆，蠖信其屈龍起蟄。", "天地訢合萬物蘇，陽氣宣聲陰屏迹。", "矇瞍一鼓歌辟雍，始與斯民發童蒙。", "大胥再鼓徵學士，復與學者開天聰。", "當其俎豆前陳，甫掖山立。", "綴兆序位，登降終日。", "吾故鼓之以相禮，所以作爾之强力。", "乃若冠蓋孔孟，佩服程朱。", "鷄鳴而起，亦步亦趨。", "吾故鼓之以戒晨，所以覺爾之迷途。", "至若理欲昏明，義利白黑。", "夕惕不謹，日省何益。", "吾故鼓之以謹昏，所以使爾非心之必斥。", "嗚呼，鼓人職廢周禮湮，方叔入漢鼓收聲。", "舉世聵聵呼不應，千載孔堂絲竹音。", "鏜然一鼓驚雷霆，撼動天地衆耳醒。", "昌黎老死石鼓裂，愧我才薄爭奈此鼓文。"]'),
('b056ca8f-397a-4162-94f4-5d86ed756d1c','蛟龍歌','何夢桂','宋','宋诗','song-poetry','','[]','生物具角齒，每每與物抗。',192,'全唐诗/poet.song.234000.json','["生物具角齒，每每與物抗。", "蹈阱虎以剛，觸籓羊以壯。", "世間怪物有蛟龍，三百六十蟲之長。", "神靈出噓吸，變化互來往。", "布爪層雲興，鼓鬐歘電放。", "無欲不受劉累馴，假形豈被葉公誑。", "時飛則飛潛則潛，所以隨時知得喪。", "莫道魚蝦性不靈，相依喣沫豈敢嗔。", "江濆鱣鯨久失水，聞此鼓舞咸相親。", "世無刑醢受，時非法網秦。", "然匪藉餘蔭，安能逃世人。", "亡象齒與革，亡猩血與脣。", "有身即有患，誰能無其身。", "安得此身化爲雲，隨龍上下雲無心。"]'),
('e0f358ac-3355-421c-a222-566f64468ffa','希有鳥吟','何夢桂','宋','宋诗','song-poetry','','[]','穹壤紛衆羽，固有仁不仁。',180,'全唐诗/poet.song.234000.json','["穹壤紛衆羽，固有仁不仁。", "鴞鳳雖異性，同爲陰陽根。", "惟彼希有鳥，於禽集大成。", "力可振海嶽，翂翐似無能。", "鯤鵬侈變化，比予爾何曾。", "羣鷇偃下風，舉受翼卵恩。", "萬里不足飛，千載始一鳴。", "遠之不可疏，即之不可親。", "地維缺不震，天柱拆不驚。", "安得以寵辱，而能累其身。", "世固有大物，天地間氣生。", "卑卑局耳目，夫誰識其真。", "道大固難同，安能抗世情。", "何如任毀譽，徜然忘我人。", "不諧衆人口，而諧萬世心。"]'),
('a3fe14ba-888a-4616-9ee9-b2a66b103ed1','愚石歌','何夢桂','宋','宋诗','song-poetry','','[]','大塊初分生怪石，曾與不周山作骨。',304,'全唐诗/poet.song.234000.json','["大塊初分生怪石，曾與不周山作骨。", "山崩地缺天柱摧，片石耆姿轉奇崛。", "媧皇煉石補天工，化作五星成五色。", "地下爲石天上星，頑質變化生神靈。", "一朝天狼齧蝕五星隕，隕石宋野猶有光晶熒。", "何人夜負入海嶼，錯雜昆吾無覓處。", "中間塊石獨𡼭嶔，住在錦溪溪上滸。", "石潤可以硯，石文可以屏。", "贔屭或刳鼎，廉栗或劖銘。", "不然雲母與紫英，否則丹砂和空青。", "爾材於用百不適，空有千尺高稜層。", "暴流沒馬不加減，霜降石出不加增。", "火不焦，水不凝。", "刻桐扣不鳴，飲羽射不驚。", "世間至智不能化，而我安敢逃愚名。", "人聞愚惡聞智喜，君謂我愚真知己。", "築室招子願結交，更請柳溪作愚記。", "我笑己愚君更愚，世有兩愚適相值。", "江流東去夕陽西，千古相看只如此。", "當年三品不點頭，况被旁人鞭得起。"]'),
('2e4c2aed-2751-4d97-b676-d97b05209e19','芸窗集畫圖','何夢桂','宋','宋诗','song-poetry','','[]','天馬不生韓幹死，崔白翎毛落蒿里。',192,'全唐诗/poet.song.234000.json','["天馬不生韓幹死，崔白翎毛落蒿里。", "虎頭妙筆夜通靈，主爵郎中羞畫史。", "楊君畫眼空四海，剩把金奩貯奇詭。", "榆關牧馬邊草秋，一騎一縱驊與騮。", "阿誰青驄嚼金勒，拔劍奔逐髯怒虬。", "提弓空捍鳴鏑盡，塵沙馬耳風颼颼。", "篔簹谷中一梢出，冷蕊相看冰雪骨。", "葵花二色空爭妍，沒骨丹青翰水墨。", "猿猱兩兩雄顧雌，獐鼠伎伎母趁兒。", "水禽並下照秋水，足踏枯荷浸蓮漪。", "人間清景能幾許，野馬戰場祇尺咫。", "芸窗一幅水沉烟，俛仰乾坤千古意。"]'),
('99da102c-577a-43fc-86ca-61508e8a628a','贈梅谷高士','何夢桂','宋','宋诗','song-poetry','','[]','去年無方老瞿曇，授我雲門一劄禪。',176,'全唐诗/poet.song.234000.json','["去年無方老瞿曇，授我雲門一劄禪。", "今年羽衣梅谷仙，丹法葛翁口談玄。", "無方是兄仲梅谷，誤墮凡胎投母腹。", "豈非江郎三石人，兩石飛來化雙玉。", "君今一字透鋒機，札斷三關鬼莫窺。", "掇取玄珠入蓬闕，自携靈母養嬰兒。", "寒山梨棗霜中熟，碧蓮池邊結茅屋。", "蛾眉白髮兩瀟疎，夜抱寒蟾成獨宿。", "相逢丹鼎問金砂，笑灌玉泉餐紫霞。", "崑崙瑶樹渺何許，遼海白鶴還歸家。", "歸去無方問何其，爲說此行奇更奇。"]'),
('4dfa0374-32c5-4016-b9e8-5080cccc1e16','和南山弟虎圖行','何夢桂','宋','宋诗','song-poetry','','[]','高堂突兀生崇岡，於菟眼電牙磨霜。',160,'全唐诗/poet.song.234000.json','["高堂突兀生崇岡，於菟眼電牙磨霜。", "古言市虎人不信，誰信挾一來座傍。", "衆犬僵仆兒輩走，猛士腰弩成蹶張。", "老翁卒見亦驚怪，便欲騎取參西皇。", "乾坤戾氣産尤物，誰爲驅雷入神筆。", "古樹蕭蕭風刁刁，陰崖幽幽雲墨墨。", "橫行屭贔不畏人，弄子庭除成穴窟。", "藍田飲羽驚夜行，今乃捋鬚當白日。", "畫圖畫虎心自知，觸目或疑猶喘息。", "世間多少涪村民，毛爪未完心已易。"]'),
('13db3fc8-7a6e-4444-9dc7-43a622b50c6b','贈方雲卿地理','何夢桂','宋','宋诗','song-poetry','','[]','金仙頂門一隻眼，五眼通神識無限。',148,'全唐诗/poet.song.234000.json','["金仙頂門一隻眼，五眼通神識無限。", "雲卿留得眼一隻，眼力最高人不識。", "眼裏青囊一卷經，照破山川無遁形。", "口談禍福句句驗，人謂先生真鬼靈。", "自言好眼與人別，當年點得白龜睛上血。", "龜存雙眼我雙眼，兩眼精明光電掣。", "有時採珠撼龍宮，有時捋鬚探虎穴。", "獨眼獨眼真地仙，一角靈犀妙莫傳。", "誰知一眼二眼化千眼，笑殺時師空眼穿。"]'),
('5f9546a6-86df-48bf-bf39-198fc818f70b','觀慈烏反哺','何夢桂','宋','宋诗','song-poetry','','[]','有鳥有鳥名慈烏，羣兒啞啞爭相呼。',160,'全唐诗/poet.song.234000.json','["有鳥有鳥名慈烏，羣兒啞啞爭相呼。", "羽毛甫集思反哺，爲報父母恩勞劬。", "民彝天理久淪斁，聞此肝膽爲昭蘇。", "禽蟲微物豈知義，烏性至孝由中孚。", "梟獍雛成軀爲裂，伯勞雛長肉已刳。", "天地生物無不仁，何至善惡相懸殊。", "禽中孝子爾烏是，世上逆子彼二雛。", "父母愛子恩罔極，子心能似父母無。", "人生誰實空桑出，爲感物類長嗟吁。", "嗟吁不足日云暮，老烏抱雛宿夜樹。"]'),
('503e0802-b04e-4f2f-aa63-f55a049e70d3','贈秋蓬王相士','何夢桂','宋','宋诗','song-poetry','','[]','秋蓬秋蓬，我不願爵三公，亦不願祿萬鍾。',83,'全唐诗/poet.song.234000.json','["秋蓬秋蓬，我不願爵三公，亦不願祿萬鍾。", "君謨骨相祇如此，休向蓬州問李翁。", "迂叟病齒落半空，豈是天食蛙骨蟲。", "但願壺中乞方匕，齒髮復出還嬰童。", "潄石清溪歌九曲，飽飯黄精羹杞菊。"]'),
('4da54582-9e8c-45c9-ae2c-20cc4670fd44','有客曰孤梅訪予於易庵孤山之下與之坐夜未半孤月在天笑謂孤梅曰維此山與月與子是三孤者爲不孤矣因相與釃酒更誦逋仙疏影暗香之句聲滿天地酒酣又從而歌之歌曰','何夢桂','宋','宋诗','song-poetry','','[]','蹇西山之孤竹兮，商周二君。',136,'全唐诗/poet.song.234000.json','["蹇西山之孤竹兮，商周二君。", "藐三徑之孤松兮，晉宋一人。", "天地冰霜兮，木落歸根。", "遺萬物而獨立兮，吾梅兄其僅存。", "夫孤高不易抗兮，故多以落落而遭世之悶悶。", "孤潔不易保兮，故多以皎皎而受人之昏昏。", "惟湼而不緇兮，梅質之清。", "磨而不磷兮，梅操之貞。", "嗟梅之愛兮，曠世無聞。", "將梅有心兮，千古誰論。"]'),
('2b194e0f-440d-4a91-b307-9d927d7d1de8','昨日王德父何昭德回後曝背于庵後大山上甚樂因成數語效大山體亦皆寫景聊以寄似','何夢桂','宋','宋诗','song-poetry','','[]','碧旻收雲兮，秋氣肅清。',153,'全唐诗/poet.song.234000.json','["碧旻收雲兮，秋氣肅清。", "萬籟聲沉兮，秋日晶熒。", "青山崟崟兮，白石瑛瑛。", "麋鹿跂跂兮出高陵，野鳥活活兮兩岑對鳴。", "黄犍濕濕兮逐羝羣，或訛或寢兮于野于坰。", "吾忘吾獨兮，吾與禽獸兮爲鄰。", "違市朝兮不與世攖，利名不入兮寵辱忘驚。", "聊遺吾形兮放吾情，美背曝兮不可以遺君。", "時分吾席坐兮，採樵負苓。", "吾其徜徉乎此山以終吾生兮，其樂無央。"]'),
('bab9e343-9c7b-4da9-a382-17d431fc7b5d','逐婦吟','何夢桂','宋','宋诗','song-poetry','','[]','妾生不辰兮命孤奇，妾嫁夫君兮尚髫垂。',68,'全唐诗/poet.song.234000.json','["妾生不辰兮命孤奇，妾嫁夫君兮尚髫垂。", "被讒放逐兮，妾不復歸。", "欲出門兮，心重悲。", "心重悲，非別離。", "夫與姑，命相依。", "願姑謹携持，山有豺狼水有螭。"]'),
('caa7a7d4-8f27-4c9f-b549-b5bf65d87b47','偶書塔塢水中石','何夢桂','宋','宋诗','song-poetry','','[]','白石兮磷磷，清泉兮泠泠。',105,'全唐诗/poet.song.234000.json','["白石兮磷磷，清泉兮泠泠。", "岸有蒲兮水有芹。", "敲竹筇兮金石聲，長嘯歌兮驚鬼神。", "世間豈無宦海之可航，仕路之可騁兮，不如此壑之安且平。", "魚自泳兮鳥自鳴，花自開兮木自榮。", "任我心兮流水，等世事兮浮萍。", "上下天地兮，吾併忘乎吾身。"]'),
('5c5bd309-7b31-483b-a22d-a84bbd38db57','和蛟峰先生熟睡吟','何夢桂','宋','宋诗','song-poetry','','[]','幕蒼天，席大地，睡去不知人世事。',144,'全唐诗/poet.song.234000.json','["幕蒼天，席大地，睡去不知人世事。", "覺來榻上總埃塵，口不能言睡中義。", "古今萬事晝夜同，萬八千年祇一寐。", "榮辱事，真夢裏，黄粱一枕邯鄲市。", "北窗謾說晉朝臣，周公不見吾衰矣。", "日高丈五閉柴門，不知身世華胥氏。", "不氈不被老希夷，山上白雲霞流水。", "得失事，真夢裏，鹿蕉翻覆終成戲。", "人言夜半息如雷，我縱行行還美睡。"]'),
('5e93da4a-8785-4a44-97c4-2eeaa7cff94d','和仙詩友鶴吟','何夢桂','宋','宋诗','song-poetry','','[]','當年隻鶴揚州去，羽衣虹裳滅烟霧。',152,'全唐诗/poet.song.234000.json','["當年隻鶴揚州去，羽衣虹裳滅烟霧。", "千年華表不歸來，來時忘却邯鄲路。", "短篷月白起酸風，天陰鬼哭戰場空。", "黄昏欲望城西東，亂山青處白雲中。", "誰解歌離騷，我自斟酌酒。", "一醉醉百年，無夢到浙右。", "插我羽翼兩臂間，頂丹蛻盡毛骨凡。", "下天上天隨君去，不與人世同悲歡。", "星星有語說未已，夕陽西去東流水。", "一聲嘹唳入蒼冥，青塚纍纍呼不起。"]'),
('3dcaf88a-0005-44f0-88c1-33bd703b30af','鵑啼曲','何夢桂','宋','宋诗','song-poetry','','[]','蠶叢鱉靈兩丘土，玉壘靈關一荒莽。',160,'全唐诗/poet.song.234000.json','["蠶叢鱉靈兩丘土，玉壘靈關一荒莽。", "杜鵑銜哀訴千古，萬里遊魂腥血污。", "冤聲無路叫天公，吻血洒地花爲紅。", "巴江東下流無極，目斷巴山歸不得。", "此身豈是無羽翰，天梯石棧雲漫漫。", "落花冉冉江城暮，年年客夢鄉關路。", "丈夫志氣笑沐猴，安知狐死還首丘。", "沛公擊筑歌湯沐，錢王錦衣衣林木。", "寄巢生子傍他誰，衆鳥雖憐祇自悲。", "哀號力盡飛不歸，老盡遺民城郭非。"]'),
('1a4591f1-c785-4739-9cf0-bea59b71086e','贈地理錢季實','何夢桂','宋','宋诗','song-poetry','','[]','神仙地理無多訣，未用尋龍先看峽。',384,'全唐诗/poet.song.234000.json','["神仙地理無多訣，未用尋龍先看峽。", "次看峽內有明堂，外峽內堂垣氣結。", "交結深時垣氣牢，交結淺時垣氣洩。", "回看遠障起星峰，認得星峰是祖宗。", "祖宗派下分嫡庶，庶是旁枝嫡正龍。", "足趾未曾登絕頂，如何辨認嫡庶蹤。", "庶是旁枝爲外從，嫡子必居堂奧中。", "此是大法論嫡庶，未是窮源尋極致。", "眼前大法既能明，更看嫡枝辨臧否。", "譬如人家有嫡兒，或賢或否不易知。", "賢者起家不肖敗，嫡枝還更有妍媸。", "到此須是牢著眼，切莫泥取嫡謂奇。", "龍到成形方結穴，若不成形總虛設。", "傾欹破碎縮腫粗，雜亂擺竄瘦死絕。", "凡屬此類不勞看，認得正龍成醜拙。", "認形既真穴亦真，真形真穴自天成。", "左右必有真纏護，真案真朝無異情。", "地真氣象自然別，山必綢繆水迴折。", "葱葱鬰鬰日回環，入眼精神俱煥發。", "設從流派問源頭，定是祖宗真骨血。", "雖然龍真穴自真，或隠或顯多誤人。", "正結人人能識得，不識偏頗閃側情。", "地有怪穴無怪局，認局方知穴法精。", "毫釐之繆隔千里，萬水千山差一指。"]'),
('8c50e967-b569-406e-b0e8-e185f06eaa74','山房約會於黄灘別後寄似','何夢桂','宋','宋诗','song-poetry','','[]','玉堂佳人珮瓊英，月下乍見心眼明。',64,'全唐诗/poet.song.234000.json','["玉堂佳人珮瓊英，月下乍見心眼明。", "貞心野雪壓不死，幽韻天風吹逾清。", "玉龍聲高夜漏下，綠衣舞短天雞鳴。", "歲寒一見苦易別，安得白頭敦弟兄。"]'),
('867c6f1b-61eb-4e3a-bc9d-ada092f1fd83','和張按察秋山二首 賦杭州','何夢桂','宋','宋诗','song-poetry','','[]','三百餘年卧甲兵，天低雨露此生成。',64,'全唐诗/poet.song.234000.json','["三百餘年卧甲兵，天低雨露此生成。", "萬家都會樓臺矗，千頃平湖舸艦輕。", "環珮玉堂人楚楚，靚妝珠箔女盈盈。", "回頭萬事俱塵土，惟有湖痕歲歲平。"]'),
('5776e268-c3d9-4e50-afbd-f0b67b3758dd','和張按察秋山二首 賦孤山','何夢桂','宋','宋诗','song-poetry','','[]','錢塘日夜水東流，回首孤山綠尚稠。',64,'全唐诗/poet.song.234000.json','["錢塘日夜水東流，回首孤山綠尚稠。", "千載老仙隨鶴去，百年此地少人遊。", "相逢柳色還青眼，說着梅花總白頭。", "身後閒名推不去，當年誤識薛杭州。"]'),
('aaad2e34-96f6-49b7-bed1-ca1b3d30c333','見田察使','何夢桂','宋','宋诗','song-poetry','','[]','玉節星軺御史冠，邦人多少路旁觀。',64,'全唐诗/poet.song.234000.json','["玉節星軺御史冠，邦人多少路旁觀。", "半空寒月千峰榭，一歃清泉七里灘。", "天地鳶魚春鼓舞，山林雞犬夜平安。", "好須借得長年住，截斷車輪挽珮珊。"]'),
('65a4b534-cee7-4ec9-8171-ca4d4c67f3de','贈馮樵隠琴棋','何夢桂','宋','宋诗','song-poetry','','[]','紋楸漫滅㸑桐焦，贏得無何醉濁醪。',64,'全唐诗/poet.song.234000.json','["紋楸漫滅㸑桐焦，贏得無何醉濁醪。", "別墅功隨淮上水，廣陵人化里中蒿。", "知音那似無絃好，當局何如不著高。", "尋取舊樵歸隠處，坐看塵世戲兒曹。"]'),
('b910d7cd-4d76-41b5-a178-03f6849fa434','寄王南叟寓江鄉','何夢桂','宋','宋诗','song-poetry','','[]','歌盡驪駒落日寒，相思無處問平安。',64,'全唐诗/poet.song.234000.json','["歌盡驪駒落日寒，相思無處問平安。", "客愁白髮三千丈，世路青泥百八盤。", "夜月梅花頻入夢，秋風菰米强加餐。", "高山如故絲絃在，懶向旁人取次彈。"]'),
('cf261053-e985-4439-82f7-fb1452da4c7c','挽勁軒鄭府理','何夢桂','宋','宋诗','song-poetry','','[]','東林冠蓋舊耆英，百尺豐碑誌墓塋。',64,'全唐诗/poet.song.234000.json','["東林冠蓋舊耆英，百尺豐碑誌墓塋。", "經濟志高官職小，睦姻義重貨財輕。", "永平倉下遺紅粟，仁壽堂前有紫荆。", "夜半山舟誰負去，蓋棺猶是昔簪纓。"]'),
('1da9af23-13c8-4c67-9bfc-c368247b5f91','燈夕樂舞','何夢桂','宋','宋诗','song-poetry','','[]','天碧星河欲下來，東風吹月上樓臺。',64,'全唐诗/poet.song.234000.json','["天碧星河欲下來，東風吹月上樓臺。", "玉梅雪柳千家閙，火樹銀花十里開。", "紫鳳笙繁聲曼衍，黄龍舞縵影徘徊。", "香車匝地紅塵軟，莫遣銅壺漏箭催。"]'),
('4d51a0c7-a900-4cd8-bd59-ce020e84203f','餞竹所叔赴慶元征官和韻','何夢桂','宋','宋诗','song-poetry','','[]','正好山中賦草堂，老龍誰喚起南陽。',64,'全唐诗/poet.song.234000.json','["正好山中賦草堂，老龍誰喚起南陽。", "青衫華髮劍三尺，白犬丹雞酒一觴。", "塵世功名蕉下鹿，半生爵祿夢中羊。", "年來處處波濤險，莫趁風帆上海艎。"]'),
('874e16b0-8604-4ac0-b711-6ae0ce41978f','寄王提舉','何夢桂','宋','宋诗','song-poetry','','[]','地到偏方苦雪霜，蒼生寒谷望春陽。',64,'全唐诗/poet.song.234000.json','["地到偏方苦雪霜，蒼生寒谷望春陽。", "一麾使節來天上，萬口行碑在路傍。", "里役莊成民弛擔，關征法簡旅行糧。", "祇今騎鶴揚州去，剩得新詩富錦囊。"]'),
('b33856b0-bf98-4822-9b01-8722135d91ad','答楊冰崖寄韻問注西銘','何夢桂','宋','宋诗','song-poetry','','[]','勘破西銘識本真，添來注脚又重新。',64,'全唐诗/poet.song.234000.json','["勘破西銘識本真，添來注脚又重新。", "父天母地元同體，物與民胞總是春。", "放蕩異端黄老佛，紛爭戰國楚齊秦。", "要知俯仰皆無愧，請向聖賢求事親。"]'),
('8596076b-59fe-46ab-a449-46b585452558','邑庠杏壇初成諸老倡和見寄因次韻','何夢桂','宋','宋诗','song-poetry','','[]','雙杏壇前花自春，登壇宛見仲尼心。',64,'全唐诗/poet.song.234000.json','["雙杏壇前花自春，登壇宛見仲尼心。", "千年此樹幾寒暑，一綫生機無古今。", "西狩事非成反袂，緇林曲在尚鳴琴。", "閒花滿地乾坤老，三嘆遺風感慨深。"]'),
('5e71e6bb-dad6-482b-8ea9-d30ece6c96b4','和宋英叟先塋建亭作','何夢桂','宋','宋诗','song-poetry','','[]','誰表新阡瞰石關，要將孝義軌人寰。',64,'全唐诗/poet.song.234000.json','["誰表新阡瞰石關，要將孝義軌人寰。", "千年永宅歸元亮，百尺豐碑葬魯山。", "旌旐尚存青檟外，亭臺半在白雲間。", "兒孫自是驊騮種，早入君王十二閑。"]'),
('5a2c0e71-dd86-48b5-91e4-55cb8e7625c8','和宋英叟二首  其一','何夢桂','宋','宋诗','song-poetry','','[]','圯上編書未出奇，有來相問重相規。',64,'全唐诗/poet.song.234000.json','["圯上編書未出奇，有來相問重相規。", "桑蓬自笑平生志，泡露誰能萬世基。", "閒去带鉏編露朮，醉來呼酒賦江蘺。", "青門待得瓜成熟，不似西山老伯夷。"]'),
('6ce1e036-b500-4336-b12b-d3a6cd4d0f8b','和宋英叟二首  其二','何夢桂','宋','宋诗','song-poetry','','[]','不堪血淚望長陵，回首松楸又幾春。',64,'全唐诗/poet.song.234000.json','["不堪血淚望長陵，回首松楸又幾春。", "荒壠牛眠何處是，古經狐首僞邪真。", "固知遷墓疑非禮，幸有周棺可芘身。", "若向防丘逢孔父，尚遺馬鬣詔今人。"]'),
('d118725e-23e0-4dfc-ac0c-54d5ca6165fc','徐仲修寄詩次韻','何夢桂','宋','宋诗','song-poetry','','[]','一枕邯鄲午夢醒，好風吹信入軒櫺。',64,'全唐诗/poet.song.234000.json','["一枕邯鄲午夢醒，好風吹信入軒櫺。", "溟摶六月鵬先化，胎孕千年鶴已靈。", "氣囿陰陽元有數，道超天地妙無形。", "何時共作緱山隠，滴露松蘿寫易經。"]'),
('e56c920a-1e11-44a3-b55d-95ec1db3e33e','贈尹巽齋易數','何夢桂','宋','宋诗','song-poetry','','[]','萬有滋荄隠混蒙，誰開玄竅洩神工。',64,'全唐诗/poet.song.234000.json','["萬有滋荄隠混蒙，誰開玄竅洩神工。", "易經四聖羲周孔，數貫三天先後中。", "執筴不須談管輅，太玄休復問揚雄。", "只今風起從何入，知得風來是巽翁。"]'),
('28f590e5-f514-4a0d-bea3-7869a9d92eda','高縣丞不負堂詩','何夢桂','宋','宋诗','song-poetry','','[]','閑丞八品一官卑，許贊男邦問便宜。',64,'全唐诗/poet.song.234000.json','["閑丞八品一官卑，許贊男邦問便宜。", "議論是非晴雨異，刑囚出入重輕疑。", "案頭涉筆余心愧，松下哦詩官事隳。", "丞得君來真不負，祇應百姓與天知。"]'),
('0f8ee0ed-5d3b-41ee-9d28-ef38d3aeba31','寄夾谷書隠  其一','何夢桂','宋','宋诗','song-poetry','','[]','巔崖一落費攀躋，汲綆千尋重挈提。',64,'全唐诗/poet.song.234000.json','["巔崖一落費攀躋，汲綆千尋重挈提。", "往事雪中鴻印迹，舊恩堂上燕銜泥。", "錢塘東去江濤遠，銀漢西流斗柄低。", "天地秋風黄葉老，年年春在故桃溪。"]'),
('340c27aa-2de8-4402-ae65-3d6be01a3f3b','寄夾谷書隠  其二','何夢桂','宋','宋诗','song-poetry','','[]','當年曾憶賦高唐，回首邯鄲事渺茫。',64,'全唐诗/poet.song.234000.json','["當年曾憶賦高唐，回首邯鄲事渺茫。", "黄閣故人千里月，青山老我半頭霜。", "交情脈脈園中柳，憂思悠悠陌上桑。", "吹斷參差天欲暮，薄言蘭芷寄衡湘。"]'),
('de75ace3-1289-4422-9280-8cd05f7eff70','九日偕府城諸貴人遊南山寺分韻和杜工部九日詩','何夢桂','宋','宋诗','song-poetry','','[]','飯山吟瘦带圍寬，過得秋來一日歡。',64,'全唐诗/poet.song.234000.json','["飯山吟瘦带圍寬，過得秋來一日歡。", "謾道高風憐破帽，還應衰髮戀南冠。", "黄花幾度今人老，藍水千年時夢寒。", "日暮歸來成醉倒，南山風雨不堪看。"]'),
('1d685698-4fe2-45ae-a907-08a59e71e139','有感寄唐月心','何夢桂','宋','宋诗','song-poetry','','[]','日暮佳人雪滿簪，不堪重聽楚騷吟。',64,'全唐诗/poet.song.234000.json','["日暮佳人雪滿簪，不堪重聽楚騷吟。", "游豚吹浪江風惡，穴蟻坯封山雨深。", "遯世敢談枰外著，濟時空抱夢中心。", "閒花滿地將軍老，莫向東風更鼓琴。"]'),
('91a2242f-5066-4107-8bd9-bbd4cad6767e','賀徐提管可大得子','何夢桂','宋','宋诗','song-poetry','','[]','四十生兒得寧馨，試教啼看是真英。',64,'全唐诗/poet.song.234000.json','["四十生兒得寧馨，試教啼看是真英。", "五文鳳自雲間落，一角麟從天上生。", "積善家應長孫子，讀書種定作公卿。", "他年大耋還推子，謾道同年我是兄。"]'),
('4d4d41f7-5333-4237-8d63-0f9c3657fcad','餞何君元赴汾陽儒諭','何夢桂','宋','宋诗','song-poetry','','[]','雪月堂前冷掾廳，况如此邑甚於冰。',64,'全唐诗/poet.song.234000.json','["雪月堂前冷掾廳，况如此邑甚於冰。", "行移太白西邊次，去占高青最上層。", "氈冷不然官舍燭，俸凉自糴太倉升。", "詩書莫道同芻狗，尚見宮牆踐豆登。"]'),
('9907f1a9-ed60-4e59-a558-024626c708fd','上張察使老山  其一','何夢桂','宋','宋诗','song-poetry','','[]','元是公侯孝友門，及今幾代見礽孫。',64,'全唐诗/poet.song.234000.json','["元是公侯孝友門，及今幾代見礽孫。", "便遺柱下持天憲，暫住都亭洗物冤。", "花影月邊吟子野，木從窗外訪南軒。", "漢庭羽翼須良計，誰是商山老綺園。"]'),
('d34487e4-100d-4863-836e-321ac21e23d8','上張察使老山  其二','何夢桂','宋','宋诗','song-poetry','','[]','玉節星軺浙水邊，好將疾苦問愚黔。',64,'全唐诗/poet.song.234000.json','["玉節星軺浙水邊，好將疾苦問愚黔。", "十羊九牧鞭俱斃，一鼠羣鴞肉未饜。", "地處覆盆遮日月，天教持斧拯閭閻。", "吳山不逐行人老，留取勳名衆具瞻。"]'),
('d41cd72a-ee1f-4268-864f-61f666227eaa','賡曾省齋舊題鳳翔空壁','何夢桂','宋','宋诗','song-poetry','','[]','滄溟陵陸起黄埃，薦福碑驚半夜雷。',64,'全唐诗/poet.song.234000.json','["滄溟陵陸起黄埃，薦福碑驚半夜雷。", "玄鶴歸遲生墓草，白鷗飛盡上磯苔。", "寒泉辱井留脂水，黑土夷陵出燼灰。", "往事興亡渾一夢，高名千古黨碑魁。"]'),
('fc59b354-a6bd-4a08-8380-6d4e5601b956','寄田察使','何夢桂','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','尊酒長亭憶別離，參差吹斷竟誰思。',64,'全唐诗/poet.song.234000.json','["尊酒長亭憶別離，參差吹斷竟誰思。", "我懷知己慚鬷蔑，公喜逢人說項斯。", "一塢烟霞雙鬢老，數椽風雨二天私。", "錢塘日暮長江闊，薄擷芳馨結桂枝。"]'),
('ea8c24ee-0f66-4d0b-987b-f7ebebbad3a0','山居','何夢桂','宋','宋诗','song-poetry','','[]','短短檐楹小小亭，先生家住綠楊陰。',64,'全唐诗/poet.song.234000.json','["短短檐楹小小亭，先生家住綠楊陰。", "軒前樂意青山色，橋上行人流水心。", "半醉半醒時自舞，獨行獨坐更微吟。", "青鸞有約孤雲外，立盡闌干到夜深。"]'),
('e5230996-002f-4d96-98e5-19f71d65db16','送李縣尹','何夢桂','宋','宋诗','song-poetry','','[]','河陽桃李是誰栽，怕說春歸疊鼓催。',64,'全唐诗/poet.song.234000.json','["河陽桃李是誰栽，怕說春歸疊鼓催。", "正好鳴琴看錦水，俄驚飛誥下金臺。", "一堤烟柳離亭路，兩岸風花送客杯。", "百里桑麻正生意，爲言來者好栽培。"]'),
('47cfb8ae-3a01-4ac6-b9bf-09000d867064','和方耜岩見寄','何夢桂','宋','宋诗','song-poetry','','[]','世事興亡轉脚跟，長安處處戰場塵。',64,'全唐诗/poet.song.234000.json','["世事興亡轉脚跟，長安處處戰場塵。", "種桃一去非秦世，採菊猶傳有晉人。", "已矣覆蕉成夢鹿，誰歟被髮趁騎麟。", "千年尚記遼東路，肯向城頭訪舊民。"]'),
('2c973785-79c0-4b62-90de-61a9c00b38b7','感興','何夢桂','宋','宋诗','song-poetry','','[]','剩得田園歸去來，江南兩度見黄梅。',64,'全唐诗/poet.song.234000.json','["剩得田園歸去來，江南兩度見黄梅。", "軒窗有侶餘松竹，牆壁無人半蘚苔。", "獨抱丹心徒自苦，相逢白首不須哀。", "人間萬事不可極，一夢蘧蘧心已灰。"]'),
('235aae59-814f-4cb8-8992-6d235606b866','贈邊縣尹  其一','何夢桂','宋','宋诗','song-poetry','','[]','君家久富五經儲，更有兒孫讀祖書。',64,'全唐诗/poet.song.234000.json','["君家久富五經儲，更有兒孫讀祖書。", "事究麟經明亥豕，理窮羲易得筌魚。", "枳叢不是棲鸞處，花縣來觀展驥初。", "北道主人今有托，華山應得老騎馿。"]'),
('53d7ba2e-8081-47a8-a09d-01968218b318','贈邊縣尹  其二','何夢桂','宋','宋诗','song-poetry','','[]','聲價中州第一流，雙鳬飛下錦溪頭。',64,'全唐诗/poet.song.234000.json','["聲價中州第一流，雙鳬飛下錦溪頭。", "隠微去處求民瘼，潛伏中間破吏媮。", "暮雨烟村無吠犬，去年荒土有耕牛。", "晝簾餘暇渾無事，好去栽花待勝遊。"]'),
('ab517488-72f4-47ef-b3d5-3839bd39749b','和勉齋侄二首  其一','何夢桂','宋','宋诗','song-poetry','','[]','謾學狂吟試筆氈，慚無風度似僧虔。',64,'全唐诗/poet.song.234000.json','["謾學狂吟試筆氈，慚無風度似僧虔。", "五車不作黄金屋，方寸猶存白玉田。", "萬事混茫隨夢境，一關玄牝透真筌。", "北窗人在羲皇上，占得清風一榻眠。"]'),
('19f9b304-971c-4f28-96ce-7f2e3ecaa949','和勉齋侄二首  其二','何夢桂','宋','宋诗','song-poetry','','[]','有鳥千年去不歸，歸來滄海劫塵飛。',64,'全唐诗/poet.song.234000.json','["有鳥千年去不歸，歸來滄海劫塵飛。", "白楊北郭行人少，青草中原戰馬肥。", "喑噫陰陽成物累，浮游天地寄身微。", "老來盡棄人間事，猶占江頭白鷺磯。"]'),
('f0d048f9-42da-4b94-ad27-306672d516d0','觀禽鳥哺雛有感賦詩三首示諸子侄  其一','何夢桂','宋','宋诗','song-poetry','','[]','父母人心物豈無，靜觀禽鳥見中孚。',64,'全唐诗/poet.song.234000.json','["父母人心物豈無，靜觀禽鳥見中孚。", "自來擇木心勞瘁，到得成巢口卒瘏。", "囝翅漸長郎罷短，仔身已壯阿㜷癯。", "人間恩義尚如此，幾個林中反哺烏。"]'),
('7bc6f0c2-8c28-45b4-b403-cc7dd29c0fa0','觀禽鳥哺雛有感賦詩三首示諸子侄  其二','何夢桂','宋','宋诗','song-poetry','','[]','考叔分羹我獨無，不如鳴鶴自相孚。',64,'全唐诗/poet.song.234000.json','["考叔分羹我獨無，不如鳴鶴自相孚。", "世途跋涉牛先喘，仕路馳驅馬已瘏。", "弗逮子輿三釜養，空餘顔氏一簞癯。", "蓼莪詩廢遺軀在，愧死林中孝義烏。"]'),
('63cf1a7a-11b5-4741-b0c6-d85f4c845a04','觀禽鳥哺雛有感賦詩三首示諸子侄  其三','何夢桂','宋','宋诗','song-poetry','','[]','萬事空花過眼無，到無言處自心孚。',64,'全唐诗/poet.song.234000.json','["萬事空花過眼無，到無言處自心孚。", "踐頭蘇爨芻何用，垂耳鹽車馬以瘏。", "野鶴不須驚客去，山雌一任笑人癯。", "他年史氏求遺稿，幸免臺中道噤烏。"]'),
('2a3d4754-993a-4498-907d-93669f540e3e','和山房夾谷僉事韻二首  其一','何夢桂','宋','宋诗','song-poetry','','[]','一家南北混車書，誰使斯民耳目塗。',64,'全唐诗/poet.song.234000.json','["一家南北混車書，誰使斯民耳目塗。", "昔日簪纓今役戶，朝時絃誦暮征夫。", "邇來風雨無完屋，何處乾坤着腐儒。", "不意斯文天未喪，鳳凰來後見河圖。"]'),
('9ec8caac-3bed-4fd5-b1bf-9ac3aac5f121','和山房夾谷僉事韻二首  其二','何夢桂','宋','宋诗','song-poetry','','[]','蒼生下土望天仙，乞得君恩易地然。',64,'全唐诗/poet.song.234000.json','["蒼生下土望天仙，乞得君恩易地然。", "繡斧聿來霄漢上，丹書先到浙江邊。", "學徒免隸夫征法，官品寧輸戶役錢。", "愧死支離疑效報，不妨鼓筴樂天年。"]'),
('dc3d0cf4-4004-48d0-bc3d-1a84f74b4baa','賀蛟峰先生入宅','何夢桂','宋','宋诗','song-poetry','','[]','富貴朱門蓋里閭，先生斸石此山居。',64,'全唐诗/poet.song.234000.json','["富貴朱門蓋里閭，先生斸石此山居。", "一區自足子雲宅，三徑何妨靖節廬。", "萬壑風雲生几席，四山花木入庭除。", "乾淳豈少高官爵，自是寒泉要著書。"]'),
('e8b961a0-40c9-42ca-b8f0-cef006c941e3','和王石澗儒免韻','何夢桂','宋','宋诗','song-poetry','','[]','鴞林何處聽遺音，三歎斯文試共論。',64,'全唐诗/poet.song.234000.json','["鴞林何處聽遺音，三歎斯文試共論。", "梁木夢非千聖往，瓜丘烟斷六經存。", "悠悠滄海東流遠，耿耿中天北極尊。", "吾道未亡鄒魯在，肯教失脚落他門。"]'),
('9aa30745-2403-4b2b-9c75-4f144739a83a','和方大山寄韻','何夢桂','宋','宋诗','song-poetry','','[]','老去莊陵一釣竿，釣魚猶勝乞粗官。',64,'全唐诗/poet.song.234000.json','["老去莊陵一釣竿，釣魚猶勝乞粗官。", "十年事業閒中過，千載功名死後看。", "往事危枰休下著，交情枯木獨知寒。", "相逢一笑雙蓬鬢，還倩何人斲鼻端。"]'),
('736f2559-3426-4b2f-b203-ea2bd3812c94','賀中齋黄大卿得子','何夢桂','宋','宋诗','song-poetry','','[]','聞說南山孕鳳雛，嶄然頭角見嶔㠌。',64,'全唐诗/poet.song.234000.json','["聞說南山孕鳳雛，嶄然頭角見嶔㠌。", "月宮仙桂託根異，海島蟠桃生子遲。", "七秩高年堂上父，一生足事膝間兒。", "朱顔白髮方强壯，要看梧孫長碧枝。"]'),
('80465666-967a-47aa-97ce-fb746eb9f099','唐昌地理王生求詩','何夢桂','宋','宋诗','song-poetry','','[]','千古青囊破六丁，太原衣鉢在心經。',64,'全唐诗/poet.song.234000.json','["千古青囊破六丁，太原衣鉢在心經。", "天教文字留心印，世有兒孫振說鈴。", "跨斷九龍行地脈，踏翻八卦撼天星。", "靈犀一點無傳訣，莫向山頭泥鬼靈。"]'),
('e94f779d-e52a-4d62-8f7a-2fde98a0552e','輓方宮使','何夢桂','宋','宋诗','song-poetry','','[]','鼎湖弓墮賦歸來，地拆天分泰華頹。',64,'全唐诗/poet.song.234000.json','["鼎湖弓墮賦歸來，地拆天分泰華頹。", "膝上二雛兵血燐，樓頭萬卷劫池灰。", "百年豪傑埋荒草，半世功名落大槐。", "身後有孫酹松柏，橋陵金粟暗蒼苔。"]'),
('a97573c8-e891-44b1-97d5-5a8999be0f5f','哭橋陵','何夢桂','宋','宋诗','song-poetry','','[]','百年弓劍入橋陵，豈料三泉化劫塵。',64,'全唐诗/poet.song.234000.json','["百年弓劍入橋陵，豈料三泉化劫塵。", "空有魚燈照荒土，忍將玉軸問遺民。", "蒼梧日落啼丹雀，金粟雲深卧石麟。", "寒食家家上丘冢，六宗盂飯屬何人。"]'),
('280be22f-e6c3-4f34-86cb-0e68f9676247','和岳文二公西湖韻','何夢桂','宋','宋诗','song-poetry','','["\u897f\u6e56"]','昆明灰出海揚塵，老去英雄白髮新。',64,'全唐诗/poet.song.234000.json','["昆明灰出海揚塵，老去英雄白髮新。", "宮闕崔嵬千里月，樓臺牢落十年春。", "血流杜宇悲遊子，夢斷梅花憶故人。", "立盡斷橋寒日薄，回頭何處望天津。"]'),
('0623d023-7a70-4716-b2d4-aa49f563ad38','弔岳文二公二首  其一','何夢桂','宋','宋诗','song-poetry','','[]','擬弔英雄酒一觴，二公肝膽一冰霜。',64,'全唐诗/poet.song.234000.json','["擬弔英雄酒一觴，二公肝膽一冰霜。", "金人未殄將軍死，宋事無成國士亡。", "湖上黄埃寒柏慘，沙場青血夜燐光。", "生芻一束新亭淚，千古興亡說未央。"]'),
('baad0b87-f573-4e9f-b858-26b6268a811b','弔岳文二公二首  其二','何夢桂','宋','宋诗','song-poetry','','[]','如此光陰冉冉何，青萍失手意蹉跎。',64,'全唐诗/poet.song.234000.json','["如此光陰冉冉何，青萍失手意蹉跎。", "門前流水溪山在，簾外落花風雨多。", "百歲身名頭半雪，十年世事淚懸河。", "相逢莫問升沉事，且對尊前聽浩歌。"]'),
('112a0989-4e67-4642-8695-06fc17899f41','弔維揚瓊花','何夢桂','宋','宋诗','song-poetry','','[]','隻鶴揚州問故家，一尊后土弔瓊花。',64,'全唐诗/poet.song.234000.json','["隻鶴揚州問故家，一尊后土弔瓊花。", "人間驚破霓裳舞，天上徵回玉女車。", "死蘗記曾霑雨露，落英誓不污泥沙。", "後庭玉樹今誰主，猶得臺城葬麗華。"]'),
('71ef212c-e305-4128-9751-c7944eb892fa','和文山先生','何夢桂','宋','宋诗','song-poetry','','[]','坐對烟煤冷麝臍，一窗風雨懶幽棲。',64,'全唐诗/poet.song.234000.json','["坐對烟煤冷麝臍，一窗風雨懶幽棲。", "蠶叢國破鵑啼血，王謝堂空燕落泥。", "華表有時歸老鶴，桃都何處聽天雞。", "十年往事俱塵土，莫上揚州唱竹西。"]'),
('4d2a3b79-60ed-47c2-bbc8-6890bb5d4729','丁亥清明和昭德侄孫韻','何夢桂','宋','宋诗','song-poetry','','[]','風吹苦楝結輕寒，乾石青精屋半間。',64,'全唐诗/poet.song.234000.json','["風吹苦楝結輕寒，乾石青精屋半間。", "潑火雨收春樹綠，踏青人出畫簾閒。", "紅顔白髮悲歡事，舊日新年夢覺關。", "滿地落花啼鳥急，天涯游子幾時還。"]'),
('5dec9fef-a4fc-4c8b-8a60-4017ae593d45','和石庵洪府理金沙酴醾牡丹二首  其一','何夢桂','宋','宋诗','song-poetry','','[]','金沙開遍牡丹忙，更簇酴醾上架芳。',64,'全唐诗/poet.song.234000.json','["金沙開遍牡丹忙，更簇酴醾上架芳。", "霞綺羅紈圍國色，玉堂金屋擁君王。", "妝成三月春光富，留得一年花事長。", "昨夜紫薇紅藥裏，詔君題品是誰香。"]'),
('8b1e37e8-9021-42ca-b9ce-7f0da96d59c9','和石庵洪府理金沙酴醾牡丹二首  其二','何夢桂','宋','宋诗','song-poetry','','[]','洛花欲放趁春忙，一架花添兩樣芳。',64,'全唐诗/poet.song.234000.json','["洛花欲放趁春忙，一架花添兩樣芳。", "倚檻白紅多侍女，臨軒黄紫是真王。", "只愁吳苑館娃老，無奈唐宮春恨長。", "說與天公須愛惜，莫教風雨委泥香。"]'),
('d9ede0cf-6e3a-442e-9553-c8ca8b36a44b','再和張秋山杭州孤山二首  其一','何夢桂','宋','宋诗','song-poetry','','[]','歌舞錢塘厭說兵，悠悠往事竟何成。',64,'全唐诗/poet.song.234000.json','["歌舞錢塘厭說兵，悠悠往事竟何成。", "錢鏐鐵箭千年在，伍子鴟夷一死輕。", "湖上園亭春代謝，江頭潮汐月虧盈。", "相逢白首休相問，見說宮門草樹平。"]'),
('bb699c65-cee0-446e-bbac-dab8ad3b2d7d','再和張秋山杭州孤山二首  其二','何夢桂','宋','宋诗','song-poetry','','[]','處士橫橋野水流，先生家住暮雲稠。',64,'全唐诗/poet.song.234000.json','["處士橫橋野水流，先生家住暮雲稠。", "百年故國成塵夢，千古青山憶舊遊。", "林下客盟寒白鶴，梅邊詩稿問蒼頭。", "公來但掃墳前竹，莫載虛名入帝州。"]'),
('564c202d-296c-4681-84ac-0e1366f13901','和汪子雨問易','何夢桂','宋','宋诗','song-poetry','','[]','玄白紛紛老子雲，那從覆瓿覓遺文。',64,'全唐诗/poet.song.234000.json','["玄白紛紛老子雲，那從覆瓿覓遺文。", "六爻本自畫前具，三極都從心上分。", "未許諸儒將見見，只應四聖自聞聞。", "浪談正墮負苓笑，况敢持芹更獻君。"]'),
('3a9bc23a-a67b-4930-8e85-d49defabca98','寄和竹所叔攝慈溪稅官二首  其一','何夢桂','宋','宋诗','song-poetry','','[]','莫向揚州唱竹西，枯桑海水自相知。',64,'全唐诗/poet.song.234000.json','["莫向揚州唱竹西，枯桑海水自相知。", "籠中老鶴千年翅，冰下寒蠶五色絲。", "官小暫淹山谷駕，庭閒好和老坡詩。", "凌風更上丹山頂，應笑人間蟻垤卑。"]'),
('c1b8c3ca-b395-4d8d-aadb-298e3920ae98','寄和竹所叔攝慈溪稅官二首  其二','何夢桂','宋','宋诗','song-poetry','','[]','半夜愚翁挾北山，頭銜休係舊時官。',64,'全唐诗/poet.song.234000.json','["半夜愚翁挾北山，頭銜休係舊時官。", "風雲失手劍光冷，霜雪滿頭衣带寬。", "歸去荒園三徑菊，相期晏歲九臯蘭。", "年年江上風濤惡，不上嚴陵七里灘。"]'),
('8cd4d150-f6ce-4e35-8f32-29254c010133','和牛知事','何夢桂','宋','宋诗','song-poetry','','[]','白首相逢歎暮年，楝花風後草連天。',64,'全唐诗/poet.song.234000.json','["白首相逢歎暮年，楝花風後草連天。", "單車載月來林下，樽酒移春入座邊。", "野老爭持寒澗水，山靈盡掃暮庭烟。", "從君去後柴門閉，惟有閒雲繞屋椽。"]'),
('2bdd3760-61b7-46c0-a710-19d81b659eb8','招隠三首  其一','何夢桂','宋','宋诗','song-poetry','','[]','昔年有約共投簪，回首紅塵白髮新。',64,'全唐诗/poet.song.234000.json','["昔年有約共投簪，回首紅塵白髮新。", "物外烟霞逢野逸，山中風雨望佳人。", "好憑野鶴尋和靖，莫待山靈喚孔賓。", "遲暮不來松蔭落，飛柯恐解折車輪。"]'),
('ca32834c-fb36-4389-a008-8717f1fce5ac','招隠三首  其二','何夢桂','宋','宋诗','song-poetry','','[]','別後頻驚束带寬，相逢亦復笑蒼顔。',64,'全唐诗/poet.song.234000.json','["別後頻驚束带寬，相逢亦復笑蒼顔。", "祇今歲月青牛老，何處烟波白鳥閒。", "千古心期寒綠綺，十年世事墮黄間。", "修篁倚遍空江暮，枉殺招呼費小山。"]'),
('9da49b67-0fe2-4c82-99fd-537f318311a3','招隠三首  其三','何夢桂','宋','宋诗','song-poetry','','[]','回頭五十九年非，千里晨風翼倦飛。',64,'全唐诗/poet.song.234000.json','["回頭五十九年非，千里晨風翼倦飛。", "門外黄塵時事改，樽前白髮故人稀。", "金河沙暖春鴻去，朱雀橋空海燕歸。", "惟有嚴陵灘下路，年年潮水上漁磯。"]'),
('f108796b-660c-47dd-84aa-faba29d8c312','邑水南夜歸即景','何夢桂','宋','宋诗','song-poetry','','[]','郊原踏遍拾芳蘅，歸聽城頭打二更。',64,'全唐诗/poet.song.234000.json','["郊原踏遍拾芳蘅，歸聽城頭打二更。", "野渡無人舟早宿，山蹊有月馬遲行。", "人家燈落半江影，僧寺鐘來隔岸聲。", "世路百年雙屐底，青山不老白頭生。"]'),
('4576df50-722b-4581-b787-d84e147f138b','和毅齋喜雪','何夢桂','宋','宋诗','song-poetry','','[]','阿滕試手下祥霙，散入郊原一尺盈。',64,'全唐诗/poet.song.234000.json','["阿滕試手下祥霙，散入郊原一尺盈。", "春近園林先富貴，夜深天地更分明。", "懶隨柳絮誇安石，浪入梅花妬廣平。", "明日詩壇期白戰，莫將點墨污瑶瓊。"]'),
('1a537ee1-1a30-44e9-b5fe-c5bc27df2584','和表露石庵韻','何夢桂','宋','宋诗','song-poetry','','[]','乾坤不固夜舟藏，去跨青鸞覓玉霜。',64,'全唐诗/poet.song.234000.json','["乾坤不固夜舟藏，去跨青鸞覓玉霜。", "東野詩隨山月墮，龍門灑落塚泥香。", "生傳嘉祐皇儲疏，死葬貞元綠綬章。", "九些招魂招不返，黄昏豺虎嘯山牆。"]'),
('bd44fbc8-9de1-4878-a293-83293eb291f9','和閩人龔玉峰韻  其一','何夢桂','宋','宋诗','song-poetry','','[]','猛拍闌干賦感傷，十年往事幾回腸。',64,'全唐诗/poet.song.234000.json','["猛拍闌干賦感傷，十年往事幾回腸。", "寧能璧與頭俱碎，安得車將臂怒當。", "太傅長沙悲鵩鳥，中郎北海牧羝羊。", "天荒地老英雄盡，萬古青山只故常。"]'),
('1bb41c6d-8e50-4fa5-94d5-0e9c56d7fb4f','和閩人龔玉峰韻  其二','何夢桂','宋','宋诗','song-poetry','','[]','病鶴衰翎歎折傷，惟餘芝草療饑腸。',64,'全唐诗/poet.song.234000.json','["病鶴衰翎歎折傷，惟餘芝草療饑腸。", "陣圖死不忘魚復，江艦生難候馬當。", "自分無帷埋畜狗，尚憐有肆返屠羊。", "頭顱老盡心猶在，夜半鈞天夢太常。"]'),
('a789a506-43e5-4fe4-92f5-0858d844906d','挽袁安人徐氏','何夢桂','宋','宋诗','song-poetry','','[]','政自傷悲歎緯嫠，可堪重賦柏舟詩。',64,'全唐诗/poet.song.234000.json','["政自傷悲歎緯嫠，可堪重賦柏舟詩。", "鳩憐隻影營巢瘁，烏喜孤雛返哺慈。", "半世苦心生自媚，百年貞節死方知。", "曼曼世路成孤憤，慚愧山前讀墓碑。"]'),
('b88cc4f8-98ef-44c6-94f9-6d7bc720761b','和李經歷見寄韻','何夢桂','宋','宋诗','song-poetry','','[]','白水輕烟古輞川，滿山紅葉稻平田。',64,'全唐诗/poet.song.234000.json','["白水輕烟古輞川，滿山紅葉稻平田。", "悠悠客夢孤雲外，落落詩情夕照邊。", "天闊風高黄鶴影，江空歲暮白鷗緣。", "推敲不任騎馿去，却訝昌黎識浪仙。"]'),
('fc02364f-f186-4d55-b4a2-2e00232a27a6','李郎中有詩謝寄藤杖仍次韻答之','何夢桂','宋','宋诗','song-poetry','','[]','海南覓得古藤枝，持與詩人杜牧之。',64,'全唐诗/poet.song.234000.json','["海南覓得古藤枝，持與詩人杜牧之。", "紫貝斑文鞭更爛，赤龍蒼骨蛻尤奇。", "路無夷險終全節，用有行藏一任時。", "非但與君扶脚力，鏦蛟剸虎要支持。"]'),
('63fcf9ea-f9fb-4cc6-a1cf-c5e3d782fc3d','和方山房韻寄李郎中','何夢桂','宋','宋诗','song-poetry','','[]','世路悠悠水上萍，相看誰與眼長青。',64,'全唐诗/poet.song.234000.json','["世路悠悠水上萍，相看誰與眼長青。", "千年彝鼎觀勳業，一代圖球見典型。", "謾道石能生白璧，自知竹已化青寧。", "絕憐驛路梅花句，肯落空江杜若汀。"]'),
('62c1c805-5366-48b2-b306-7a9b9cac05a9','梅杖詩','何夢桂','宋','宋诗','song-poetry','','[]','曾向孤山劚薜蘿，根株栗櫛試摩挲。',64,'全唐诗/poet.song.234000.json','["曾向孤山劚薜蘿，根株栗櫛試摩挲。", "持身慣歷風波路，回首還憐雪月坡。", "鐵骨自將惟世用，赤心不偶奈時何。", "會尋蒼竹成龍去，莫向葛陂深處過。"]'),
('92c3fd67-c647-48a6-83c1-7df364aaee05','夜坐有感','何夢桂','宋','宋诗','song-poetry','','[]','銀漢無聲玉漏沉，樓高風露入衣襟。',64,'全唐诗/poet.song.234000.json','["銀漢無聲玉漏沉，樓高風露入衣襟。", "洞龍睡熟雲歸岫，枝鵲啼乾月滿林。", "甕裏故書前世夢，匣中孤劍少年心。", "征鴻目斷闌干角，吹盡參差到夜深。"]'),
('f719bd09-2b09-4557-9950-db52509e600f','存厨徐君徵生挽歌','何夢桂','宋','宋诗','song-poetry','','[]','一厨聊寄等歸藏，荷鍤携壺畢此鄉。',64,'全唐诗/poet.song.234000.json','["一厨聊寄等歸藏，荷鍤携壺畢此鄉。", "逆旅不歸前路惡，蓋棺未了後期長。", "壙中酣飲自忘癖，道上哀歌人笑狂。", "千古心存千古事，青山流水付於塘。"]'),
('5fffe1c8-6355-422b-b2ae-9eccdaf50b15','偶成  其一','何夢桂','宋','宋诗','song-poetry','','[]','一卷南華一炷香，身閒隨處是仙鄉。',64,'全唐诗/poet.song.234000.json','["一卷南華一炷香，身閒隨處是仙鄉。", "竹聲侵戶朝眠覺，花影移階晝坐忘。", "杜曲自耕貧亦樂，柴桑可葬死何妨。", "悠悠往事俱塵土，剩得頭顱上雪霜。"]'),
('35326b71-d80d-42f0-a186-fbf8f47058e2','偶成  其二','何夢桂','宋','宋诗','song-poetry','','[]','沉水烟銷寶鴨香，山窩人在水雲鄉。',64,'全唐诗/poet.song.234000.json','["沉水烟銷寶鴨香，山窩人在水雲鄉。", "魚非惠子同魚樂，蝶化莊周併蝶忘。", "心了固知身是寄，物齊寧與道相妨。", "清明即是神仙界，不用丹爐煉玉霜。"]'),
('17588385-912f-48fa-8f90-bed86e4ffef6','小有山中即事','何夢桂','宋','宋诗','song-poetry','','[]','閒隨鶴影步山蹊，摘草歸來養竹雞。',64,'全唐诗/poet.song.234000.json','["閒隨鶴影步山蹊，摘草歸來養竹雞。", "水带平沙流澗淺，雲將落照壓山低。", "覆階亂葉憑風掃，護徑叢筠借鷺棲。", "萬物不言皆自得，此心觸處見端倪。"]'),
('c6e6093a-f2a9-4fd8-9926-96355ac05529','偶成寄王德甫','何夢桂','宋','宋诗','song-poetry','','[]','休休萬事總歸休，猶占青山對白頭。',64,'全唐诗/poet.song.234000.json','["休休萬事總歸休，猶占青山對白頭。", "籟寂乾坤機落落，境忘身世夢悠悠。", "孤雲野水遼天鶴，明月清風露地牛。", "此意不知誰會得，一聲鐵笛萬山秋。"]'),
('2270d3d1-0826-4055-b408-915c00ac4206','和王德甫見壽二律  其一','何夢桂','宋','宋诗','song-poetry','','[]','百年閒夢寄山窩，世態人情任唯阿。',64,'全唐诗/poet.song.234000.json','["百年閒夢寄山窩，世態人情任唯阿。", "竹裹貞心經歲老，梅開白眼看人多。", "身從野叟分樵牧，莫遣山靈掃桂蘿。", "黄閣朱崖身外事，一蓑牛背夕陽歌。"]'),
('dfe3237d-9bf0-47ad-94e1-54dcf888a561','和王德甫見壽二律  其二','何夢桂','宋','宋诗','song-poetry','','[]','竈墮丹飛昔未仙，重來人世了前緣。',64,'全唐诗/poet.song.234000.json','["竈墮丹飛昔未仙，重來人世了前緣。", "自憐白髮隨孤影，空撫青萍憶少年。", "黄菊秋餘花尚耐，玄梨霜後果初圓。", "問君何以爲翁壽，但誦黄庭內外篇。"]'),
('d422772d-6e1a-4b40-a643-0ea03940016d','挽新城徐峴山','何夢桂','宋','宋诗','song-poetry','','[]','騎鸞一去藐塵寰，萬里天風杳珮環。',64,'全唐诗/poet.song.234000.json','["騎鸞一去藐塵寰，萬里天風杳珮環。", "江海十年生白浪，星霜七秩隕朱顔。", "瑶池月墮夢中夢，翠峴雲歸山外山。", "身世到頭秋露盡，吟魂猶自在人間。"]'),
('46a0059d-8149-4e5e-a091-1a004758becd','道汾陽不及訪逢原蒙寄詩次韻','何夢桂','宋','宋诗','song-poetry','','[]','浮槎曾誤客星占，屐齒空傳遍好山。',64,'全唐诗/poet.song.234000.json','["浮槎曾誤客星占，屐齒空傳遍好山。", "弱水方壺三萬里，武夷玉女九重關。", "蹇馿有徑穿花外，短棹無人出葦間。", "不是鍾山真勒駕，自慚松桂莫能攀。"]'),
('cf502e6a-a72a-4290-bbb1-798c73bba275','王石澗賦小有洞天之詩邵青谿和之輒次韻奉謝','何夢桂','宋','宋诗','song-poetry','','[]','自憐惡石狠難鞭，歸去漁樵結老緣。',64,'全唐诗/poet.song.234000.json','["自憐惡石狠難鞭，歸去漁樵結老緣。", "野鶴分無軒上祿，醯雞粗足甕中天。", "病來摩詰非真佛，睡去希夷已半仙。", "僻好自耽如嗜酒，醉鄉休與醒人傳。"]'),
('e35542b5-942c-4758-a9a7-ce2e689b03a9','和韻問魏石川疾  其一','何夢桂','宋','宋诗','song-poetry','','[]','謾道無丹蛻骨凡，繡襦不換嫁時衫。',64,'全唐诗/poet.song.234000.json','["謾道無丹蛻骨凡，繡襦不換嫁時衫。", "老天倘未忘周孔，巫鬼何須問抵咸。", "身健加餐親鼎飪，眼明減藥認囊椷。", "山中吠犬千年杞，采采猶堪饜吻饞。"]'),
('64db3370-6c43-413d-b93c-c4a5826e4a8f','和韻問魏石川疾  其二','何夢桂','宋','宋诗','song-poetry','','[]','不是塵中骨相凡，蓉裳蕙带芰荷衫。',64,'全唐诗/poet.song.234000.json','["不是塵中骨相凡，蓉裳蕙带芰荷衫。", "勿疑有疾淫成蠱，須信無心感是咸。", "裹藥曾經丹竈火，裁書祇欠土奩椷。", "病餘努力加蔬飯，莫笑篔簹太守饞。"]'),
('7bcd6da8-5a8d-4008-9655-8d147688eee9','和韻問魏石川疾  其三','何夢桂','宋','宋诗','song-poetry','','[]','靈山何許問巫凡，狹地知難旋舞衫。',64,'全唐诗/poet.song.234000.json','["靈山何許問巫凡，狹地知難旋舞衫。", "枕上病雖憂白傅，床前教肯媿陳咸。", "君宜借力寬詩課，我亦埋頭事藥椷。", "種朮養鳬隨分足，豈因富貴墮涎饞。"]'),
('91e8ef4d-1695-4946-97d8-b8eec1d0d87d','贈董君竹梧亭','何夢桂','宋','宋诗','song-poetry','','[]','買得園亭樂賦歸，一庭翠碧映參差。',64,'全唐诗/poet.song.234000.json','["買得園亭樂賦歸，一庭翠碧映參差。", "自憐封戶培新笋，更喜添孫養嫩枝。", "翠袖倚看雲影亂，銀床坐對月陰移。", "沉香欄北花如故，富貴無心懶賦詩。"]'),
('5189c0ae-6dfa-4f42-bfe6-045c430ea0c3','山窩適興','何夢桂','宋','宋诗','song-poetry','','[]','剩得閒身鎮自憐，更憐閒占此山泉。',64,'全唐诗/poet.song.234000.json','["剩得閒身鎮自憐，更憐閒占此山泉。", "滿階碧草客稀到，半榻白雲人對眠。", "窗影枝摇知雀踏，壁痕苔濕認蝸涎。", "日長靜看辛夷樹，落盡閒花忘宿緣。"]'),
('0eda07cf-00e8-4221-8169-43077bce12ad','感興  其一','何夢桂','宋','宋诗','song-poetry','','[]','坐斷乾坤老一窩，修篁翠袖自婆娑。',64,'全唐诗/poet.song.234000.json','["坐斷乾坤老一窩，修篁翠袖自婆娑。", "半生夢覺青山在，萬世期長白日過。", "雲影對人閒裏好，禽聲入耳靜邊多。", "舞雩不是真狂者，樂上心來可奈何。"]'),
('27b4e09b-2fe6-47c5-85fe-c6e757ca6c5c','感興  其二','何夢桂','宋','宋诗','song-poetry','','[]','擬將物化問漁樵，妙裏無形本寂寥。',64,'全唐诗/poet.song.234000.json','["擬將物化問漁樵，妙裏無形本寂寥。", "大地雲生千嶂雨，中天月上九溟潮。", "山河劫運九中化，世界塵緣座上銷。", "此意到頭誰會得，任他人道似逍遥。"]'),
('72a3f61f-9dc1-4eb5-b30a-0daa892fe949','次山房韻  其一','何夢桂','宋','宋诗','song-poetry','','[]','天教龍馬現河圖，盡把先天授伏羲。',64,'全唐诗/poet.song.234000.json','["天教龍馬現河圖，盡把先天授伏羲。", "三極都從九裏出，六爻只向一中推。", "易如可毀乾坤熄，神本無方晝夜知。", "三聖有憂辭已贅，寥寥千載復何時。"]'),
('2d660d6e-c395-467a-901f-5182875f2484','次山房韻  其二','何夢桂','宋','宋诗','song-poetry','','[]','易寂無爲有感幾，幾存萬物未生時。',64,'全唐诗/poet.song.234000.json','["易寂無爲有感幾，幾存萬物未生時。", "陰陽理向極中看，天地心從復處知。", "潮上海門探月窟，日迴地戶濯咸池。", "何時騎鶴研朱露，共勘經圖叩古羲。"]'),
('86a0008d-8194-4727-b7f2-2fe0e6e0aed6','次山房韻  其三','何夢桂','宋','宋诗','song-poetry','','[]','西狩事非文殆喪，舂陵書出道寧孤。',64,'全唐诗/poet.song.234000.json','["西狩事非文殆喪，舂陵書出道寧孤。", "六經有舌存先聖，千古留心付後儒。", "杲日麗天隨處見，逝川行地幾時無。", "齋居珍重賡歌意，即此全吞太極圖。"]'),
('2518a902-d526-4f9a-bf1c-3a1778670fec','己卯春過西湖','何夢桂','宋','宋诗','song-poetry','','["\u897f\u6e56"]','世事誰家屋上烏，重來猶認舊西湖。',64,'全唐诗/poet.song.234000.json','["世事誰家屋上烏，重來猶認舊西湖。", "風帘隔岸自高下，烟寺前山半有無。", "野水菰蒲飛屬玉，夕陽欄檻喚提壺。", "十年不記梅花夢，試向孤山問老逋。"]'),
('bd1eb531-6a89-4590-b5f5-1ca762ee1387','再用前韻和諸公','何夢桂','宋','宋诗','song-poetry','','["\u897f\u6e56"]','白髮星星紗帽烏，怕隨年少過西湖。',64,'全唐诗/poet.song.234000.json','["白髮星星紗帽烏，怕隨年少過西湖。", "清明上冢行人少，寒食開門宮使無。", "半世行藏隨杖屨，百年悲樂寄樽壺。", "歸來第五橋邊路，半樹殘陽噪畢逋。"]'),
('34aedb34-9b07-4131-b524-c8b7433c4db7','和昭德孫燕子韻  其一','何夢桂','宋','宋诗','song-poetry','','[]','飄零短翅歎誰同，猶記當年繫足紅。',64,'全唐诗/poet.song.234000.json','["飄零短翅歎誰同，猶記當年繫足紅。", "人事合離夢槐國，歲時來去旅新豐。", "新樓綠幕無巢地，故國烏衣隔海風。", "說盡興亡人不識，春風雙淚白鬚翁。"]'),
('5575b2af-6bb5-4668-b2fa-6a7ce1c63232','和昭德孫燕子韻  其二','何夢桂','宋','宋诗','song-poetry','','[]','說著興亡事不同，且斟玄玉駐顔紅。',64,'全唐诗/poet.song.234000.json','["說著興亡事不同，且斟玄玉駐顔紅。", "雲軒夢斷宮花逝，綵縷盟寒墓草豐。", "處處社時茅屋雨，年年春後楝花風。", "人間不是無棲處，要認當年舊媼翁。"]'),
('4193c5b0-9d25-46af-8b59-9ec333b1afdb','和梅鏡寄韻','何夢桂','宋','宋诗','song-poetry','','[]','未能生翼化鯤魚，誰御泠風問太初。',64,'全唐诗/poet.song.234000.json','["未能生翼化鯤魚，誰御泠風問太初。", "十載青衫關洛客，半生白首楚橋書。", "蹇馿豈解思長道，病鶴徒知戀舊廬。", "世有二程精說易，臯比何事到橫渠。"]'),
('3fc1415d-e10f-4b0a-bc65-425ff4c10c16','和酈僉事見寄韻  其一','何夢桂','宋','宋诗','song-poetry','','["\u897f\u6e56"]','詩書無用戲侏儒，兩序今猶見璧圖。',64,'全唐诗/poet.song.234000.json','["詩書無用戲侏儒，兩序今猶見璧圖。", "末路弟兄知己少，中原人物似君無。", "曲終湘水絲繩絕，書入昭陵筆硯蕪。", "珍重江南春信早，暗隨梅萼到西湖。"]'),
('f187bda9-827a-4357-8383-e84888f3ea20','和酈僉事見寄韻  其二','何夢桂','宋','宋诗','song-poetry','','[]','半世虛名我誤儒，樊中短翅倦南圖。',64,'全唐诗/poet.song.234000.json','["半世虛名我誤儒，樊中短翅倦南圖。", "黄塵世路千年改，白髮心期四海無。", "績紡婦慵麻褐短，耕鋤兒懦豆田蕪。", "老來萬事心灰盡，只願君王賜鏡湖。"]'),
('97171ba4-6338-4759-b7fe-16f496ef9f75','病起有感','何夢桂','宋','宋诗','song-poetry','','[]','聲乾木鐸說鈴非，天地無情世運奇。',64,'全唐诗/poet.song.234000.json','["聲乾木鐸說鈴非，天地無情世運奇。", "吾道悠悠川水逝，人才落落曉星稀。", "百年身後千年遠，萬個人中一個知。", "一曲汾亭彈未盡，却教漁父洩天機。"]'),
('d8ef7b51-62ca-44e4-b4be-ef8a08362d63','汾陽諸公招徐祥叔歸代之答謝  其一','何夢桂','宋','宋诗','song-poetry','','[]','富貴男兒晝錦衣，天涯漂泊衆心違。',64,'全唐诗/poet.song.234000.json','["富貴男兒晝錦衣，天涯漂泊衆心違。", "人情鈎餌驚魚去，世界瓶羅礙雀飛。", "隠去甘從山鬼喚，狎遊寧墮海翁機。", "草堂猶在終歸去，只恐風塵白髮微。"]'),
('771e8a97-4aeb-45ab-870c-27204d130b0a','汾陽諸公招徐祥叔歸代之答謝  其二','何夢桂','宋','宋诗','song-poetry','','[]','澗陵望斷憶玄暉，一片春雲渭水涯。',64,'全唐诗/poet.song.234000.json','["澗陵望斷憶玄暉，一片春雲渭水涯。", "洞裏桃開成隔世，山中柯爛忘來時。", "歸休韋曲應無頼，隠去玄真那有詩。", "松菊相逢如見問，此心欲寄已忘辭。"]'),
('478ac856-e58f-49f6-8ce5-cd4c2f27a93e','和何寧谷韻','何夢桂','宋','宋诗','song-poetry','','[]','一曲樽前浩浩歌，流年容易隙駒過。',64,'全唐诗/poet.song.234000.json','["一曲樽前浩浩歌，流年容易隙駒過。", "眼前白髮故人少，郭外青楓古冢多。", "流水不彈嗟老矣，雍門欲聽奈愁何。", "回頭城闕應非昔，還記千年老鶴麽。"]'),
('e33a554e-8e0f-4030-b6b4-c00027f54626','歸途再得八句併寄','何夢桂','宋','宋诗','song-poetry','','[]','石田歸去醉時歌，白日飛帆送客過。',64,'全唐诗/poet.song.234000.json','["石田歸去醉時歌，白日飛帆送客過。", "舞袖低旋兼地狹，出門長嘯覺天多。", "子卿朔漠知存否，武帝秋風奈老何。", "極目西陵臺下路，漳河東去復來麽。"]'),
('f325e621-3916-4913-9b5d-2d51e50f4bcb','何逢原寄和章再和前韻','何夢桂','宋','宋诗','song-poetry','','[]','日暮歸來彈鋏歌，詩筒何處又相過。',64,'全唐诗/poet.song.234000.json','["日暮歸來彈鋏歌，詩筒何處又相過。", "人生百歲樂時少，春色三分塵土多。", "愧乏丹砂修渾沌，且拚樽酒醉無何。", "近來江上風濤惡，還有閒鷗似我麽。"]'),
('302a523c-9d21-4850-94b1-58dfc339b503','和昭德孫聞鵑','何夢桂','宋','宋诗','song-poetry','','[]','平生抵掌志伊吾，聞著鵑聲淚血枯。',64,'全唐诗/poet.song.234000.json','["平生抵掌志伊吾，聞著鵑聲淚血枯。", "故國蠶叢千古恨，霧關熊耳一身孤。", "自從飛去啼痕在，縱不歸來有夢無。", "莫向延秋門上叫，門樓無數白頭烏。"]'),
('700a2ba2-ed61-4d6e-909d-8d93d193f83f','和抱甕馮提學二首  其一','何夢桂','宋','宋诗','song-poetry','','[]','吁嗟世事落黄間，倦矣人間行路難。',64,'全唐诗/poet.song.234000.json','["吁嗟世事落黄間，倦矣人間行路難。", "流水已隨鍾子老，仙舟徒羨李膺觀。", "從來豪傑爲時出，到底功名耐久看。", "大厦將成要梁棟，雪深方見玉龍寒。"]'),
('fdea3e87-dc31-4065-b33b-69c230258ead','和抱甕馮提學二首  其二','何夢桂','宋','宋诗','song-poetry','','[]','山人日卧嶺雲長，扣戶詩書枉紀綱。',64,'全唐诗/poet.song.234000.json','["山人日卧嶺雲長，扣戶詩書枉紀綱。", "多病半生雙白鬢，相思一日九迴腸。", "人情取舍成芻狗，世事興亡化石羊。", "明日相逢且拚醉，轉頭三萬六千場。"]'),
('8dbceed9-790b-4490-9508-715615cbc166','聞琴一首','何夢桂','宋','宋诗','song-poetry','','[]','自呼濁酒賦江蘺，一曲朱繩萬感隨。',64,'全唐诗/poet.song.234000.json','["自呼濁酒賦江蘺，一曲朱繩萬感隨。", "沙漠美人青冢恨，關河壯士北邙噫。", "無人流水音誰賞，老我雍門聽轉悲。", "夜半月明天籟寂，飛烏猶自繞南枝。"]'),
('6a69384a-89f6-4933-8e3b-b7dcf756e917','贈喬縣尹','何夢桂','宋','宋诗','song-poetry','','[]','神君當日藹民謠，復見君來試割刀。',64,'全唐诗/poet.song.234000.json','["神君當日藹民謠，復見君來試割刀。", "花下簾櫳閒訟牒，柳邊亭榭見旌旄。", "農桑課最繭絲殿，芻秣征寬馬骨高。", "泉出後田渾不飲，恐他滴滴是民膏。"]'),
('b051b421-5063-43ed-9fb3-a4042a999f8d','寄方龍溪','何夢桂','宋','宋诗','song-poetry','','[]','欲扣玄關訪偓佺，人間無路鐵鞋穿。',64,'全唐诗/poet.song.234000.json','["欲扣玄關訪偓佺，人間無路鐵鞋穿。", "瑯邪舊約驚千載，嵩嶽新來下二仙。", "肯把丹砂分藥鼎，便將白玉種芝田。", "瓣香欲謝雙巖過，却道龍溪合受拳。"]'),
('9d2be1ad-7e13-4c64-97c9-f65c4647851d','樂意','何夢桂','宋','宋诗','song-poetry','','[]','真樂攻心無奈何，自行自坐自謳歌。',64,'全唐诗/poet.song.234000.json','["真樂攻心無奈何，自行自坐自謳歌。", "雲收雨浄天無滓，月朗淵澄水不波。", "更把新詩勾野興，時將濁酒發天和。", "傍人笑我荒唐甚，真樂攻心無奈何。"]'),
('0e7b4412-c4ac-43cb-a2c6-8a56d5cdc544','挽寧谷居士何公三首  其一','何夢桂','宋','宋诗','song-poetry','','[]','英雄千古入泉臺，八十餘齡死更哀。',64,'全唐诗/poet.song.234000.json','["英雄千古入泉臺，八十餘齡死更哀。", "隠谷雲歸龍已老，吟壇月墮鶴空回。", "黄花滿地詩人老，青檟成阡弔客來。", "白髮蓋棺公事了，朔風世路正黄埃。"]'),
('b8471ef7-6bb6-4dbf-90a1-14b3a3584b85','挽寧谷居士何公三首  其二','何夢桂','宋','宋诗','song-poetry','','["\u897f\u6e56"]','天寒白月墮西湖，血淚啼枯聽薤歌。',64,'全唐诗/poet.song.234000.json','["天寒白月墮西湖，血淚啼枯聽薤歌。", "食子俱亡收子在，近孫猶少遠孫多。", "北邙有地存詩窖，後圃無人負鞠窠。", "欲誌魯山慚四絕，空遺陳迹照松蘿。"]'),
('a267e890-36ca-4eb2-a9d1-cb1b253ef149','挽寧谷居士何公三首  其三','何夢桂','宋','宋诗','song-poetry','','[]','鼠繞枯藤嚙未休，得如此老死何求。',64,'全唐诗/poet.song.234000.json','["鼠繞枯藤嚙未休，得如此老死何求。", "翁踰八十媼黄髮，孫見曾玄兒白頭。", "身世幅巾歸繭室，歲時盂飯灑狐丘。", "百年心事無人識，分付黄花滿地秋。"]'),
('df1971f0-114b-46e4-a79f-56ac31dd2f26','挽閤門唐中齋','何夢桂','宋','宋诗','song-poetry','','[]','英州別駕老昭陵，尚有錢塘八代孫。',64,'全唐诗/poet.song.234000.json','["英州別駕老昭陵，尚有錢塘八代孫。", "三略兵書生未識，百篇詩史死猶存。", "羊公峴首行人淚，白傅龍門過客樽。", "盂飯寢園誰是主，鳳亭霜露有雞豚。"]'),
('2f495fef-a7d9-4f5f-a3bd-108356855423','挽吏部劉謙山','何夢桂','宋','宋诗','song-poetry','','[]','猶記青原白鷺盟，轉頭宿草上新塋。',64,'全唐诗/poet.song.234000.json','["猶記青原白鷺盟，轉頭宿草上新塋。", "屋梁月落丹心在，海水天寒白髮生。", "樽酒十年兒女淚，篇詩兩地弟兄情。", "蓋棺事了君無愧，未死遑知身後名。"]'),
('e7e1ea79-f4f6-45a0-9e15-5a4f22638199','感寓二首  其一','何夢桂','宋','宋诗','song-poetry','','[]','西風落日怕登樓，倚遍闌干萬古愁。',64,'全唐诗/poet.song.234000.json','["西風落日怕登樓，倚遍闌干萬古愁。", "衰漢竟成三國誤，秣陵不蓋六朝羞。", "江山有恨留青史，天地無情送白頭。", "擊碎唾壺歌不盡，荒臺殘雨夢揚州。"]'),
('3c8fd826-5dcd-4fc3-a78a-996935172258','感寓二首  其二','何夢桂','宋','宋诗','song-poetry','','[]','試向昆明問劫灰，幾看麋鹿上蘇臺。',64,'全唐诗/poet.song.234000.json','["試向昆明問劫灰，幾看麋鹿上蘇臺。", "閒中歷日生青草，夢裏乾坤化大槐。", "塞雁南歸春又去，江潮東下暮還來。", "臨平山盡啼鵑歇，可是征人喚不回。"]'),
('c16dce3a-ea09-4e69-b6bc-c697958d12b1','挽太學正節先生徐應鑣','何夢桂','宋','宋诗','song-poetry','','[]','國破君亡一死宜，絕憐兒女死如飴。',64,'全唐诗/poet.song.234000.json','["國破君亡一死宜，絕憐兒女死如飴。", "龍池久負媧皇誓，蛙坎空遺烈士悲。", "洗骨不污唐六館，瀝心無愧趙孤兒。", "北行多少生還客，休向梯雲讀墓碑。"]'),
('c4924a15-17f0-4d24-b884-64a24b1f1c58','寄淳安括田省委賈都事','何夢桂','宋','宋诗','song-poetry','','[]','括田馳檄遍封提，分得清官照錦衣。',64,'全唐诗/poet.song.234000.json','["括田馳檄遍封提，分得清官照錦衣。", "百里春風生几案，千村甘雨自鋤犁。", "江南地狹人民夥，燕北天遥日月低。", "歸覲九重如顧問，尚歌雲漢勞遺黎。"]'),
('ea72e504-86f3-4348-adfc-88ccd1f650e2','送平石姪孫還杭','何夢桂','宋','宋诗','song-poetry','','["\u897f\u6e56"]','東風吹雨濕平蕪，三疊陽關醉唾壺。',64,'全唐诗/poet.song.234000.json','["東風吹雨濕平蕪，三疊陽關醉唾壺。", "往事盡隨塵世界，新來祇怪老頭顱。", "百年祖父留湯沐，千里兒孫有飯盂。", "目斷長亭休折柳，斜陽山外是西湖。"]'),
('6aa18254-b044-4616-adfc-6411569bed14','送嚴郡知事石綉回鄉','何夢桂','宋','宋诗','song-poetry','','[]','三年幕府鬢成霜，剩得行歌載道傍。',64,'全唐诗/poet.song.234000.json','["三年幕府鬢成霜，剩得行歌載道傍。", "瓜戍春濃官又滿，蓮池人好水尤香。", "燕然碣石去程遠，江水雲山看日長。", "倚遍修篁衣袖薄，長亭無路折垂楊。"]'),
('f0525012-6f3b-44ce-8b73-93489b79b96b','送入都僉事','何夢桂','宋','宋诗','song-poetry','','[]','天教持斧下錢塘，來爲蒼生滌痏瘡。',64,'全唐诗/poet.song.234000.json','["天教持斧下錢塘，來爲蒼生滌痏瘡。", "胸次對天懸日月，筆端隨地轉冰霜。", "雲山有分高名在，江水無情清議長。", "臨別折梅嫌太俗，斲將冰雪薦瓊觴。"]'),
('0f64edbf-4231-4753-8328-4a2fbed2ba58','和尉衙落成贈阮梅仙','何夢桂','宋','宋诗','song-poetry','','[]','梅仙貴介出侯門，庭砌猶傳有紫荆。',64,'全唐诗/poet.song.234000.json','["梅仙貴介出侯門，庭砌猶傳有紫荆。", "黄綬銅章官小試，青溪花縣室初成。", "公衙好作三年計，少府香留百代名。", "田野近聞多犬吠，夜深刁鼓要分明。"]'),
('79c7d6db-898a-4c5e-bfb0-e68398678282','挽吳靜軒','何夢桂','宋','宋诗','song-poetry','','[]','手摩銘碣弔延陵，落日青山昨夢驚。',64,'全唐诗/poet.song.234000.json','["手摩銘碣弔延陵，落日青山昨夢驚。", "狹世路危行却曲，浮生事了去分明。", "竹林熠耀飛臺榭，石壁鈎輈叫冢塋。", "珠雁玉龍今在否，漆燈千古照佳城。"]'),
('939b5ae6-8cf8-4b8d-9e79-af1b8544f683','赤壁夢鶴','何夢桂','宋','宋诗','song-poetry','','[]','遼海千年約未寒，一樽還酹大江干。',64,'全唐诗/poet.song.234000.json','["遼海千年約未寒，一樽還酹大江干。", "夜深睡熟忘身世，天闊歸遲化羽翰。", "滿界紅塵飛不下，半船明月笑相看。", "起來開戶無人迹，數盡枝烏吊老瞞。"]'),
('894345c2-0aa2-432d-8c97-e6c912dc0f7a','和雪','何夢桂','宋','宋诗','song-poetry','','[]','天上瓊樓一夜開，雲林先約意徘徊。',64,'全唐诗/poet.song.234000.json','["天上瓊樓一夜開，雲林先約意徘徊。", "靈河剪水急飛落，色界憑風緩下來。", "霓舞未闌離月殿，蛾妝初試度陽臺。", "自矜顔色難爲偶，嫁得梅花却占魁。"]'),
('8578d4f7-b8b0-4b80-bb52-a9db79b8b5a2','送胡簿秩滿歸','何夢桂','宋','宋诗','song-poetry','','[]','佐邑三年去後思，祇今無奈送行時。',64,'全唐诗/poet.song.234000.json','["佐邑三年去後思，祇今無奈送行時。", "不諧白雪皇荂耳，謾指清風惡木枝。", "臺府無心空裏鏡，士民有口路傍碑。", "錦溪流下嚴陵瀨，八月潮來有轉期。"]'),
('90852c67-d10c-4ca8-a0d1-c294cb8997ad','承書言別再寄','何夢桂','宋','宋诗','song-poetry','','[]','一曲離鸞感寄心，此心誰解試分明。',64,'全唐诗/poet.song.234000.json','["一曲離鸞感寄心，此心誰解試分明。", "百年耆舊閒中話，千古溪山去後名。", "雙鯉尺書兒女淚，隻雞斗酒弟兄情。", "男兒須勒燕然石，歸拜堂諼始是榮。"]'),
('2d114fb5-2d66-46e2-be84-cdb364b87393','寄贈潘氏積善堂','何夢桂','宋','宋诗','song-poetry','','[]','市義今無古孟嘗，不圖近見鄭公鄉。',64,'全唐诗/poet.song.234000.json','["市義今無古孟嘗，不圖近見鄭公鄉。", "布金地已成祇樹，簞食人應遍翳桑。", "身享九齡耆壽福，眼看五世子孫昌。", "天公有耳長聰聽，多少行碑在路傍。"]'),
('0e00219c-5606-468a-a5e1-b16d2740b967','灞橋騎馿','何夢桂','宋','宋诗','song-poetry','','[]','小驪買得最便宜，好是河梁古柳涯。',64,'全唐诗/poet.song.234000.json','["小驪買得最便宜，好是河梁古柳涯。", "風急吹沙長耳峻，雪深沒板蹇蹄遲。", "據鞍吟透肩雙聳，敲鐙歌狂帽半欹。", "道上莫教逢大尹，推敲句裏不曾知。"]'),
('caa47a70-940e-4b0e-9d98-0f6f6d75bba5','送陳治中勿齋二首  其一','何夢桂','宋','宋诗','song-poetry','','[]','天台萬丈下靈光，便合乘旗翳鳳凰。',64,'全唐诗/poet.song.234000.json','["天台萬丈下靈光，便合乘旗翳鳳凰。", "身在金臺天北闕，手提銅柱地南荒。", "一生許國心如鐵，萬里封侯鬢未霜。", "別駕小淹元不惡，公來私得海沂康。"]'),
('e5f2b6b3-8bbb-4148-bfad-d509f5cce332','送陳治中勿齋二首  其二','何夢桂','宋','宋诗','song-poetry','','[]','箳篂三載誦賢侯，折柳郵亭菊又秋。',64,'全唐诗/poet.song.234000.json','["箳篂三載誦賢侯，折柳郵亭菊又秋。", "無翼解隨雲北去，有心長注海東流。", "千崖雨意留行旆，七里灘頭送去舟。", "早爲蒼生題福筆，尚回麾節顧滄洲。"]'),
('8d14b8dd-bdc3-4658-a29b-1946d525c8ae','挽徐子愚母','何夢桂','宋','宋诗','song-poetry','','[]','萱花落盡北堂空，龍頷碑銘百尺豐。',64,'全唐诗/poet.song.234000.json','["萱花落盡北堂空，龍頷碑銘百尺豐。", "鄹紇晚婚無徵在，孟光不嫁有梁鴻。", "一官得子榮身後，四世看孫滿眼中。", "三酹生芻人似玉，故丘狐首此封崇。"]'),
('1cbc8c71-6a7f-4e36-b206-955cc92b88a1','挽方中立同舍','何夢桂','宋','宋诗','song-poetry','','[]','回首爐亭夢已非，英雄老盡壯心違。',64,'全唐诗/poet.song.234000.json','["回首爐亭夢已非，英雄老盡壯心違。", "鈞天雲散蒼龍墮，華表風寒白鶴歸。", "往事悠悠川水逝，故人落落曙星稀。", "樂天無子留孫在，多少龍門客淚揮。"]'),
('3ac1ebc0-ad11-43c2-833a-b70f9aaa2f15','又代人','何夢桂','宋','宋诗','song-poetry','','[]','一曲哀歌老淚垂，英雄不偶數孤奇。',64,'全唐诗/poet.song.234000.json','["一曲哀歌老淚垂，英雄不偶數孤奇。", "百年事墮槐安國，半世名成薦福碑。", "無祿逮親生自憾，有孫表墓死何悲。", "黄門靖節均生死，清議無情更屬誰。"]'),
('aefd94c6-df55-418e-9e3f-46249a83b38d','送阮梅仙','何夢桂','宋','宋诗','song-poetry','','[]','佐邑三年吏隠仙，聲名留照錦江邊。',64,'全唐诗/poet.song.234000.json','["佐邑三年吏隠仙，聲名留照錦江邊。", "才高不受青衫束，官小聊將綵仗懸。", "流沫呂梁游十仞，摶風溟海上三千。", "沙頭雙玉難爲別，一曲離歌約暮年。"]'),
('9acd9bc6-1c14-4b5c-94f2-7106423358d4','贈電目相士','何夢桂','宋','宋诗','song-poetry','','[]','知君說相壓南州，相我空貽白髮羞。',64,'全唐诗/poet.song.234000.json','["知君說相壓南州，相我空貽白髮羞。", "但得羊裘歸釣澤，安知燕頷去封侯。", "窮通有分都休問，出處難言已自謀。", "一笑相看出山去，逢人莫道見壺丘。"]'),
('4c2a867f-1e73-4ce5-b053-82c15ee864a1','挽汝南袁君  其一','何夢桂','宋','宋诗','song-poetry','','[]','一曲哀歌行道難，滿堂試聽一潸然。',64,'全唐诗/poet.song.234000.json','["一曲哀歌行道難，滿堂試聽一潸然。", "兩兒青紫開榮路，五世曾玄送暮年。", "喬木受風危易撼，孤舟排浪險終全。", "故丘狐首君無憾，寒食年年灑墓阡。"]'),
('204767d1-1b3f-42b4-a7ee-787f8008fd5a','挽汝南袁君  其二','何夢桂','宋','宋诗','song-poetry','','[]','黄金不鑄百年身，世變相劘白髮親。',64,'全唐诗/poet.song.234000.json','["黄金不鑄百年身，世變相劘白髮親。", "龍角墓碑生古蘚，砥如亭路落緇塵。", "明時事業留諸子，前代衣冠見似人。", "得失雞蟲都莫問，故丘抔土是全真。"]'),
('eaec5b62-9cdb-477c-bf3f-9ecda5cb33f0','挽汝南袁君  其三','何夢桂','宋','宋诗','song-poetry','','[]','桐木山西送落暉，百年耆舊數他誰。',64,'全唐诗/poet.song.234000.json','["桐木山西送落暉，百年耆舊數他誰。", "畏途幾歷青泥險，往事惟餘白髮知。", "今代衣冠遺此老，前朝簪笏付吾兒。", "明朝歸葬西邙路，五世哀思百尺碑。"]'),
('1baa048e-e75b-447f-9ee5-c0a3a7399586','挽檢院吳對山','何夢桂','宋','宋诗','song-poetry','','[]','岝崿山前弔隠君，招魂九些淚霑巾。',64,'全唐诗/poet.song.234000.json','["岝崿山前弔隠君，招魂九些淚霑巾。", "風雲失勢丹心死，天地無情白髮新。", "西洛衣冠遺一老，東籬詩酒是全人。", "蓋棺事了應無媿，消得新阡號逸民。"]'),
('2bfcb178-bfda-410b-a02d-b6662a9f4a3d','挽南坡章知縣章運使子家則堂誌','何夢桂','宋','宋诗','song-poetry','','[]','豐碑二絕照新阡，節義成名得象賢。',64,'全唐诗/poet.song.234000.json','["豐碑二絕照新阡，節義成名得象賢。", "善政人能書宰邑，寬恩民尚誦公田。", "家翁不負心傳印，冢嗣能忘手澤編。", "仕學一生行未了，後來好爲拂青氈。"]'),
('a5e20e44-8424-4164-8ffd-363be27a5ec4','挽邵青谿二章  其一','何夢桂','宋','宋诗','song-poetry','','[]','尊酒生芻弔舊遊，白髭老淚故山秋。',64,'全唐诗/poet.song.234000.json','["尊酒生芻弔舊遊，白髭老淚故山秋。", "百年勳業黄粱枕，一代文章白玉樓。", "豪傑彫零天地老，山河牢落古今愁。", "行人不歃青溪水，付與閒翁對白鷗。"]'),
('d6813cc5-9c95-45d5-a5bf-62c7fbfc0443','挽邵青谿二章  其二','何夢桂','宋','宋诗','song-poetry','','[]','貞元一曲淚霑巾，耆舊今能有幾存。',64,'全唐诗/poet.song.234000.json','["貞元一曲淚霑巾，耆舊今能有幾存。", "斗酒隻雞空酹冢，縞衣匹馬尚招魂。", "百年身後事終定，千古眼前誰共論。", "試問故侯瓜熟未，青門猶自有兒孫。"]'),
('5fd92a4b-373f-448f-908c-75322f867daf','山居即事','何夢桂','宋','宋诗','song-poetry','','[]','分得南窗與世違，坐消白晝樂清時。',64,'全唐诗/poet.song.234000.json','["分得南窗與世違，坐消白晝樂清時。", "樓頭秋意一聲笛，鏡裏歲華雙鬢絲。", "綠水放教通竹徑，清風招不下梧枝。", "心期自得難爲說，白鳥青山是己知。"]'),
('029d641f-929a-4c02-a962-07398182300b','贈舊同舍王景陽','何夢桂','宋','宋诗','song-poetry','','[]','何許相逢客路岐，相看鬚鬢各成絲。',64,'全唐诗/poet.song.234000.json','["何許相逢客路岐，相看鬚鬢各成絲。", "兩年衰病苦牢落，千里故人傷別離。", "江月不遺流水逝，天風未起老桑知。", "人生百歲先朝露，惟有貞名死不隳。"]'),
('3fa59f99-56ba-47a8-a340-898571d7615d','送高參政','何夢桂','宋','宋诗','song-poetry','','[]','聲名蓋世古人豪，天遣西來展六韜。',64,'全唐诗/poet.song.234000.json','["聲名蓋世古人豪，天遣西來展六韜。", "狐鼠何能嬰虎旅，鯨鯢猶合避龍刀。", "將壇七拜功增重，省府重登官轉高。", "他日中書勳第一，汾陽應只是兒曹。"]'),
('cb33b29a-c7a1-4144-8ef0-3ab98cf482fd','送馬高參政','何夢桂','宋','宋诗','song-poetry','','[]','瘦骨丰稜産渥洼，幾年俛首服鹽車。',64,'全唐诗/poet.song.234000.json','["瘦骨丰稜産渥洼，幾年俛首服鹽車。", "穿花久失青絲轡，莝豆誰憐白鼻騧。", "汗血浪誇空北冀，風蹄猶慣步東華。", "錦鄣不肯污泥水，好去侯門逐五花。"]'),
('8da3de20-8c8a-4f8c-be2d-6ef517599203','寄壽王直卿省郎二親年八十詩二首  其一','何夢桂','宋','宋诗','song-poetry','','[]','金盤玉筯脯麒麟，榮福堂前壽二親。',64,'全唐诗/poet.song.234000.json','["金盤玉筯脯麒麟，榮福堂前壽二親。", "白髮宋州老司馬，紅顔晉國太夫人。", "生時曾結同年會，見世重來兩佛身。", "庭下有兒歸省掾，執鞭時自導雙輪。"]'),
('4776df12-d11d-4134-8ee5-cf48b4e09905','寄壽王直卿省郎二親年八十詩二首  其二','何夢桂','宋','宋诗','song-poetry','','[]','二老婆娑出壽筵，綠衣人好舞蹁躚。',64,'全唐诗/poet.song.234000.json','["二老婆娑出壽筵，綠衣人好舞蹁躚。", "餐桃阿母臉猶玉，食杞仙翁頭返玄。", "堂上相看新八秩，尊前重話舊同年。", "累茵列鼎人間有，安得親庭此樂全。"]'),
('4876c610-fab2-41fc-889c-6da427f6b2b8','上留尚書','何夢桂','宋','宋诗','song-poetry','','[]','昆明池劫化靈緇，夢覺功名忝一炊。',64,'全唐诗/poet.song.234000.json','["昆明池劫化靈緇，夢覺功名忝一炊。", "鍾子未將南操變，庾公空抱北朝悲。", "歸來眼底湖山在，去後心期浙水知。", "白髮門生憐未死，青袍留得裹遺骴。"]'),
('caefd9df-9b72-4214-973a-9a17c55dee82','挽何此園','何夢桂','宋','宋诗','song-poetry','','[]','南窗一枕夢槐安，咽鼓悲笳生暮寒。',64,'全唐诗/poet.song.234000.json','["南窗一枕夢槐安，咽鼓悲笳生暮寒。", "壽極星移墮芒角，詩仙身蛻失丸丹。", "扶藜記與漁樵話，種菊留教孫子看。", "歸去休休言不盡，殘陽木末亂鴉盤。"]'),
('0219e0da-edd9-487c-adb3-7cdc864eeb8c','偶成','何夢桂','宋','宋诗','song-poetry','','[]','喚醒邯鄲出夢關，悠悠身世隔塵寰。',64,'全唐诗/poet.song.234000.json','["喚醒邯鄲出夢關，悠悠身世隔塵寰。", "飛鴻落照琴三疊，流水寒花屋半間。", "老不如人甘遯世，閑誰似我得看山。", "乾坤許大雙蝸角，消得人間戰觸蠻。"]'),
('bdcedf5a-ea0d-43d6-98dd-b1d61bc47f8f','和訪使徐容齋西湖韻寄縣尹趙文玉二首  其一','何夢桂','宋','宋诗','song-poetry','','["\u897f\u6e56"]','一幅西湖畫，誰將淡墨揮。',48,'全唐诗/poet.song.234000.json','["一幅西湖畫，誰將淡墨揮。", "水浮孤嶼出，山約五雲飛。", "雨洞猿啼濕，烟林鳥度微。", "龍舟雙翠檝，曾此夜遊歸。"]'),
('a9442415-3f4e-4344-887c-3e23ab3b6984','和訪使徐容齋西湖韻寄縣尹趙文玉二首  其二','何夢桂','宋','宋诗','song-poetry','','["\u897f\u6e56"]','滿目湖山恨，憑欄淚雨揮。',48,'全唐诗/poet.song.234000.json','["滿目湖山恨，憑欄淚雨揮。", "泉寒龍已化，雲盡鶴猶飛。", "樓影摇波亂，鐘聲隠岫微。", "誰家航十錦，歌舞夜深歸。"]'),
('95cb8631-8672-4e25-85f6-17fd42bbc6bd','和徐雲嶼寄徐清溪','何夢桂','宋','宋诗','song-poetry','','[]','平生經濟事，寧與世沉淪。',48,'全唐诗/poet.song.234000.json','["平生經濟事，寧與世沉淪。", "日暮倦行客，天寒却掃門。", "百年雙白髮，四海一緇塵。", "欲相壺丘子，深慚見地文。"]'),
('94423f87-7e36-4409-9b7c-7f8c3536b1b0','爲友人解無妻之嘲','何夢桂','宋','宋诗','song-poetry','','[]','自甘爲牧犢，何不娶巫臣。',48,'全唐诗/poet.song.234000.json','["自甘爲牧犢，何不娶巫臣。", "魚目長淒斷，雉飛徒苦辛。", "遠衣無與寄，孤枕有誰親。", "毋惜蛾眉買，黄金未是貧。"]'),
('6c51dc4d-d358-46d0-b9aa-22373730d6a8','寄月岩黄高士','何夢桂','宋','宋诗','song-poetry','','[]','有客扣松扃，重來問宿盟。',48,'全唐诗/poet.song.234000.json','["有客扣松扃，重來問宿盟。", "青山塵世夢，玄鶴故人情。", "柯爛棋猶在，壚寒藥未成。", "鼎邊無好句，慚愧謝彌明。"]'),
('e5a45894-d3f5-4e69-8e87-5e480d5d8964','和文公見寄降筆','何夢桂','宋','宋诗','song-poetry','','[]','玉壘失元戎，關河慘北風。',48,'全唐诗/poet.song.234000.json','["玉壘失元戎，關河慘北風。", "中原殘照外，故國夢魂中。", "往事隨流水，餘生歎轉蓬。", "唾壺歌未已，飛雁落江空。"]'),
('062545ad-9e1b-45a0-a5d3-941fc7b1066c','和可菴見寄韻','何夢桂','宋','宋诗','song-poetry','','[]','蜃境平生夢，名場逝水川。',48,'全唐诗/poet.song.234000.json','["蜃境平生夢，名場逝水川。", "相逢驚白髮，一醉仰青天。", "浪出疑鷗笑，遄歸伴鶴眠。", "故人知道意，珍重寄詩篇。"]'),
('5246259e-e006-4995-9076-95b34151a4e0','倚欄即景','何夢桂','宋','宋诗','song-poetry','','[]','落日青山外，寒烟古樹頭。',48,'全唐诗/poet.song.234000.json','["落日青山外，寒烟古樹頭。", "犬聲隔村落，漁火半汀洲。", "興廢江郊屋，行藏野渡舟。", "夜深風雨惡，人尚倚層樓。"]'),
('41815fcd-a0df-4233-8656-ab72445831e5','挽汾陽何北園二首  其一','何夢桂','宋','宋诗','song-poetry','','[]','宇宙千年暮，丘山一老遺。',48,'全唐诗/poet.song.234000.json','["宇宙千年暮，丘山一老遺。", "頭因憂世白，體爲哭親羸。", "明月落何處，清風歸去時。", "英魂招不返，回首北邙噫。"]'),
('08bee596-4f3c-4f56-b2b5-03c768c2e254','挽汾陽何北園二首  其二','何夢桂','宋','宋诗','song-poetry','','[]','五十年來夢，邯鄲黍一炊。',48,'全唐诗/poet.song.234000.json','["五十年來夢，邯鄲黍一炊。", "傳家無長物，誌墓有豐碑。", "落日江湖淚，西風里巷悲。", "故園吟不盡，千古付他誰。"]'),
('c2507ceb-920d-4659-8400-0ecec0446f6f','登天台巾山','何夢桂','宋','宋诗','song-poetry','','[]','寸碧倚蒼旻，孤城俯可吞。',48,'全唐诗/poet.song.234000.json','["寸碧倚蒼旻，孤城俯可吞。", "人行平木杪，帆去入雲根。", "月榻留僧夢，風松弔鶴魂。", "江心千古石，歲歲記潮痕。"]'),
('9387992d-251a-499d-97fb-81812227d7ce','到石寶岩下二絕  其一','何夢桂','宋','宋诗','song-poetry','','[]','十里矗巉岩，移來指顧間。',24,'全唐诗/poet.song.234000.json','["十里矗巉岩，移來指顧間。", "相逢曾識面，元不隔重關。"]'),
('62c44c22-1f17-4696-8059-356c2bf9ae0a','到石寶岩下二絕  其二','何夢桂','宋','宋诗','song-poetry','','[]','相望各天涯，相看又恐差。',24,'全唐诗/poet.song.234000.json','["相望各天涯，相看又恐差。", "朅來山下路，端的到君家。"]'),
('0b13f259-876b-4ccf-b9c2-022d8c465892','和夾谷僉事題釣臺十首  其一','何夢桂','宋','宋诗','song-poetry','','[]','白水龍飛帝運開，先生夢不到雲臺。',32,'全唐诗/poet.song.234000.json','["白水龍飛帝運開，先生夢不到雲臺。", "當時已笑占星誤，豈易虛名落後來。"]'),
('0f97e8ab-4ba0-4225-9d6b-5d01cfff0a41','和夾谷僉事題釣臺十首  其二','何夢桂','宋','宋诗','song-poetry','','[]','當年江上一竿青，老盡羊裘兩鬢星。',32,'全唐诗/poet.song.234000.json','["當年江上一竿青，老盡羊裘兩鬢星。", "往事成塵遺迹在，石痕齒齒水泠泠。"]'),
('02025490-a7c8-4d8b-96c4-b211bcbc7dcf','和夾谷僉事題釣臺十首  其三','何夢桂','宋','宋诗','song-poetry','','[]','龍信蛇屈各升沉，白髮朱顔亦故今。',32,'全唐诗/poet.song.234000.json','["龍信蛇屈各升沉，白髮朱顔亦故今。", "出處兩難人不識，雲山江水是知心。"]'),
('665f2d23-01c5-4271-951d-1854b8f5557d','和夾谷僉事題釣臺十首  其四','何夢桂','宋','宋诗','song-poetry','','[]','誤出山來亟已還，絕塵逸駕竟難攀。',32,'全唐诗/poet.song.234000.json','["誤出山來亟已還，絕塵逸駕竟難攀。", "狂奴不了宮中事，剩得閒身宇宙間。"]'),
('b9dae5bf-7a7a-4ee8-a7c5-3c401ae90254','和夾谷僉事題釣臺十首  其五','何夢桂','宋','宋诗','song-poetry','','[]','咄咄相逢話故交，不嫌萬乘友漁樵。',32,'全唐诗/poet.song.234000.json','["咄咄相逢話故交，不嫌萬乘友漁樵。", "當初未有玄纁至，只好收綸學棄瓢。"]'),
('27bd8471-6b8b-40aa-a340-48601a8680bc','和夾谷僉事題釣臺十首  其六','何夢桂','宋','宋诗','song-poetry','','[]','漢事如舟要着篙，諸公已共濟風濤。',32,'全唐诗/poet.song.234000.json','["漢事如舟要着篙，諸公已共濟風濤。", "勳華終不臣巢許，莫道先生索價高。"]'),
('dee6c888-f7f3-4515-b876-eb8b87853168','和夾谷僉事題釣臺十首  其七','何夢桂','宋','宋诗','song-poetry','','[]','逝水滔滔七里灘，高情聊寄一絲竿。',32,'全唐诗/poet.song.234000.json','["逝水滔滔七里灘，高情聊寄一絲竿。", "無魚可釣渾閒事，脚底龍眠儘自安。"]'),
('c93c5e36-d975-4c7d-a80f-60a8b462218c','和夾谷僉事題釣臺十首  其八','何夢桂','宋','宋诗','song-poetry','','[]','苔蘚碑漫字斷章，休將漢事費評量。',32,'全唐诗/poet.song.234000.json','["苔蘚碑漫字斷章，休將漢事費評量。", "興亡付與東流水，留得荒祠一瓣香。"]'),
('dd05d1ca-1207-4cf9-9af5-392074ebdb2f','和夾谷僉事題釣臺十首  其九','何夢桂','宋','宋诗','song-poetry','','[]','雙臺絕壁鎖林霏，每恨躋攀足力微。',32,'全唐诗/poet.song.234000.json','["雙臺絕壁鎖林霏，每恨躋攀足力微。", "今日重來問鷗鷺，絕無人迹上苔磯。"]'),
('ab2599ec-5b41-435f-9e82-90fe9fcd58e8','和夾谷僉事題釣臺十首  其一○','何夢桂','宋','宋诗','song-poetry','','[]','觀風祠下謁先生，隔世相知重感情。',32,'全唐诗/poet.song.234000.json','["觀風祠下謁先生，隔世相知重感情。", "歸向中州諸老說，且休拈出此山名。"]'),
('2bced2fc-849c-46f0-a641-bc686dac9e7b','桃源三首  其一','何夢桂','宋','宋诗','song-poetry','','[]','誤逐桃花去訪春，當年猶有種桃人。',32,'全唐诗/poet.song.234000.json','["誤逐桃花去訪春，當年猶有種桃人。", "相逢休問秦時事，世上興亡又幾春。"]'),
('cc88e0ef-d880-4cbc-afa4-f88dc1364ef8','桃源三首  其二','何夢桂','宋','宋诗','song-poetry','','[]','洞裏栽桃不記時，世間秦晉是邪非。',32,'全唐诗/poet.song.234000.json','["洞裏栽桃不記時，世間秦晉是邪非。", "落花落地青春老，千載漁郎去不歸。"]'),
('83e39f01-9dad-4668-b25b-92e6b6e2ff1b','桃源三首  其三','何夢桂','宋','宋诗','song-poetry','','[]','牧歌樵唱自朝昏，白首何曾出洞門。',32,'全唐诗/poet.song.234000.json','["牧歌樵唱自朝昏，白首何曾出洞門。", "一度草青添一歲，如今世代長兒孫。"]'),
('0c4c07b5-6665-431b-a70d-492f70fc2874','夢中作','何夢桂','宋','宋诗','song-poetry','','[]','草濃阡陌眠黄犢，沙煖汀洲浴翠禽。',32,'全唐诗/poet.song.234000.json','["草濃阡陌眠黄犢，沙煖汀洲浴翠禽。", "一徑梧桐花落後，半江春水綠陰陰。"]'),
('3da073a1-d9c2-426d-a419-5606e34c8508','贈地理章月岩','何夢桂','宋','宋诗','song-poetry','','[]','世事興亡千古意，山花開落幾番春。',32,'全唐诗/poet.song.234000.json','["世事興亡千古意，山花開落幾番春。", "年年惟有巖頭月，照盡今人與古人。"]'),
('473ef5ef-6199-40ef-a045-e2665f5cf73a','贈張月齋','何夢桂','宋','宋诗','song-poetry','','[]','斸盡青瑶補缺光，暫持玉斧下青蒼。',32,'全唐诗/poet.song.234000.json','["斸盡青瑶補缺光，暫持玉斧下青蒼。", "相逢一笑乘鸞去，顔色猶疑在屋梁。"]'),
('cc0b1b1b-89c7-43e9-8082-01b61dc62655','挽林公坐化','何夢桂','宋','宋诗','song-poetry','','[]','一枕黄粱透夢關，獨留蟬蛻在人間。',32,'全唐诗/poet.song.234000.json','["一枕黄粱透夢關，獨留蟬蛻在人間。", "有時欲見公顔色，木落枝枯月萬山。"]'),
('1a90b194-15f2-4fbc-9c2e-343c87ca60fc','題川無竭寄傲窗二首  其一','何夢桂','宋','宋诗','song-poetry','','[]','遠公招不到淵明，蓮社千年迹已陳。',32,'全唐诗/poet.song.234000.json','["遠公招不到淵明，蓮社千年迹已陳。", "莫道先生曾傲己，如今更傲世間人。"]'),
('4806fe17-4a65-4e9f-b0f2-72bc2d6b1c79','題川無竭寄傲窗二首  其二','何夢桂','宋','宋诗','song-poetry','','[]','南山有路滑如苔，多少人從半嶺回。',32,'全唐诗/poet.song.234000.json','["南山有路滑如苔，多少人從半嶺回。", "不是老僧空傲世，世人自不上山來。"]'),
('a3d3cd59-b3ee-4517-aace-9f94ed4bb557','和王樵隠阻雨二首  其一','何夢桂','宋','宋诗','song-poetry','','[]','春水連天雨載塗，春江無處認平蕪。',32,'全唐诗/poet.song.234000.json','["春水連天雨載塗，春江無處認平蕪。", "茫茫世路風波惡，留得湘潭橘渚無。"]'),
